        public List<string> ExecuteQueryToListAgein(string query)
        {
            List<string> result = new List<string>();
            using (OracleConnection con = new OracleConnection(_connection))
            {
                con.Open();
                try
                {
                    using (var cmd = new OracleCommand(query, con))
                    {
                        cmd.CommandType = CommandType.Text;
                        cmd.CommandTimeout = 300;
                        using (var reader = cmd.ExecuteReader())
                        {
                            while (reader.Read())
                            {
                                List<string> row = new List<string>();
                                for (int i = 0; i < reader.FieldCount; i++)
                                {
                                    object value = reader.GetValue(i);
                                    row.Add(value != DBNull.Value ? value.ToString() : "");
                                }
                                result.Add(string.Join(",", row)); 
                            }
                        }
                    }
                }
                catch (Exception ex)
                {
                    
                }
            }
            return result;
        }
        public async Task<List<string>> ExecuteQueryToListAsync(string query)
        {
            var result = new List<string>();

            using (OracleConnection con = new OracleConnection(_connection))
            {
                await con.OpenAsync();
                using (var cmd = new OracleCommand(query, con))
                {
                    try
                    {
                        cmd.CommandType = CommandType.Text;
                        cmd.CommandTimeout = 300;
                        //cmd.FetchSize = 100000;
                        using (var reader = await cmd.ExecuteReaderAsync())
                        {
                            while (await reader.ReadAsync())
                            {
                                result.Add(reader.IsDBNull(0) ? string.Empty : reader.GetFieldValue<string>(0));
                            }
                        }
                    }
                    catch(Exception ex)
                    {

                    }
                }
            }

            return result;
        }

