        #region Initquery Developed By: Prem Prakash Dhakal Date: 09-19-2024 Modify By: Prem P Dhakal Date :02-20-2025
        public List<DateRange> GetVDateRanges(string RangeNameFilter)
        {
            List<DateRange> dateRanges = new List<DateRange>();
            string queryDateRangeView = @" SELECT *from V_DATE_RANGE";
            DataTable dt = new DataTable();
            using (OracleConnection connDateRange = new OracleConnection(_connection))
            {
                using (OracleCommand cmdDateRange = new OracleCommand(queryDateRangeView, connDateRange))
                {
                    connDateRange.Open();
                    using (OracleDataReader readerDateRange = cmdDateRange.ExecuteReader())
                    {
                        try
                        {
                           
                            while (readerDateRange.Read())
                            {
                                //dateRanges.Add(new DateRange
                                //{
                                //    StartDate = readerDateRange.GetDateTime(0),
                                //    EndDate = readerDateRange.GetDateTime(1),
                                //    RangeName = readerDateRange.GetString(2),
                                //    SortOrder = readerDateRange.GetInt32(3)
                                //});
                                var dateRange = new DateRange
                                {
                                    StartDate = readerDateRange.GetDateTime(0),
                                    EndDate = readerDateRange.GetDateTime(1),
                                    RangeName = readerDateRange.GetString(2),
                                    SortOrder = readerDateRange.GetInt32(3)
                                };

                                if (string.IsNullOrEmpty(RangeNameFilter) || dateRange.RangeName == RangeNameFilter)
                                {
                                    dateRanges.Add(dateRange);
                                    dt.Load(readerDateRange);
                                }
                            }
                        }
                        catch(Exception ex)
                        { }
                    }
                }
            }
            string queryDateRanges = @"
            CREATE OR REPLACE FORCE VIEW V_DATE_RANGE
            (
                STARTDATE,
                ENDDATE,
                RANGENAME,
                SORTORDER
            )
            AS
            SELECT DISTINCT STARTDATE,
                            ENDDATE,
                            RANGENAME,
                            SORTORDER
                FROM (SELECT CS.AD_DATE STARTDATE,
                        (CS.AD_DATE + CS.DAYS_NO - 1) ENDDATE,
                        FN_BS_MONTH(SUBSTR(CS.BS_MONTH, -2, 2)) RANGENAME,
                        1 AS SORTORDER
                    FROM PREFERENCE_SETUP FY
                    JOIN CALENDAR_SETUP CS
                        ON CS.AD_DATE BETWEEN FY.FY_START_DATE AND FY.FY_END_DATE
                    UNION ALL
                    SELECT FY_START_DATE,
                            FY_END_DATE,
                            'This Year' DATE_NAME,
                            2 AS SORTORDER
                    FROM PREFERENCE_SETUP
                    UNION ALL
                    SELECT AD_DATE FY_START_DATE,
                            (AD_DATE + DAYS_NO - 1) FY_END_DATE,
                            'This Month' DATE_NAME,
                            3 AS SORTORDER
                    FROM CALENDAR_SETUP
                    WHERE SYSDATE BETWEEN AD_DATE AND (AD_DATE + DAYS_NO)
                    UNION ALL
                    SELECT DISTINCT
                            FIRST_VALUE(CS.AD_DATE)
                            OVER (ORDER BY CS.AD_DATE DESC, (CS.AD_DATE + CS.DAYS_NO - 1) DESC) FY_START_DATE,
                            FIRST_VALUE(CS.AD_DATE + CS.DAYS_NO - 1)
                            OVER (ORDER BY (CS.AD_DATE + CS.DAYS_NO - 1) DESC, CS.AD_DATE ASC) FY_END_DATE,
                            'Last Month' DATE_NAME,
                            4 AS SORTORDER
                    FROM PREFERENCE_SETUP FY
                    JOIN CALENDAR_SETUP CS
                        ON CS.AD_DATE BETWEEN FY.FY_START_DATE AND FY.FY_END_DATE
                        AND CS.AD_DATE < SYSDATE - DAYS_NO
                    UNION ALL
                    SELECT TRUNC((NEXT_DAY(SYSDATE, 'SUN') - 7)) FY_START_DATE,
                            TRUNC(SYSDATE) FY_END_DATE,
                            'This Week' DATE_NAME,
                            5 AS SORTORDER
                    FROM DUAL
                    UNION ALL
                    SELECT TRUNC((NEXT_DAY(SYSDATE, 'SUN') - 14)) FY_START_DATE,
                            TRUNC((NEXT_DAY(SYSDATE, 'SAT') - 7)) FY_END_DATE,
                            'Last Week' DATE_NAME,
                            6 AS SORTORDER
                    FROM DUAL
                    UNION ALL
                    SELECT DISTINCT
                            FIRST_VALUE(CS.AD_DATE)
                            OVER (ORDER BY CS.AD_DATE ASC, (CS.AD_DATE + CS.DAYS_NO - 1) DESC) FY_START_DATE,
                            FIRST_VALUE(CS.AD_DATE + CS.DAYS_NO - 1)
                            OVER (ORDER BY (CS.AD_DATE + CS.DAYS_NO - 1) DESC, CS.AD_DATE ASC) FY_END_DATE,
                            'First Quarter' DATE_NAME,
                            7 AS SORTORDER
                    FROM PREFERENCE_SETUP FY
                    JOIN CALENDAR_SETUP CS
                        ON CS.AD_DATE BETWEEN FY.FY_START_DATE AND FY.FY_END_DATE
                        AND SUBSTR(CS.BS_MONTH, -2, 2) >= '04'
                        AND SUBSTR(CS.BS_MONTH, -2, 2) < '07'
                    UNION ALL
                    SELECT DISTINCT
                            FIRST_VALUE(CS.AD_DATE)
                            OVER (ORDER BY CS.AD_DATE ASC, (CS.AD_DATE + CS.DAYS_NO - 1) DESC) FY_START_DATE,
                            FIRST_VALUE(CS.AD_DATE + CS.DAYS_NO - 1)
                            OVER (ORDER BY (CS.AD_DATE + CS.DAYS_NO - 1) DESC, CS.AD_DATE ASC) FY_END_DATE,
                            'Second Quarter' DATE_NAME,
                            8 AS SORTORDER
                    FROM PREFERENCE_SETUP FY
                    JOIN CALENDAR_SETUP CS
                        ON CS.AD_DATE BETWEEN FY.FY_START_DATE AND FY.FY_END_DATE
                        AND SUBSTR(CS.BS_MONTH, -2, 2) >= '07'
                        AND SUBSTR(CS.BS_MONTH, -2, 2) < '10'
                    UNION ALL
                    SELECT DISTINCT
                            FIRST_VALUE(CS.AD_DATE)
                            OVER (ORDER BY CS.AD_DATE ASC, (CS.AD_DATE + CS.DAYS_NO - 1) DESC) FY_START_DATE,
                            FIRST_VALUE(CS.AD_DATE + CS.DAYS_NO - 1)
                            OVER (ORDER BY (CS.AD_DATE + CS.DAYS_NO - 1) DESC, CS.AD_DATE ASC) FY_END_DATE,
                            'Third Quarter' DATE_NAME,
                            9 AS SORTORDER
                    FROM PREFERENCE_SETUP FY
                    JOIN CALENDAR_SETUP CS
                        ON CS.AD_DATE BETWEEN FY.FY_START_DATE AND FY.FY_END_DATE
                        AND SUBSTR(CS.BS_MONTH, -2, 2) >= '10'
                        AND SUBSTR(CS.BS_MONTH, -2, 2) <= '12'
                    UNION ALL
                    SELECT DISTINCT
                            FIRST_VALUE(CS.AD_DATE)
                            OVER (ORDER BY CS.AD_DATE ASC, (CS.AD_DATE + CS.DAYS_NO - 1) DESC) FY_START_DATE,
                            FIRST_VALUE(CS.AD_DATE + CS.DAYS_NO - 1)
                            OVER (ORDER BY (CS.AD_DATE + CS.DAYS_NO - 1) DESC, CS.AD_DATE ASC) FY_END_DATE,
                            'Forth Quarter' DATE_NAME,
                            10 AS SORTORDER
                    FROM PREFERENCE_SETUP FY
                    JOIN CALENDAR_SETUP CS
                        ON CS.AD_DATE BETWEEN FY.FY_START_DATE AND FY.FY_END_DATE
                        AND SUBSTR(CS.BS_MONTH, -2, 2) >= '01'
                        AND SUBSTR(CS.BS_MONTH, -2, 2) <= '03'
                    UNION ALL
                    SELECT FY_START_DATE,
                            FY_END_DATE,
                            'Custom' DATE_NAME,
                            -100 AS SORTORDER
                    FROM PREFERENCE_SETUP
             )";
            if (dt.Rows.Count == 0)
            {
                using (OracleConnection connDateRange = new OracleConnection(_connection))
                {
                    using (OracleCommand cmdDateRange = new OracleCommand(queryDateRanges, connDateRange))
                    {
                        try
                        {
                            connDateRange.Open();
                            using (OracleDataReader readerDateRange = cmdDateRange.ExecuteReader())
                            {
                                while (readerDateRange.Read())
                                {
                                    //dateRanges.Add(new DateRange
                                    //{
                                    //    StartDate = readerDateRange.GetDateTime(0),
                                    //    EndDate = readerDateRange.GetDateTime(1),
                                    //    RangeName = readerDateRange.GetString(2),
                                    //    SortOrder = readerDateRange.GetInt32(3)
                                    //});
                                    var dateRange = new DateRange
                                    {
                                        StartDate = readerDateRange.GetDateTime(0),
                                        EndDate = readerDateRange.GetDateTime(1),
                                        RangeName = readerDateRange.GetString(2),
                                        SortOrder = readerDateRange.GetInt32(3)
                                    };

                                    if (string.IsNullOrEmpty(RangeNameFilter) || dateRange.RangeName == RangeNameFilter)
                                    {
                                        dateRanges.Add(dateRange);
                                    }
                                }
                            }
                        }catch(Exception ex)
                        { }
                    }
                }
            }
            return dateRanges;
        }
        public List<DateRange> GetVDateRangesEnglish(string RangeNameFilter)
        {
            List<DateRange> dateRanges = new List<DateRange>();
            string queryDateRangeView = @" SELECT *from V_DATE_RANGE_ENG";
            DataTable dt = new DataTable();
            using (OracleConnection connDateRange = new OracleConnection(_connection))
            {
                using (OracleCommand cmdDateRange = new OracleCommand(queryDateRangeView, connDateRange))
                {
                    connDateRange.Open();
                    using (OracleDataReader readerDateRange = cmdDateRange.ExecuteReader())
                    {
                        try
                        {
                            while (readerDateRange.Read())
                            {
                                //dateRanges.Add(new DateRange
                                //{
                                //    StartDate = readerDateRange.GetDateTime(0),
                                //    EndDate = readerDateRange.GetDateTime(1),
                                //    RangeName = readerDateRange.GetString(2),
                                //    SortOrder = readerDateRange.GetInt32(3)
                                //});
                                var dateRange = new DateRange
                                {
                                    StartDate = readerDateRange.GetDateTime(0),
                                    EndDate = readerDateRange.GetDateTime(1),
                                    RangeName = readerDateRange.GetString(2),
                                    SortOrder = readerDateRange.GetInt32(3)
                                };

                                if (string.IsNullOrEmpty(RangeNameFilter) || dateRange.RangeName == RangeNameFilter)
                                {
                                    dateRanges.Add(dateRange);
                                    dt.Load(readerDateRange);
                                }
                            }
                        }
                        catch(Exception ex)
                        { }
                    }
                }
            }
            string queryDateRanges = @"
            CREATE materialized VIEW V_DATE_RANGE_ENG
                            (
                               STARTDATE,
                               ENDDATE,
                               RANGENAME,
                               SORTORDER
                            )
                            AS
                               SELECT fromdate startdate,
                                      todate enddate,
                                      month_name rangename,
                                      1 SORTORDER
                                 FROM (SELECT *
                                         FROM    (  SELECT month_name, MIN (dates) fromdate
                                                      FROM (SELECT    TRIM (month_name)
                                       || '-'
                                       || SUBSTR (dates, 8, 4)
                                          month_name,
                                       dates
                                            FROM (    SELECT TO_CHAR (
                                                      (SELECT startdate
                                                         FROM v_date_range
                                                        WHERE rangename =
                                                                 'This Year')
                                                      + LEVEL
                                                      - 1,
                                                      'MONTH')
                                                      AS month_name,
                                                   (SELECT startdate
                                                      FROM v_date_range
                                                     WHERE rangename = 'This Year')
                                                   + LEVEL
                                                   - 1
                                                      dates
                                              FROM DUAL
                                        CONNECT BY LEVEL <=
                                                      ( (SELECT enddate
                                                           FROM v_date_range
                                                          WHERE rangename =
                                                                   'This Year')
                                                       - (SELECT startdate
                                                            FROM v_date_range
                                                           WHERE rangename =
                                                                    'This Year'))
                                                      + 1))
                      GROUP BY month_name
                      ORDER BY fromdate) a
                  LEFT OUTER JOIN
                     (  SELECT month_name mon, MAX (dates) todate
                          FROM (SELECT    TRIM (month_name)
                                       || '-'
                                       || SUBSTR (dates, 8, 4)
                                          month_name,
                                       dates
                                  FROM (    SELECT TO_CHAR (
                                                      (SELECT startdate
                                                         FROM v_date_range
                                                        WHERE rangename =
                                                                 'This Year')
                                                      + LEVEL
                                                      - 1,
                                                      'MONTH')
                                                      AS month_name,
                                                   (SELECT startdate
                                                      FROM v_date_range
                                                     WHERE rangename = 'This Year')
                                                   + LEVEL
                                                   - 1
                                                      dates
                                              FROM DUAL
                                        CONNECT BY LEVEL <=
                                                      ( (SELECT enddate
                                                           FROM v_date_range
                                                          WHERE rangename =
                                                                   'This Year')
                                                       - (SELECT startdate
                                                            FROM v_date_range
                                                           WHERE rangename =
                                                                    'This Year'))
                                                      + 1))
                      GROUP BY month_name
                      ORDER BY todate) b
                  ON a.month_name = b.mon
                  )";

            if (dt.Rows.Count == 0)
            {
                using (OracleConnection connDateRange = new OracleConnection(_connection))
                {
                    using (OracleCommand cmdDateRange = new OracleCommand(queryDateRanges, connDateRange))
                    {
                        connDateRange.Open();
                        using (OracleDataReader readerDateRange = cmdDateRange.ExecuteReader())
                        {
                            try
                            {
                                while (readerDateRange.Read())
                                {
                                    //dateRanges.Add(new DateRange
                                    //{
                                    //    StartDate = readerDateRange.GetDateTime(0),
                                    //    EndDate = readerDateRange.GetDateTime(1),
                                    //    RangeName = readerDateRange.GetString(2),
                                    //    SortOrder = readerDateRange.GetInt32(3)
                                    //});
                                    var dateRange = new DateRange
                                    {
                                        StartDate = readerDateRange.GetDateTime(0),
                                        EndDate = readerDateRange.GetDateTime(1),
                                        RangeName = readerDateRange.GetString(2),
                                        SortOrder = readerDateRange.GetInt32(3)
                                    };

                                    if (string.IsNullOrEmpty(RangeNameFilter) || dateRange.RangeName == RangeNameFilter)
                                    {
                                        dateRanges.Add(dateRange);
                                    }
                                }
                            }
                            catch(Exception ex)
                            { }
                        }
                    }
                }
            }
            return dateRanges;
        }
