            //        WHERE ACC_NATURE IN ('AB','AC','LC') 
            //        AND COMPANY_CODE = A.COMPANY_CODE
            //    )
            //    AND A.TRANSACTION_TYPE = 'DR'                                        
            //    AND A.COMPANY_CODE = '{model.CompanyCode}'
            //    AND A.DELETED_FLAG = 'N'
            //    AND A.Voucher_NO != '0'
            //    AND voucher_date BETWEEN '{model.FromDate}' AND '{model.ToDate}'
            //)
            //AND SUBSTR(sub_code, 1, 1) = 'C'
            //AND TRANSACTION_TYPE = 'CR'";

            //var collectionData = await ExecuteQueryAsync(query2);
            //if (collectionData.Rows.Count > 0)
            //{
            //    var collectionRow = collectionData.Rows[0];
            //    response.Add(new Dictionary<string, object>
            //{
            //    { "amt", Convert.ToDouble(collectionRow["CR_AMOUNT"]) },
            //    { "topic", "Collection" }
            //});
            //}
            #endregion

            #region  Purchase Data
            string queryPurchaseData = $@"
            SELECT SALES_ROLL_QTY, SALES_QTY, SALES_VALUE, 
                   SALES_RET_ROLL_QTY, SALES_RET_QTY, SALES_RET_VALUE,
                   SALES_ROLL_QTY - SALES_RET_ROLL_QTY AS NET_ROLL_QTY,
                   NVL(SALES_QTY - SALES_RET_QTY, 0) AS NET_SALES_QTY,
                   NVL(SALES_VALUE - SALES_RET_VALUE, 0) AS NET_SALES_VALUE
            FROM (
                SELECT SUM(A.SALES_ROLL_QTY) AS SALES_ROLL_QTY,
                       SUM(A.SALES_QTY) AS SALES_QTY,
                       SUM(A.SALES_VALUE) AS SALES_VALUE,
                       SUM(SALES_RET_ROLL_QTY) AS SALES_RET_ROLL_QTY,
                       SUM(A.SALES_RET_QTY) AS SALES_RET_QTY,
                       SUM(A.SALES_RET_VALUE) AS SALES_RET_VALUE
                FROM (
                    SELECT A.COMPANY_CODE, A.ITEM_CODE, 
                           SUM(NVL(A.ROLL_QTY, 0)) AS SALES_ROLL_QTY,
                           SUM(NVL(A.QUANTITY, 0)) AS SALES_QTY,
                           SUM(NVL(A.QUANTITY * A.CALC_UNIT_PRICE * EXCHANGE_RATE, 0)) AS SALES_VALUE,
                            0 AS SALES_RET_ROLL_QTY, 
                            0 AS SALES_RET_QTY,      
                            0 AS SALES_RET_VALUE     
                    FROM IP_PURCHASE_INVOICE A
                    WHERE COMPANY_CODE IN ('{model.CompanyCode}')
                      AND DELETED_FLAG = 'N'
                      AND TRUNC(invoice_DATE) BETWEEN TO_DATE('{model.FromDate}','DD-MON-YYYY') AND TO_DATE('{model.ToDate}','DD-MON-YYYY')
                    GROUP BY A.COMPANY_CODE, A.ITEM_CODE
                ) A
            )";
            var purchaseData = await ExecuteQueryAsync(queryPurchaseData);
            if (purchaseData.Rows.Count > 0)
            {
                var purchaseRow = purchaseData.Rows[0];
                response.Add(new Dictionary<string, object>
            {
                { "qty", Convert.ToDouble(purchaseRow["NET_SALES_QTY"]) },
                { "amt", Convert.ToDouble(purchaseRow["NET_SALES_VALUE"]) },
                { "topic", "Purchase" }
            });
            }
            #endregion

            #region  Second query for collection
            string queryCollection = @"
                    SELECT NVL(SUM(NVL(CR_AMOUNT, 0) * NVL(EXCHANGE_RATE, 1)), 0) AS CR_AMOUNT
                    FROM V$VIRTUAL_SUB_LEDGER b
                    WHERE (COMPANY_CODE, Voucher_NO) IN
                    (
                        SELECT COMPANY_CODE, A.voucher_no
                        FROM V$VIRTUAL_GENERAL_LEDGER A
                        WHERE A.ACC_CODE IN 
                        (
                            SELECT ACC_CODE 
                            FROM FA_CHART_OF_ACCOUNTS_SETUP 
                            WHERE ACC_NATURE IN ('AB', 'AC', 'LC') 
                            AND COMPANY_CODE = A.COMPANY_CODE
                        )
                        AND A.TRANSACTION_TYPE = 'DR'                                        
                        AND A.COMPANY_CODE = :CompanyCode
                        AND A.DELETED_FLAG = 'N'
                        AND A.Voucher_NO != '0'
                        AND voucher_date BETWEEN :FromDate AND :ToDate
                    )
                    AND SUBSTR(sub_code, 1, 1) = 'C'
                    AND TRANSACTION_TYPE = 'CR'";

            var parameters = new Dictionary<string, object>
                {
                    { "CompanyCode", model.CompanyCode },
                    { "FromDate", model.FromDate },
                    { "ToDate", model.ToDate }
                };

            // Execute the query with parameterized values
            var collectionData = await ExecuteQueryAsync(queryCollection, parameters);
            if (collectionData.Rows.Count > 0)
            {
                var collectionRow = collectionData.Rows[0];
                var vals = new Dictionary<string, object>
                {
                    { "amt", Convert.ToDouble(collectionRow["CR_AMOUNT"]) },
                    { "topic", "Collection" }
                };
                response.Add(vals);
            }
            #endregion

            #region  Query for Purchase
            string queryPurchase = @"
                SELECT NVL(SUM(NVL(QUANTITY, 0)) * 1, 0) AS QTY
                FROM IP_Purchase_MRR 
                WHERE DELETED_FLAG = 'N' 
                AND COMPANY_CODE IN (:CompanyCode)
                AND mrr_date BETWEEN :FromDate AND :ToDate";

            var parametersValue = new Dictionary<string, object>
            {
                { "CompanyCode", model.CompanyCode },
                { "FromDate", model.FromDate },
                { "ToDate", model.ToDate }
            };

            // Execute the query with parameterized values
            var purchaseDataValues = await ExecuteQueryAsync(queryPurchase, parametersValue);

            if (purchaseDataValues.Rows.Count > 0)
            {
                var purchaseRowValue = purchaseDataValues.Rows[0];
                var vals = new Dictionary<string, object>
                {
                    { "qty", Convert.ToDouble(purchaseRowValue["QTY"]) },
                    { "topic", "Purchase" }
                };
                response.Add(vals);
            }
            #endregion

            #region  Cash/Bank Data
            var cashBankData = await BankCashClosing(new string[] { "01" }, model.FromDate, model.ToDate);
            double cash = 0, bank = 0;

            foreach (var cashBankEntry in cashBankData)
            {
                if (cashBankEntry.ContainsKey("CASH"))
                {
                    foreach (var cashEntry in cashBankEntry["CASH"])
                    {
                        cash += Convert.ToDouble(cashEntry["closing"]);
                    }
                }

                if (cashBankEntry.ContainsKey("BANK"))
                {
                    foreach (var bankEntry in cashBankEntry["BANK"])
                    {
                        bank += Convert.ToDouble(bankEntry["closing"]);
                    }
                }
            }
            response.Add(new Dictionary<string, object> { { "amt", cash }, { "topic", "Cash Balance" } });
            response.Add(new Dictionary<string, object> { { "amt", bank }, { "topic", "Bank Balance" } });

            #endregion

            #region  Query for Receivable

            string queryReceivable = @"
                SELECT NVL(SUM(FN_CONVERT_CURRENCY(ROUND((NVL(dR_AMOUNT, 0) - NVL(CR_AMOUNT, 0)), 2) * NVL(EXCHANGE_RATE, 1), 'NRS', VOUCHER_DATE)), 0) amt 
                FROM V$VIRTUAL_GENERAL_LEDGER  
                WHERE DELETED_FLAG = 'N'  
                AND COMPANY_CODE IN (:CompanyCode) 
                AND FORM_CODE <> '0'
                AND ACC_CODE IN
                (
                    SELECT DISTINCT ACC_CODE 
                    FROM FA_CHART_OF_ACCOUNTS_SETUP A 
                    WHERE A.DELETED_FLAG = 'N' 
                    AND A.ACC_NATURE IN ('AE') 
                    AND COMPANY_CODE IN (:CompanyCode)      
                    AND ACC_TYPE_FLAG = 'T'
                )
                AND VOUCHER_DATE BETWEEN :FromDate AND :ToDate";

            var parametersCode = new Dictionary<string, object>
                {
                    { "CompanyCode", model.CompanyCode },
                    { "FromDate", model.FromDate },
                    { "ToDate", model.ToDate }
                };

            var receivableData = await ExecuteQueryAsync(queryReceivable, parametersCode);
            if (receivableData.Rows.Count > 0)
            {
                var receivableRow = receivableData.Rows[0];
                var vals = new Dictionary<string, object>
                {
                    { "amt", Convert.ToDouble(receivableRow["amt"]) },
                    { "topic", "Receivable" }
                };
                response.Add(vals);
            }
            #endregion

            #region Query for Payable
            string queryPayable = @"
            SELECT NVL(SUM(a), 0) 
            FROM 
            (
                SELECT SUM(dr_amount) - SUM(cr_amount) a 
                FROM V$VIRTUAL_GENERAL_LEDGER
                WHERE DELETED_FLAG = 'N'
                AND COMPANY_CODE = :CompanyCode
                AND ACC_CODE IN (
                    SELECT DISTINCT ACC_CODE 
                    FROM FA_CHART_OF_ACCOUNTS_SETUP A 
                    WHERE A.DELETED_FLAG = 'N' 
                    AND A.ACC_NATURE IN ('LD') 
                    AND COMPANY_CODE = :CompanyCode     
                    AND ACC_TYPE_FLAG = 'T'
                ) 
                AND (FORM_CODE = 0 OR VOUCHER_DATE < :FromDate)                        
                UNION ALL
                SELECT SUM(dr_amount) - SUM(cr_amount) 
                FROM V$VIRTUAL_GENERAL_LEDGER
                WHERE DELETED_FLAG = 'N'
                AND COMPANY_CODE = :CompanyCode
                AND ACC_CODE IN (
                    SELECT DISTINCT ACC_CODE 
                    FROM FA_CHART_OF_ACCOUNTS_SETUP A 
                    WHERE A.DELETED_FLAG = 'N' 
                    AND A.ACC_NATURE IN ('LD') 
                    AND COMPANY_CODE = :CompanyCode     
                    AND ACC_TYPE_FLAG = 'T'
                ) 
                AND FORM_CODE <> 0
                AND VOUCHER_DATE BETWEEN :FromDate AND :ToDate
            )";

            var parametersPayable = new Dictionary<string, object>
            {
                { "CompanyCode", model.CompanyCode },
                { "FromDate", model.FromDate },
                { "ToDate", model.ToDate }
            };

            var payableDataPayable = await ExecuteQueryAsync(queryPayable, parametersPayable);
            if (payableDataPayable.Rows.Count > 0)
            {
                var payableRow = payableDataPayable.Rows[0];
                var payableAmount = Convert.ToDecimal(payableRow[0]) * -1;
                var vals = new Dictionary<string, object>
