                        AND company_code = :CompanyCode
                        AND (FORM_CODE = 0 OR VOUCHER_DATE < :FromDate)                        
                        UNION ALL                
                        SELECT NVL(SUM(NVL(cr_amount, 0)) - SUM(NVL(dr_amount, 0)), 0) amt 
