                            AND company_code = :CompanyCode
                        )
                        AND company_code = :CompanyCode
                        AND VOUCHER_DATE BETWEEN :FromDate AND :ToDate
                    )";

            var parametersVAT = new Dictionary<string, object>
                    {
                        { "CompanyCode", model.CompanyCode },
                        { "FromDate", model.FromDate },
                        { "ToDate", model.ToDate }
                    };

            var vatData = await ExecuteQueryAsync(queryVAT, parametersVAT);
            if (vatData.Rows.Count > 0)
            {
                var vatRow = vatData.Rows[0];
                var vatAmount = Convert.ToDecimal(vatRow[0]);
                var vals = new Dictionary<string, object>
