        [HttpPost]
        [Route("GetAgeingReport")]
        public async Task<IHttpActionResult> GetAgeingReport(string companyCode, string branchCode, string toDate, string subCode, string userNo)
        {
            try
            {
                using (OracleConnection conn = new OracleConnection(_connection))
                {
                    conn.Open();

                    // First Query: Check if the balance is greater than zero to decide if it's a debit balance
                    string checkBalanceQuery = @"
                        SELECT NVL(SUM(dr_amount) - SUM(cr_amount), 0) 
                        FROM V$VIRTUAL_SUB_LEDGER 
                        WHERE SUB_CODE = :SubCode 
                        AND COMPANY_CODE IN (:CompanyCode)";

                    using (OracleCommand command = new OracleCommand(checkBalanceQuery, conn))
                    {
                        command.Parameters.Add(new OracleParameter(":SubCode", subCode));
                        command.Parameters.Add(new OracleParameter(":CompanyCode", companyCode));

                        object result = command.ExecuteScalar();
                        bool forDebitBalance = Convert.ToDecimal(result) > 0;

                        // Second Query: Construct the ageing report query based on the balance type
                        string ageingQuery = forDebitBalance ? GetDebitBalanceAgeingQuery() : GetCreditBalanceAgeingQuery();

                        // Execute the ageing report query
                        command.CommandText = ageingQuery;
                        command.Parameters.Clear(); // Clear parameters for new query
                        command.Parameters.Add(new OracleParameter(":SubCode", subCode));
                        command.Parameters.Add(new OracleParameter(":CompanyCode", companyCode));
                        command.Parameters.Add(new OracleParameter(":ToDate", toDate));

                        OracleDataAdapter dataAdapter = new OracleDataAdapter(command);
                        DataTable dataTable = new DataTable();
                        dataAdapter.Fill(dataTable);

                        // Prepare the response dictionary
                        var ageingReport = new Dictionary<string, decimal>
                        {
                            ["0-30"] = Convert.ToDecimal(dataTable.Rows[0]["A30"] ?? 0),
                            ["31-60"] = Convert.ToDecimal(dataTable.Rows[0]["A60"] ?? 0),
                            ["61-90"] = Convert.ToDecimal(dataTable.Rows[0]["A90"] ?? 0),
                            ["91-120"] = Convert.ToDecimal(dataTable.Rows[0]["A120"] ?? 0),
                            ["120++"] = Convert.ToDecimal(dataTable.Rows[0]["A121"] ?? 0),
                            ["total"] = Convert.ToDecimal(dataTable.Rows[0]["A30"] ?? 0) +
                                        Convert.ToDecimal(dataTable.Rows[0]["A60"] ?? 0) +
                                        Convert.ToDecimal(dataTable.Rows[0]["A90"] ?? 0) +
                                        Convert.ToDecimal(dataTable.Rows[0]["A120"] ?? 0) +
                                        Convert.ToDecimal(dataTable.Rows[0]["A121"] ?? 0)
                        };

                        return Ok(ageingReport);
                    }
                }
            }
            catch (Exception ex)
            {
                return InternalServerError(ex); // Return 500 Internal Server Error with exception details
            }
        }
        private string GetDebitBalanceAgeingQuery()
        {
            return @"
            SELECT 
                SUM(CASE WHEN DATEDIFF(day, VOUCHER_DATE, :ToDate) BETWEEN 0 AND 30 THEN REAL_BALANCE ELSE 0 END) AS A30,
                SUM(CASE WHEN DATEDIFF(day, VOUCHER_DATE, :ToDate) BETWEEN 31 AND 60 THEN REAL_BALANCE ELSE 0 END) AS A60,
                SUM(CASE WHEN DATEDIFF(day, VOUCHER_DATE, :ToDate) BETWEEN 61 AND 90 THEN REAL_BALANCE ELSE 0 END) AS A90,
                SUM(CASE WHEN DATEDIFF(day, VOUCHER_DATE, :ToDate) BETWEEN 91 AND 120 THEN REAL_BALANCE ELSE 0 END) AS A120,
                SUM(CASE WHEN DATEDIFF(day, VOUCHER_DATE, :ToDate) > 120 THEN REAL_BALANCE ELSE 0 END) AS A121
            FROM (
                SELECT 
                VOUCHER_NO, VOUCHER_DATE, DR_AMOUNT, BALANCE_AMOUNT, CR_AMOUNT, 
                CASE WHEN ROW_NUMBER() OVER (ORDER BY VOUCHER_DATE) = 1 THEN ABS(BALANCE_AMOUNT) ELSE DR_AMOUNT END AS REAL_BALANCE
            FROM (
                SELECT VOUCHER_NO, VOUCHER_DATE, DR_AMOUNT, CR_AMOUNT, 
                    SUM(CR_AMOUNT - DR_AMOUNT) OVER (ORDER BY VOUCHER_DATE ROWS BETWEEN UNBOUNDED PRECEDING AND CURRENT ROW) AS BALANCE_AMOUNT
                FROM V$VIRTUAL_SUB_LEDGER
                WHERE COMPANY_CODE IN (:CompanyCode) 
                AND SUB_CODE = :SubCode 
                AND DELETED_FLAG = 'N'
            ) AS InnerQuery
        ) AS FinalQuery
        WHERE BALANCE_AMOUNT < 0";
        }
        private string GetCreditBalanceAgeingQuery()
        {
            return @"
        SELECT 
            SUM(CASE WHEN DATEDIFF(day, VOUCHER_DATE, :ToDate) BETWEEN 0 AND 30 THEN REAL_BALANCE ELSE 0 END) AS A30,
            SUM(CASE WHEN DATEDIFF(day, VOUCHER_DATE, :ToDate) BETWEEN 31 AND 60 THEN REAL_BALANCE ELSE 0 END) AS A60,
            SUM(CASE WHEN DATEDIFF(day, VOUCHER_DATE, :ToDate) BETWEEN 61 AND 90 THEN REAL_BALANCE ELSE 0 END) AS A90,
            SUM(CASE WHEN DATEDIFF(day, VOUCHER_DATE, :ToDate) BETWEEN 91 AND 120 THEN REAL_BALANCE ELSE 0 END) AS A120,
            SUM(CASE WHEN DATEDIFF(day, VOUCHER_DATE, :ToDate) > 120 THEN REAL_BALANCE ELSE 0 END) AS A121
        FROM (
            SELECT 
                VOUCHER_NO, VOUCHER_DATE, CR_AMOUNT, BALANCE_AMOUNT, DR_AMOUNT, 
                CASE WHEN ROW_NUMBER() OVER (ORDER BY VOUCHER_DATE) = 1 THEN ABS(BALANCE_AMOUNT) ELSE CR_AMOUNT END AS REAL_BALANCE
            FROM (
                SELECT VOUCHER_NO, VOUCHER_DATE, CR_AMOUNT, DR_AMOUNT, 
                    SUM(DR_AMOUNT - CR_AMOUNT) OVER (ORDER BY VOUCHER_DATE ROWS BETWEEN UNBOUNDED PRECEDING AND CURRENT ROW) AS BALANCE_AMOUNT
                FROM V$VIRTUAL_SUB_LEDGER
                WHERE COMPANY_CODE IN (:CompanyCode) 
                AND SUB_CODE = :SubCode 
                AND DELETED_FLAG = 'N'
            ) AS InnerQuery
        ) AS FinalQuery
        WHERE BALANCE_AMOUNT < 0";
        }
        // Helper method for branch filter (modify logic as needed)
        private string GetBranchFilter(string companyCode, string branchCode, string userNo)
        {
            if (string.IsNullOrEmpty(branchCode))
            {
                return $"(SELECT branch_code FROM SC_BRANCH_CONTROL WHERE user_no = '{userNo}' AND company_code IN ({companyCode}))";
            }
            else if (branchCode.Split(',').Length == 1)
            {
                return $"('{branchCode}', '0')";
            }
            else
            {
                return $"({branchCode})";
            }
        }
        [HttpPost]
        [Route("GetBranchFilterNames")]
        public async Task<IHttpActionResult> GetBranchFilterNames([FromBody] List<string> sendedBranchCode, string userNo, string companyCode)
        {
            try
            {
                string query;

                using (OracleConnection conn = new OracleConnection(_connection))
                {
                    conn.Open();

                    if (sendedBranchCode == null || sendedBranchCode.Count == 0)
                    {
                        // Case when branch code list is empty
                        query = $@"
                    SELECT branch_edesc 
                    FROM FA_BRANCH_SETUP 
                    WHERE branch_code IN 
                        (SELECT branch_code FROM SC_BRANCH_CONTROL WHERE user_no = :userNo AND company_code IN (:companyCode))";
                    }
                    else if (sendedBranchCode.Count == 1)
                    {
                        // Case when branch code has one element, adding '0' as fallback
                        sendedBranchCode.Add("0");
                        string branchCodes = $"('{string.Join("','", sendedBranchCode)}')";
                        query = $@"
                    SELECT branch_edesc 
                    FROM FA_BRANCH_SETUP 
                    WHERE branch_code IN {branchCodes} 
                      AND company_code IN (:companyCode)";
                    }
                    else
                    {
                        // Case when branch code has multiple elements
                        string branchCodes = $"('{string.Join("','", sendedBranchCode)}')";
                        query = $@"
                    SELECT branch_edesc 
                    FROM FA_BRANCH_SETUP 
                    WHERE branch_code IN {branchCodes} 
                      AND company_code IN (:companyCode)";
                    }

                    OracleCommand command = new OracleCommand(query, conn);
                    command.Parameters.Add(new OracleParameter("userNo", userNo));
                    command.Parameters.Add(new OracleParameter("companyCode", companyCode));

                    OracleDataReader reader = command.ExecuteReader();

                    var branches = new List<string>();
                    while (reader.Read())
                    {
                        branches.Add(reader["branch_edesc"].ToString());
                    }

                    return Ok(branches);
                }
            }
            catch (Exception ex)
            {
                return InternalServerError(ex);
            }
        }

        [HttpPost]
        [Route("GetTransactionDate")]
        public async Task<IHttpActionResult> GetTransactionDate()
        {
            try
            {
                string query = @"
                        SELECT fy_start_date, 
                               CASE WHEN SYSDATE > fy_end_date THEN fy_end_date 
                               ELSE SYSDATE END AS fy_end_date 
                        FROM PREFERENCE_SETUP 
                        WHERE ROWNUM = 1";

                using (OracleConnection conn = new OracleConnection(_connection))
                {
                    conn.Open();
                    OracleCommand command = new OracleCommand(query, conn);
                    OracleDataReader reader = command.ExecuteReader();
                    var vals = new Dictionary<string, string>();
                    if (reader.Read())
                    {
                        vals["fy_start_date"] = Convert.ToDateTime(reader["fy_start_date"]).ToString("dd-MMM-yyyy");
                        vals["fy_till_date"] = Convert.ToDateTime(reader["fy_end_date"]).ToString("dd-MMM-yyyy");
                    }
                    return Ok(vals);
                }
            }
            catch (Exception ex)
            {
                return InternalServerError(ex);
            }
        }
        [HttpPost]
        [Route("GetAllItems")]
        public async Task<IHttpActionResult> GetAllItems([FromBody] string companyCode, string grp = "", string cat = "")
        {
            try
            {
                string query = @"
                SELECT item_code, item_edesc 
                FROM IP_ITEM_MASTER_SETUP 
                WHERE GROUP_SKU_FLAG = 'I' 
                  AND DELETED_FLAG = 'N' 
                  AND company_code = :companyCode";
                if (!string.IsNullOrEmpty(grp))
                {
                    query += " AND master_item_code LIKE '%' || :grp || '%'";
                }

                if (!string.IsNullOrEmpty(cat))
                {
                    query += " AND CATEGORY_CODE = :cat";
                }
                query += " ORDER BY item_edesc";
                using (OracleConnection conn = new OracleConnection(_connection))
                {
                    conn.Open();
                    OracleCommand command = new OracleCommand(query, conn);
                    command.Parameters.Add(new OracleParameter("companyCode", companyCode));

                    if (!string.IsNullOrEmpty(grp))
                    {
                        command.Parameters.Add(new OracleParameter("grp", grp));
                    }

                    if (!string.IsNullOrEmpty(cat))
                    {
                        command.Parameters.Add(new OracleParameter("cat", cat));
                    }
                    OracleDataReader reader = command.ExecuteReader();
                    var items = new Dictionary<string, string>();

                    while (reader.Read())
                    {
                        items[reader["item_code"].ToString()] = reader["item_edesc"].ToString();
                    }
                    return Ok(items);
                }
            }
            catch (Exception ex)
            {
                return InternalServerError(ex);
            }
        }
        [HttpPost]
        [Route("GetVoucherDetails")]
        public async Task<IHttpActionResult> GetVoucherDetails([FromBody] string companyCode, string voucherNo)
        {
            using (OracleConnection conn = new OracleConnection(_connection)) // Use OracleConnection for Oracle DB
            {
                try
                {
                    conn.Open();

                    // Step 1: Query for getting voucher details
                    string query1 = @"
                        SELECT a.form_code, b.form_type, a.voucher_no, a.voucher_date, a.created_by,
                            (SELECT table_name FROM FORM_DETAIL_SETUP WHERE form_code = a.form_code AND company_code = :CompanyCode GROUP BY table_name) AS tab_name,
                            a.authorised_by, NVL(a.authorised_date, '') AS authorised_date, a.posted_by, NVL(a.posted_date, '') AS posted_date,
                            a.CHECKED_BY, NVL(a.CHECKED_date, '') AS checked_date
                        FROM master_transaction a
                        JOIN form_setup b ON a.form_code = b.form_code AND a.company_code = b.company_code
                        WHERE a.voucher_no = :VoucherNo AND a.company_code = :CompanyCode";

                    OracleCommand cmd = new OracleCommand(query1, conn);
                    cmd.Parameters.Add(new OracleParameter("CompanyCode", companyCode));
                    cmd.Parameters.Add(new OracleParameter("VoucherNo", voucherNo));

                    OracleDataReader reader = cmd.ExecuteReader();

                    if (reader.HasRows)
                    {
                        reader.Read();

                        // Step 2: Retrieve the voucher details from the first query
                        string formType = reader["form_type"].ToString();
                        string voucherNumber = reader["voucher_no"].ToString();
                        DateTime voucherDate = Convert.ToDateTime(reader["voucher_date"]);
                        string createdBy = reader["created_by"].ToString();
                        string tableName = reader["tab_name"].ToString();
                        string authorisedBy = reader["authorised_by"].ToString();
                        string authorisedDate = reader["authorised_date"].ToString();
                        string postedBy = reader["posted_by"].ToString();
                        string postedDate = reader["posted_date"].ToString();
                        string checkedBy = reader["checked_by"].ToString();
                        string checkedDate = reader["checked_date"].ToString();

                        // Step 3: Dictionary for dynamic table/column mapping
                        var distinctColumns = new Dictionary<string, Dictionary<string, string>>
                {
                    { "SA_QUOTATION_DETAILS", new Dictionary<string, string> { { "V_NO", "QUOTATION_NO" }, { "V_DATE", "QUOTATION_DATE" }, { "PARTY_NAME", "customer_edesc" }, { "PARTY_TABLE_NAME", "sa_customer_setup" }, { "PARTY_CODE", "customer_code" }, { "SUB_CODE", "C" } } },
                    { "SA_SALES_ORDER", new Dictionary<string, string> { { "V_NO", "ORDER_NO" }, { "V_DATE", "ORDER_DATE" }, { "PARTY_NAME", "customer_edesc" }, { "PARTY_TABLE_NAME", "sa_customer_setup" }, { "PARTY_CODE", "customer_code" }, { "SUB_CODE", "C" } } },
                    { "SA_SALES_INVOICE", new Dictionary<string, string> { { "V_NO", "SALES_NO" }, { "V_DATE", "SALES_DATE" }, { "PARTY_NAME", "customer_edesc" }, { "PARTY_TABLE_NAME", "sa_customer_setup" }, { "PARTY_CODE", "customer_code" }, { "SUB_CODE", "C" } } },
                    // Add other table mappings as necessary
                };

                        // Step 4: Check if the table exists in the dictionary
                        if (distinctColumns.ContainsKey(tableName))
                        {
                            var tableMapping = distinctColumns[tableName];

                            // Step 5: Prepare the second query based on dynamic table and columns
                            string subQuery = $@"
                        SELECT b.{tableMapping["PARTY_NAME"]}, a.{tableMapping["V_NO"]}, TO_CHAR(a.{tableMapping["V_DATE"]}, 'DD/MM/YYYY') AS {tableMapping["V_DATE"]},
                               a.serial_no, a.item_code, c.item_edesc, a.mu_code, a.QUANTITY, a.UNIT_PRICE, 
                               NVL(a.total_price * a.exchange_rate, 1) AS total_price, '{tableMapping["SUB_CODE"]}' || a.{tableMapping["PARTY_CODE"]} AS party_code, a.remarks
                        FROM {tableName} a
                        JOIN {tableMapping["PARTY_TABLE_NAME"]} b ON a.company_code = b.company_code AND a.{tableMapping["PARTY_CODE"]} = b.{tableMapping["PARTY_CODE"]}
                        JOIN ip_item_master_setup c ON a.company_code = c.company_code AND a.item_code = c.item_code
                        WHERE a.company_code = :CompanyCode AND a.{tableMapping["V_NO"]} = :VoucherNo
                        ORDER BY a.serial_no";

                            OracleCommand subCmd = new OracleCommand(subQuery, conn);
                            subCmd.Parameters.Add(new OracleParameter("CompanyCode", companyCode));
                            subCmd.Parameters.Add(new OracleParameter("VoucherNo", voucherNo));

                            OracleDataReader subReader = subCmd.ExecuteReader();
                            var itemList = new List<object>();

                            // Step 6: Fetch item details from the sub-query
                            while (subReader.Read())
                            {
                                itemList.Add(new
                                {
                                    SerialNo = subReader["serial_no"],
                                    Item = subReader["item_edesc"],
                                    Unit = subReader["mu_code"],
                                    Quantity = Convert.ToDouble(subReader["QUANTITY"]),
                                    Rate = Convert.ToDouble(subReader["UNIT_PRICE"]),
                                    Amount = Convert.ToDouble(subReader["total_price"]),
                                    Remarks = subReader["remarks"],
                                    PartyCode = subReader["party_code"]
                                });
                            }

                            // Step 7: Return the voucher details and the item list
                            return Ok(new
                            {
                                Detail = itemList,
                                VoucherNo = voucherNumber,
                                VoucherDate = voucherDate.ToString("yyyy-MM-dd"),
                                CreatedBy = createdBy,
                                AuthorisedBy = authorisedBy,
                                AuthorisedDate = authorisedDate,
                                PostedBy = postedBy,
                                PostedDate = postedDate,
                                CheckedBy = checkedBy,
                                CheckedDate = checkedDate
                            });
                        }

                        // Step 8: Return if the form type is invalid
                        return Ok(new { Message = "Invalid Form Type." });
                    }

                    // Step 9: Handle case where no voucher is found
                    return NotFound();
                }
                catch (Exception ex)
                {
                    // Step 10: Handle any errors
                    return InternalServerError(ex);
                }
            }
        }

        [HttpPost]
        [Route("GetSalesTodayYTDMTD")]
        public async Task<IHttpActionResult> GetSalesTodayYTDMTD([FromBody] OverviewRequestModel model)
        {
            var branchCode = new List<string>();
            var results = new Dictionary<string, object>();
            var allReps = new List<string> { "sales", "collection", "production", "purchase", "payment" };

            if (!string.IsNullOrEmpty(model.ItemStringFilter))
            {
                string filterData = model.ItemStringFilter.ToLower();
                //List<DateRange> filteredRanges = GetVDateRanges(filterData);
                var filteredReps = allReps.Where(rep => rep.IndexOf(model.ItemStringFilter, StringComparison.OrdinalIgnoreCase) >= 0).ToList();

                //if (filterData!="")
                foreach (var rep in filteredReps)
                {
                    string query = string.Empty;
                    if (rep == "sales")
                    {
                    query = $@"
                    SELECT 
                    startdate,
                    rangename,
                    inde,
                    ROUND(SUM(sales_qty - sales_ret_qty)) AS total_sales_qty,
                    ROUND(SUM(sales_value - sales_ret_value)) AS total_sales_value,
                   ROUND(CASE 
                    WHEN RANGENAME = 'Today' THEN 
                        ROUND(SUM(sales_value - sales_ret_value), 2)
                    ELSE 
                        ROUND(SUM(sales_value - sales_ret_value) / 
                            CASE 
                                WHEN TRUNC(SYSDATE) - startdate = 0 THEN 1 
                                ELSE TRUNC(SYSDATE) - startdate 
                            END, 2)
                END) AS avg_perday
                FROM (
                    SELECT * FROM (
                        SELECT 
                            A.COMPANY_CODE,
                            A.BRANCH_CODE,
                            A.sales_date,
                            SUM(NVL(A.ROLL_QTY, 0)) AS SALES_ROLL_QTY,
                            SUM(NVL(A.QUANTITY, 0)) AS SALES_QTY,
                            SUM(NVL(A.QUANTITY * A.NET_GROSS_RATE, 0)) AS SALES_VALUE,
                            0 AS SALES_RET_ROLL_QTY,
                            0 AS SALES_RET_QTY,
                            0 AS SALES_RET_VALUE
                        FROM 
                            SA_SALES_INVOICE A
                        WHERE 
                            A.DELETED_FLAG = 'N'
                            AND A.COMPANY_CODE IN ('{model.CompanyCode}')                                                             
                        GROUP BY  
                            A.COMPANY_CODE, 
                            A.BRANCH_CODE, 
                            A.sales_date
        
                        UNION ALL
        
                        SELECT 
                            A.COMPANY_CODE, 
                            A.BRANCH_CODE, 
                            A.return_date,
                            0 AS SALES_ROLL_QTY, 
                            0 AS SALES_QTY, 
                            0 AS SALES_VALUE,
                            SUM(NVL(A.ROLL_QTY, 0)) AS SALES_RET_ROLL_QTY, 
                            SUM(NVL(A.QUANTITY, 0)) AS SALES_RET_QTY,
                            SUM(NVL(A.QUANTITY * A.NET_GROSS_RATE, 0)) AS SALES_RET_VALUE  
                        FROM 
                            SA_SALES_RETURN A
                        WHERE 
                            A.DELETED_FLAG = 'N'
                            AND A.COMPANY_CODE IN ('{model.CompanyCode}')                                 
                        GROUP BY  
                            A.COMPANY_CODE, 
                            A.BRANCH_CODE,  
                            A.return_date 
                        ORDER BY 
                            sales_date 
                    ) a
                    LEFT OUTER JOIN (
                        SELECT 
                            startdate,
                            enddate,
                            rangename,
                            TO_NUMBER('11') AS inde 
                        FROM 
                            V_DATE_RANGE 
                        WHERE 
                            sortorder IN ('2')
        
                        UNION ALL
        
                        SELECT 
                            TRUNC(TO_DATE(SUBSTR(TO_CHAR(SYSDATE, 'YYYY-MM-DD'), 1, 8) || '01', 'YYYY-MM-DD')) AS FDATE, 
                            TRUNC(SYSDATE) AS TDATE, 
                            'This_Month' AS ra,
                            10 AS s 
                        FROM 
                            DUAL                             
       
                        UNION ALL
        
                        SELECT  
                            TRUNC(SYSDATE) AS FDATE, 
                            TRUNC(SYSDATE) AS TDATE,
                            'Today' AS rangename,
                            TO_NUMBER('9') AS inde  
                        FROM 
                            V_DATE_RANGE 
                        WHERE 
                            sortorder IN ('3') 
        
                        UNION ALL
        
                        SELECT  
                            TRUNC(SYSDATE) - 1 AS FDATE, 
                            TRUNC(SYSDATE) - 1 AS TDATE,
                            'Yesterday' AS rangename,
                            TO_NUMBER('8') AS inde 
                        FROM 
                            DUAL
        
                        UNION ALL
        
                        SELECT  
                            TRUNC(SYSDATE - n) AS FDATE, 
                            TRUNC(SYSDATE - n) AS TDATE,
                            SUBSTR(TO_CHAR(TRUNC(SYSDATE - n), 'DAY'), 1, 3) || '-' || 
                            TO_CHAR(TRUNC(SYSDATE - n), 'MM') || '/' ||
                            TO_CHAR(TRUNC(SYSDATE - n), 'DD') AS sas,
                            TO_NUMBER('1200') AS rangename  
                        FROM 
                            (SELECT ROWNUM n FROM dual CONNECT BY LEVEL <= 7) 
                        WHERE 
                            n >= 1
                    ) b
                    ON a.sales_date BETWEEN b.startdate AND b.enddate    
                ) 
                GROUP BY 
                    startdate, 
                    rangename, 
                    inde 
                ORDER BY 
                    startdate";
                    }
                    else if (rep == "collection")
                    {
                   query = $@"
                    SELECT startdate, rangename, inde,
                    ISNULL(SUM(qty), 0), ISNULL(SUM(AMT), 0),
                     CASE WHEN RANGENAME = 'Today' THEN
                        SUM(ISNULL(AMT, 0))
                    ELSE
                        (SUM(ISNULL(AMT, 0)) / 
                        (CASE WHEN DATEDIFF(DAY, startdate, GETDATE()) = 0 THEN 1 ELSE DATEDIFF(DAY, startdate, GETDATE()) END))
                    END AS avg_perday
                    FROM
                    (
                        SELECT A.ORDER_DATE AS startdate, 
                               b.rangename, 
                               b.ind, 
                               SUM(NVL(qty, 0)) AS qty,
                               SUM(NVL(AMT, 0)) AS AMT 
                        FROM V$PRODUCTION_ORDER A 
                        INNER JOIN 
                        (
                            SELECT startdate, enddate, rangename, CAST('11' AS INT) AS inde 
                            FROM V_DATE_RANGE 
                            WHERE sortorder IN ('2')
                            UNION ALL 
                            SELECT CAST(CONCAT(SUBSTRING(CONVERT(VARCHAR, GETDATE(), 112), 1, 8), '01') AS DATE) AS FDATE,
                                   CAST(GETDATE() AS DATE) AS TDATE, 
                                   'This_Month' AS ra, 10 AS s 
                            FROM DUAL
                            UNION ALL
                            SELECT CAST(GETDATE() AS DATE) AS startdate, 
                                   CAST(GETDATE() AS DATE) AS enddate, 
                                   'Today' AS rangename, CAST('9' AS INT) AS inde  
                            FROM V_DATE_RANGE 
                            WHERE sortorder IN ('3') 
                            UNION ALL
                            SELECT CAST(DATEADD(DAY, -1, GETDATE()) AS DATE) AS FDATE, 
                                   CAST(DATEADD(DAY, -1, GETDATE()) AS DATE) AS TDATE, 
                                   'Yesterday' AS rangename, CAST('8' AS INT) AS inde  
                            FROM DUAL
                            UNION ALL
                            SELECT CAST(DATEADD(DAY, -n, GETDATE()) AS DATE) AS startdate, 
                                   CAST(DATEADD(DAY, -n, GETDATE()) AS DATE) AS enddate, 
                                   CONCAT(LEFT(DATENAME(WEEKDAY, DATEADD(DAY, -n, GETDATE())), 3), '-', 
                                   MONTH(DATEADD(DAY, -n, GETDATE())),'/', 
                                   DAY(DATEADD(DAY, -n, GETDATE()))) AS sas, 
                                   CAST('1200' AS INT) AS rangename  
                            FROM (SELECT ROW_NUMBER() OVER (ORDER BY (SELECT NULL)) n FROM master.dbo.spt_values) t 
                            WHERE n >= 1 AND n <= 7
                        ) b
                        ON A.ORDER_DATE BETWEEN b.startdate AND b.enddate
                        GROUP BY A.ORDER_DATE, b.rangename, b.ind
                    ) 
                    GROUP BY startdate, rangename, inde 
                    ORDER BY startdate";

                        query = $@"SELECT 
                            startdate,
                            rangename,
                            inde,
                            ROUND(SUM(AMT), 2) AS total_amt,
                            ROUND(SUM(AMT), 2) AS total_amt_duplicated,
                             ROUND(
                            CASE 
                                WHEN RANGENAME = 'Today' THEN SUM(AMT)
                                ELSE (SUM(AMT) / 
                                      CASE 
                                          WHEN TRUNC(SYSDATE) - startdate = 0 THEN 1 
                                          ELSE TRUNC(SYSDATE) - startdate 
                                      END)
                            END, 2) AS avg_perday 
                        FROM (
                            SELECT * FROM (
                                SELECT 
                                    voucher_date, 
                                    NVL(SUM(NVL(CR_AMOUNT, 0) * NVL(EXCHANGE_RATE, 1)), 0) AS amt
                                FROM 
                                    V$VIRTUAL_SUB_LEDGER b
                                WHERE 
                                    (COMPANY_CODE, Voucher_NO) IN (
                                        SELECT 
                                            COMPANY_CODE, A.voucher_no
                                        FROM 
                                            V$VIRTUAL_GENERAL_LEDGER A
                                        WHERE 
                                            A.ACC_CODE IN (
                                                SELECT ACC_CODE 
                                                FROM FA_CHART_OF_ACCOUNTS_SETUP 
                                                WHERE ACC_NATURE IN ('AB', 'AC', 'LC') 
                                                  AND COMPANY_CODE = A.COMPANY_CODE
                                            )
                                            AND A.TRANSACTION_TYPE = 'DR'
                                            AND A.COMPANY_CODE = '{model.CompanyCode}'
                                            AND A.DELETED_FLAG = 'N'
                                            AND A.Voucher_NO != '0'
                                    )
                                    AND SUBSTR(sub_code, 1, 1) = 'C'
                                    AND TRANSACTION_TYPE = 'CR'
                                GROUP BY 
                                    voucher_date
                            ) a
                            LEFT OUTER JOIN (
                                SELECT 
                                    startdate, 
                                    enddate, 
                                    rangename, 
                                    TO_NUMBER('11') AS inde 
                                FROM 
                                    V_DATE_RANGE 
                                WHERE 
                                    sortorder IN ('2')

                                UNION ALL 

                                SELECT 
                                    TRUNC(TO_DATE(SUBSTR(TO_CHAR(SYSDATE, 'YYYY-MM-DD'), 1, 8) || '01', 'YYYY-MM-DD')) AS startdate, 
                                    TRUNC(SYSDATE) AS enddate, 
                                    'This_Month' AS rangename, 
                                    10 AS inde 
                                FROM 
                                    DUAL

                                UNION ALL

                                SELECT  
                                    TRUNC(SYSDATE) AS startdate, 
                                    TRUNC(SYSDATE) AS enddate, 
                                    'Today' AS rangename, 
                                    TO_NUMBER('9') AS inde  
                                FROM 
                                    V_DATE_RANGE 
                                WHERE 
                                    sortorder IN ('3')

                                UNION ALL

                                SELECT  
                                    TRUNC(SYSDATE - 1) AS startdate, 
                                    TRUNC(SYSDATE - 1) AS enddate, 
                                    'Yesterday' AS rangename, 
                                    TO_NUMBER('8') AS inde 
                                FROM 
                                    DUAL

                                UNION ALL

                                SELECT  
                                    TRUNC(SYSDATE - n) AS startdate, 
                                    TRUNC(SYSDATE - n) AS enddate, 
                                    SUBSTR(TO_CHAR(TRUNC(SYSDATE - n), 'DAY'), 1, 3) || '-' || 
                                    EXTRACT(MONTH FROM TRUNC(SYSDATE - n)) || '/' || 
                                    EXTRACT(DAY FROM TRUNC(SYSDATE - n)) AS rangename, 
                                    TO_NUMBER('1200') AS inde  
                                FROM 
                                    (SELECT ROWNUM AS n FROM dual CONNECT BY LEVEL <= 7)
                                WHERE 
                                    n >= 1
                            ) b
                            ON a.voucher_date BETWEEN b.startdate AND b.enddate
                        )
                        GROUP BY 
                            startdate, 
                            rangename, 
                            inde 
                        ORDER BY 
                            startdate";
                    }
                    else if (rep == "production")
                    {
                        query = $@"
                    SELECT 
                        startdate,
                        rangename,
                        inde,
                        ROUND(NVL(SUM(qty), 0)) AS total_qty,
                        ROUND(NVL(SUM(AMT), 0)) AS total_amt,
                        ROUND(CASE 
                            WHEN RANGENAME = 'Today' THEN SUM(NVL(AMT, 0))
                            ELSE (SUM(NVL(AMT, 0)) / 
                                  CASE 
                                      WHEN TRUNC(SYSDATE) - startdate = 0 THEN 1 
                                      ELSE TRUNC(SYSDATE) - startdate 
                                  END)
                        END) AS avg_perday
                    FROM (
                        SELECT * FROM (
                            -- Main query to calculate quantity and amount grouped by mrr_date
                            SELECT 
                                mrr_date, 
                                SUM(quantity) AS qty, 
                                SUM(total_price) AS amt 
                            FROM 
                                IP_PRODUCTION_MRR 
                            WHERE 
                                deleted_flag = 'N' 
                                AND COMPANY_CODE IN ('{model.CompanyCode}') 
                            GROUP BY 
                                mrr_date
                        ) a
                        LEFT OUTER JOIN (
                            -- Date range subquery to get different ranges like Today, Yesterday, etc.
                            SELECT 
                                startdate, 
                                enddate, 
                                rangename, 
                                TO_NUMBER('11') AS inde 
                            FROM 
                                V_DATE_RANGE 
                            WHERE 
                                sortorder IN ('2')

                            UNION ALL 

                            SELECT 
                                TRUNC(TO_DATE(SUBSTR(TO_CHAR(SYSDATE, 'YYYY-MM-DD'), 1, 8) || '01', 'YYYY-MM-DD')) AS startdate, 
                                TRUNC(SYSDATE) AS enddate, 
                                'This_Month' AS rangename, 
                                10 AS inde 
                            FROM 
                                DUAL

                            UNION ALL 

                            SELECT 
                                TRUNC(SYSDATE) AS startdate, 
                                TRUNC(SYSDATE) AS enddate, 
                                'Today' AS rangename, 
                                TO_NUMBER('9') AS inde  
                            FROM 
                                V_DATE_RANGE 
                            WHERE 
                                sortorder IN ('3')

                            UNION ALL 

                            SELECT  
                                TRUNC(SYSDATE - 1) AS startdate, 
                                TRUNC(SYSDATE - 1) AS enddate, 
                                'Yesterday' AS rangename, 
                                TO_NUMBER('8') AS inde  
                            FROM 
                                DUAL

                            UNION ALL 

                            -- Generating previous 7 days dynamically
                            SELECT  
                                TRUNC(SYSDATE - n) AS startdate, 
                                TRUNC(SYSDATE - n) AS enddate, 
                                SUBSTR(TO_CHAR(TRUNC(SYSDATE - n), 'DAY'), 1, 3) || '-' || 
                                EXTRACT(MONTH FROM TRUNC(SYSDATE - n)) || '/' || 
                                EXTRACT(DAY FROM TRUNC(SYSDATE - n)) AS rangename, 
                                TO_NUMBER('1200') AS inde  
                            FROM 
                                (SELECT ROWNUM AS n FROM dual CONNECT BY LEVEL <= 7)
                            WHERE 
                                n >= 1
                        ) b
                        ON a.mrr_date BETWEEN b.startdate AND b.enddate
                    )
                    GROUP BY 
                        startdate, 
                        rangename, 
                        inde 
                    ORDER BY 
                        startdate";
                    }
                    else if (rep == "purchase")
                    {
                        query = $@"
                    SELECT 
                        startdate,
                        rangename,
                        inde,
                        ROUND(SUM(sales_qty - sales_ret_qty)) AS net_sales_qty,
                        ROUND(SUM(sales_value - sales_ret_value)) AS net_sales_value,
                        ROUND(CASE 
                            WHEN rangename = 'Today' THEN SUM(sales_value - sales_ret_value)
                            ELSE 
                                (SUM(sales_value - sales_ret_value) / 
                                CASE 
                                    WHEN TRUNC(SYSDATE) - startdate = 0 THEN 1 
                                    ELSE TRUNC(SYSDATE) - startdate 
                                END)
                        END) AS avg_perday
                    FROM (
                        SELECT * FROM (
                            -- Sales Invoice Subquery
                            SELECT 
                                A.COMPANY_CODE, 
                                A.BRANCH_CODE, 
                                A.invoice_date AS sales_date,
                                SUM(NVL(A.ROLL_QTY, 0)) AS sales_roll_qty, 
                                SUM(NVL(A.QUANTITY, 0)) AS sales_qty, 
                                SUM(NVL(A.QUANTITY * A.NET_GROSS_RATE, 0)) AS sales_value,
                                0 AS sales_ret_roll_qty, 
                                0 AS sales_ret_qty, 
                                0 AS sales_ret_value  
                            FROM 
                                ip_purchase_invoice A 
                            WHERE 
                                A.DELETED_FLAG = 'N' 
                                AND A.COMPANY_CODE IN ('{model.CompanyCode}')
                            GROUP BY 
                                A.COMPANY_CODE, A.BRANCH_CODE, A.invoice_date
        
                            UNION ALL
        
                            -- Sales Return Subquery
                            SELECT 
                                A.COMPANY_CODE, 
                                A.BRANCH_CODE, 
                                A.return_date AS sales_date,
                                0 AS sales_roll_qty, 
                                0 AS sales_qty, 
                                0 AS sales_value,
                                SUM(NVL(A.ROLL_QTY, 0)) AS sales_ret_roll_qty, 
                                SUM(NVL(A.QUANTITY, 0)) AS sales_ret_qty,
                                SUM(NVL(A.QUANTITY * A.NET_GROSS_RATE, 0)) AS sales_ret_value 
                            FROM 
                                ip_purchase_return A
                            WHERE 
                                A.DELETED_FLAG = 'N'
                                AND A.COMPANY_CODE IN ('{model.CompanyCode}')
                            GROUP BY 
                                A.COMPANY_CODE, A.BRANCH_CODE, A.return_date
                        ) a
                        LEFT OUTER JOIN (
                            -- Date Range Subquery
                            SELECT 
                                startdate, 
                                enddate, 
                                rangename, 
                                TO_NUMBER('11') AS inde 
                            FROM 
                                V_DATE_RANGE 
                            WHERE 
                                sortorder IN ('2')

                            UNION ALL

                            -- 'This Month' Date Range
                            SELECT 
                                TRUNC(TO_DATE(SUBSTR(TO_CHAR(SYSDATE, 'YYYY-MM-DD'), 1, 8) || '01', 'YYYY-MM-DD')) AS startdate, 
                                TRUNC(SYSDATE) AS enddate, 
                                'This_Month' AS rangename, 
                                10 AS inde 
                            FROM 
                                DUAL

                            UNION ALL

                            -- 'Today' Date Range
                            SELECT 
                                TRUNC(SYSDATE) AS startdate, 
                                TRUNC(SYSDATE) AS enddate, 
                                'Today' AS rangename, 
                                TO_NUMBER('9') AS inde 
                            FROM 
                                V_DATE_RANGE 
                            WHERE 
                                sortorder IN ('3')

                            UNION ALL

                            -- 'Yesterday' Date Range
                            SELECT  
                                TRUNC(SYSDATE - 1) AS startdate, 
                                TRUNC(SYSDATE - 1) AS enddate, 
                                'Yesterday' AS rangename, 
                                TO_NUMBER('8') AS inde 
                            FROM 
                                DUAL

                            UNION ALL

                            -- Last 7 Days
                            SELECT  
                                TRUNC(SYSDATE - n) AS startdate, 
                                TRUNC(SYSDATE - n) AS enddate, 
                                SUBSTR(TO_CHAR(TRUNC(SYSDATE - n), 'DAY'), 1, 3) || '-' || 
                                EXTRACT(MONTH FROM TRUNC(SYSDATE - n)) || '/' || 
                                EXTRACT(DAY FROM TRUNC(SYSDATE - n)) AS rangename, 
                                TO_NUMBER('1200') AS inde 
                            FROM 
                                (SELECT ROWNUM AS n FROM DUAL CONNECT BY LEVEL <= 7)
                            WHERE 
                                n >= 1
                        ) b
                        ON a.sales_date BETWEEN b.startdate AND b.enddate
                    )
                    GROUP BY 
                        startdate, 
                        rangename, 
                        inde
                    ORDER BY 
                        startdate";
                    }
                    else if (rep == "payment")
                    {
                        query = $@"
                    SELECT 
                        startdate,
                        rangename,
                        inde,
                        ROUND(SUM(AMT)) AS total_amt,
                        ROUND(SUM(AMT)) AS total_amt_copy,
                        ROUND(CASE 
                            WHEN RANGENAME = 'Today' THEN SUM(AMT)
                            ELSE 
                                (SUM(AMT) / 
                                 CASE 
                                     WHEN TRUNC(SYSDATE) - startdate = 0 THEN 1 
                                     ELSE TRUNC(SYSDATE) - startdate 
                                 END
                                )
                        END) AS avg_perday
                    FROM (
                        SELECT * FROM (
                            -- Main subquery to calculate amounts grouped by voucher_date
                            SELECT 
                                voucher_date,
                                NVL(SUM(NVL(DR_AMOUNT, 0) * NVL(EXCHANGE_RATE, 1)), 0) AS amt 
                            FROM 
                                V$VIRTUAL_SUB_LEDGER 
                            WHERE 
                                DELETED_FLAG = 'N' 
                                AND COMPANY_CODE = '{model.CompanyCode}' 
                                AND DR_AMOUNT > 0
                                AND SUBSTR(sub_code, 1, 1) = 'S' 
                                AND VOUCHER_DATE IS NOT NULL 
                            GROUP BY 
                                voucher_date
                        ) a
                        LEFT OUTER JOIN (
                            -- Date range subquery to get date ranges like 'Today', 'Yesterday', 'This Month', etc.
                            SELECT 
                                startdate, 
                                enddate, 
                                rangename, 
                                TO_NUMBER('11') AS inde 
                            FROM 
                                V_DATE_RANGE 
                            WHERE 
                                sortorder IN ('2')

                            UNION ALL 

                            -- 'This Month' date range
                            SELECT 
                                TRUNC(TO_DATE(SUBSTR(TO_CHAR(SYSDATE, 'YYYY-MM-DD'), 1, 8) || '01', 'YYYY-MM-DD')) AS startdate, 
                                TRUNC(SYSDATE) AS enddate, 
                                'This_Month' AS rangename, 
                                10 AS inde 
                            FROM 
                                DUAL

                            UNION ALL 

                            -- 'Today' date range
                            SELECT 
                                TRUNC(SYSDATE) AS startdate, 
                                TRUNC(SYSDATE) AS enddate, 
                                'Today' AS rangename, 
                                TO_NUMBER('9') AS inde 
                            FROM 
                                V_DATE_RANGE 
                            WHERE 
                                sortorder IN ('3')

                            UNION ALL 

                            -- 'Yesterday' date range
                            SELECT  
                                TRUNC(SYSDATE - 1) AS startdate, 
                                TRUNC(SYSDATE - 1) AS enddate, 
                                'Yesterday' AS rangename, 
                                TO_NUMBER('8') AS inde 
                            FROM 
                                DUAL

                            UNION ALL 

                            -- Last 7 days
                            SELECT  
                                TRUNC(SYSDATE - n) AS startdate, 
                                TRUNC(SYSDATE - n) AS enddate, 
                                SUBSTR(TO_CHAR(TRUNC(SYSDATE - n), 'DAY'), 1, 3) || '-' || 
                                EXTRACT(MONTH FROM TRUNC(SYSDATE - n)) || '/' || 
                                EXTRACT(DAY FROM TRUNC(SYSDATE - n)) AS rangename, 
                                TO_NUMBER('1200') AS inde 
                            FROM 
                                (SELECT ROWNUM AS n FROM dual CONNECT BY LEVEL <= 7)
                            WHERE 
                                n >= 1
                        ) b
                        ON a.voucher_date BETWEEN b.startdate AND b.enddate
                    )
                    GROUP BY 
                        startdate, 
                        rangename, 
                        inde 
                    ORDER BY 
                        startdate";
                    }
                    // Execute the query and get the results
                    using (OracleConnection connYTDMTD = new OracleConnection(_connection))
                    {
                        try
                        {
                            connYTDMTD.Open();
                            using (OracleCommand cmdYTDMTD = new OracleCommand(query, connYTDMTD))
                            {
                                cmdYTDMTD.CommandType = CommandType.Text;
                                cmdYTDMTD.CommandTimeout = 500;
                                cmdYTDMTD.ExecuteNonQuery();
                                //using (OracleDataAdapter adapterYTDMTD = new OracleDataAdapter(cmdYTDMTD))
                                //{
                                //    DataTable dt = new DataTable();
                                //    adapterYTDMTD.Fill(dt);
                                //    foreach (DataRow row in dt.Rows)
                                //    {
                                //        var rangename = row["rangename"].ToString();
                                //        results[$"{rep}_{rangename}"] = new
                                //        {
                                //            TotalQty = Convert.ToDecimal(row[3]),
                                //            TotalAmt = Convert.ToDecimal(row[4]),
                                //            AvgPerDay = Convert.ToDecimal(row[5])
                                //        };
                                //    }
                                //}
                                using (OracleDataReader reader = cmdYTDMTD.ExecuteReader())
                                {
                                    while (reader.Read())
                                    {
                                        var rangename = reader["rangename"]?.ToString() ?? "Unknown";
                                        // Safe parsing of decimal values
                                        decimal totalQty = reader.IsDBNull(3) ? 0 : Convert.ToDecimal(reader.GetValue(3));
                                        decimal totalAmt = reader.IsDBNull(4) ? 0 : Convert.ToDecimal(reader.GetValue(4));
                                        decimal avgPerDay = reader.IsDBNull(5) ? 0 : Convert.ToDecimal(reader.GetValue(5));
                                        // Ensure unique key before adding
                                        string key = $"{rep}_{rangename}";
                                        if (!results.ContainsKey(key))
                                        {
                                            results[key] = new
                                            {
                                                TotalQty = totalQty,
                                                TotalAmt = totalAmt,
                                                AvgPerDay = avgPerDay
                                            };
                                        }
                                    }
                                }
                            }
                        }
                        catch (Exception ex)
                        {

                        }
                    }
                }
            }
            else
            {
                foreach (var rep in allReps)
                {
                    string query = string.Empty;

                    if (rep == "sales")
                    {
                        query = $@"
                    SELECT 
                    startdate,
                    rangename,
                    inde,
                    ROUND(SUM(sales_qty - sales_ret_qty)) AS total_sales_qty,
                    ROUND(SUM(sales_value - sales_ret_value)) AS total_sales_value,
                   ROUND(CASE 
                    WHEN RANGENAME = 'Today' THEN 
                        ROUND(SUM(sales_value - sales_ret_value), 2)
                    ELSE 
                        ROUND(SUM(sales_value - sales_ret_value) / 
                            CASE 
                                WHEN TRUNC(SYSDATE) - startdate = 0 THEN 1 
                                ELSE TRUNC(SYSDATE) - startdate 
                            END, 2)
                END) AS avg_perday
                FROM (
                    SELECT * FROM (
                        SELECT 
                            A.COMPANY_CODE,
                            A.BRANCH_CODE,
                            A.sales_date,
                            SUM(NVL(A.ROLL_QTY, 0)) AS SALES_ROLL_QTY,
                            SUM(NVL(A.QUANTITY, 0)) AS SALES_QTY,
                            SUM(NVL(A.QUANTITY * A.NET_GROSS_RATE, 0)) AS SALES_VALUE,
                            0 AS SALES_RET_ROLL_QTY,
                            0 AS SALES_RET_QTY,
                            0 AS SALES_RET_VALUE
                        FROM 
                            SA_SALES_INVOICE A
                        WHERE 
                            A.DELETED_FLAG = 'N'
                            AND A.COMPANY_CODE IN ('{model.CompanyCode}')                                                             
                        GROUP BY  
                            A.COMPANY_CODE, 
                            A.BRANCH_CODE, 
                            A.sales_date
        
                        UNION ALL
        
                        SELECT 
                            A.COMPANY_CODE, 
                            A.BRANCH_CODE, 
                            A.return_date,
                            0 AS SALES_ROLL_QTY, 
                            0 AS SALES_QTY, 
                            0 AS SALES_VALUE,
                            SUM(NVL(A.ROLL_QTY, 0)) AS SALES_RET_ROLL_QTY, 
                            SUM(NVL(A.QUANTITY, 0)) AS SALES_RET_QTY,
                            SUM(NVL(A.QUANTITY * A.NET_GROSS_RATE, 0)) AS SALES_RET_VALUE  
                        FROM 
                            SA_SALES_RETURN A
                        WHERE 
                            A.DELETED_FLAG = 'N'
                            AND A.COMPANY_CODE IN ('{model.CompanyCode}')                                 
                        GROUP BY  
                            A.COMPANY_CODE, 
                            A.BRANCH_CODE,  
                            A.return_date 
                        ORDER BY 
                            sales_date 
                    ) a
                    LEFT OUTER JOIN (
                        SELECT 
                            startdate,
                            enddate,
                            rangename,
                            TO_NUMBER('11') AS inde 
                        FROM 
                            V_DATE_RANGE 
                        WHERE 
                            sortorder IN ('2')
        
                        UNION ALL
        
                        SELECT 
                            TRUNC(TO_DATE(SUBSTR(TO_CHAR(SYSDATE, 'YYYY-MM-DD'), 1, 8) || '01', 'YYYY-MM-DD')) AS FDATE, 
                            TRUNC(SYSDATE) AS TDATE, 
                            'This_Month' AS ra,
                            10 AS s 
                        FROM 
                            DUAL                             
       
                        UNION ALL
        
                        SELECT  
                            TRUNC(SYSDATE) AS FDATE, 
                            TRUNC(SYSDATE) AS TDATE,
                            'Today' AS rangename,
                            TO_NUMBER('9') AS inde  
                        FROM 
                            V_DATE_RANGE 
                        WHERE 
                            sortorder IN ('3') 
        
                        UNION ALL
        
                        SELECT  
                            TRUNC(SYSDATE) - 1 AS FDATE, 
                            TRUNC(SYSDATE) - 1 AS TDATE,
                            'Yesterday' AS rangename,
                            TO_NUMBER('8') AS inde 
                        FROM 
                            DUAL
        
                        UNION ALL
        
                        SELECT  
                            TRUNC(SYSDATE - n) AS FDATE, 
                            TRUNC(SYSDATE - n) AS TDATE,
                            SUBSTR(TO_CHAR(TRUNC(SYSDATE - n), 'DAY'), 1, 3) || '-' || 
                            TO_CHAR(TRUNC(SYSDATE - n), 'MM') || '/' ||
                            TO_CHAR(TRUNC(SYSDATE - n), 'DD') AS sas,
                            TO_NUMBER('1200') AS rangename  
                        FROM 
                            (SELECT ROWNUM n FROM dual CONNECT BY LEVEL <= 7) 
                        WHERE 
                            n >= 1
                    ) b
                    ON a.sales_date BETWEEN b.startdate AND b.enddate    
                ) 
                GROUP BY 
                    startdate, 
                    rangename, 
                    inde 
                ORDER BY 
                    startdate";
                    }
                    else if (rep == "collection")
                    {
                        query = $@"
                    SELECT startdate, rangename, inde,
                    ISNULL(SUM(qty), 0), ISNULL(SUM(AMT), 0),
                     CASE WHEN RANGENAME = 'Today' THEN
                        SUM(ISNULL(AMT, 0))
                    ELSE
                        (SUM(ISNULL(AMT, 0)) / 
                        (CASE WHEN DATEDIFF(DAY, startdate, GETDATE()) = 0 THEN 1 ELSE DATEDIFF(DAY, startdate, GETDATE()) END))
                    END AS avg_perday
                    FROM
                    (
                        SELECT A.ORDER_DATE AS startdate, 
                               b.rangename, 
                               b.ind, 
                               SUM(NVL(qty, 0)) AS qty,
                               SUM(NVL(AMT, 0)) AS AMT 
                        FROM V$PRODUCTION_ORDER A 
                        INNER JOIN 
                        (
                            SELECT startdate, enddate, rangename, CAST('11' AS INT) AS inde 
                            FROM V_DATE_RANGE 
                            WHERE sortorder IN ('2')
                            UNION ALL 
                            SELECT CAST(CONCAT(SUBSTRING(CONVERT(VARCHAR, GETDATE(), 112), 1, 8), '01') AS DATE) AS FDATE,
                                   CAST(GETDATE() AS DATE) AS TDATE, 
                                   'This_Month' AS ra, 10 AS s 
                            FROM DUAL
                            UNION ALL
                            SELECT CAST(GETDATE() AS DATE) AS startdate, 
                                   CAST(GETDATE() AS DATE) AS enddate, 
                                   'Today' AS rangename, CAST('9' AS INT) AS inde  
                            FROM V_DATE_RANGE 
                            WHERE sortorder IN ('3') 
                            UNION ALL
                            SELECT CAST(DATEADD(DAY, -1, GETDATE()) AS DATE) AS FDATE, 
                                   CAST(DATEADD(DAY, -1, GETDATE()) AS DATE) AS TDATE, 
                                   'Yesterday' AS rangename, CAST('8' AS INT) AS inde  
                            FROM DUAL
                            UNION ALL
                            SELECT CAST(DATEADD(DAY, -n, GETDATE()) AS DATE) AS startdate, 
                                   CAST(DATEADD(DAY, -n, GETDATE()) AS DATE) AS enddate, 
                                   CONCAT(LEFT(DATENAME(WEEKDAY, DATEADD(DAY, -n, GETDATE())), 3), '-', 
                                   MONTH(DATEADD(DAY, -n, GETDATE())),'/', 
                                   DAY(DATEADD(DAY, -n, GETDATE()))) AS sas, 
                                   CAST('1200' AS INT) AS rangename  
                            FROM (SELECT ROW_NUMBER() OVER (ORDER BY (SELECT NULL)) n FROM master.dbo.spt_values) t 
                            WHERE n >= 1 AND n <= 7
                        ) b
                        ON A.ORDER_DATE BETWEEN b.startdate AND b.enddate
                        GROUP BY A.ORDER_DATE, b.rangename, b.ind
                    ) 
                    GROUP BY startdate, rangename, inde 
                    ORDER BY startdate";

                        query = $@"SELECT 
                            startdate,
                            rangename,
                            inde,
                            ROUND(SUM(AMT)) AS total_amt,
                            ROUND(SUM(AMT)) AS total_amt_duplicated,
                            ROUND(CASE 
                                WHEN RANGENAME = 'Today' THEN SUM(AMT)
                                ELSE (SUM(AMT) / 
                                      CASE 
                                          WHEN TRUNC(SYSDATE) - startdate = 0 THEN 1 
                                          ELSE TRUNC(SYSDATE) - startdate 
                                      END)
                            END) AS avg_perday
                        FROM (
                            SELECT * FROM (
                                SELECT 
                                    voucher_date, 
                                    NVL(SUM(NVL(CR_AMOUNT, 0) * NVL(EXCHANGE_RATE, 1)), 0) AS amt
                                FROM 
                                    V$VIRTUAL_SUB_LEDGER b
                                WHERE 
                                    (COMPANY_CODE, Voucher_NO) IN (
                                        SELECT 
                                            COMPANY_CODE, A.voucher_no
                                        FROM 
                                            V$VIRTUAL_GENERAL_LEDGER A
                                        WHERE 
                                            A.ACC_CODE IN (
                                                SELECT ACC_CODE 
                                                FROM FA_CHART_OF_ACCOUNTS_SETUP 
                                                WHERE ACC_NATURE IN ('AB', 'AC', 'LC') 
                                                  AND COMPANY_CODE = A.COMPANY_CODE
                                            )
                                            AND A.TRANSACTION_TYPE = 'DR'
                                            AND A.COMPANY_CODE = '{model.CompanyCode}'
                                            AND A.DELETED_FLAG = 'N'
                                            AND A.Voucher_NO != '0'
                                    )
                                    AND SUBSTR(sub_code, 1, 1) = 'C'
                                    AND TRANSACTION_TYPE = 'CR'
                                GROUP BY 
                                    voucher_date
                            ) a
                            LEFT OUTER JOIN (
                                SELECT 
                                    startdate, 
                                    enddate, 
                                    rangename, 
                                    TO_NUMBER('11') AS inde 
                                FROM 
                                    V_DATE_RANGE 
                                WHERE 
                                    sortorder IN ('2')

                                UNION ALL 

                                SELECT 
                                    TRUNC(TO_DATE(SUBSTR(TO_CHAR(SYSDATE, 'YYYY-MM-DD'), 1, 8) || '01', 'YYYY-MM-DD')) AS startdate, 
                                    TRUNC(SYSDATE) AS enddate, 
                                    'This_Month' AS rangename, 
                                    10 AS inde 
                                FROM 
                                    DUAL

                                UNION ALL

                                SELECT  
                                    TRUNC(SYSDATE) AS startdate, 
                                    TRUNC(SYSDATE) AS enddate, 
                                    'Today' AS rangename, 
                                    TO_NUMBER('9') AS inde  
                                FROM 
                                    V_DATE_RANGE 
                                WHERE 
                                    sortorder IN ('3')

                                UNION ALL

                                SELECT  
                                    TRUNC(SYSDATE - 1) AS startdate, 
                                    TRUNC(SYSDATE - 1) AS enddate, 
                                    'Yesterday' AS rangename, 
                                    TO_NUMBER('8') AS inde 
                                FROM 
                                    DUAL

                                UNION ALL

                                SELECT  
                                    TRUNC(SYSDATE - n) AS startdate, 
                                    TRUNC(SYSDATE - n) AS enddate, 
                                    SUBSTR(TO_CHAR(TRUNC(SYSDATE - n), 'DAY'), 1, 3) || '-' || 
                                    EXTRACT(MONTH FROM TRUNC(SYSDATE - n)) || '/' || 
                                    EXTRACT(DAY FROM TRUNC(SYSDATE - n)) AS rangename, 
                                    TO_NUMBER('1200') AS inde  
                                FROM 
                                    (SELECT ROWNUM AS n FROM dual CONNECT BY LEVEL <= 7)
                                WHERE 
                                    n >= 1
                            ) b
                            ON a.voucher_date BETWEEN b.startdate AND b.enddate
                        )
                        GROUP BY 
                            startdate, 
                            rangename, 
                            inde 
                        ORDER BY 
                            startdate";
                    }
                    else if (rep == "production")
                    {
                        query = $@"
                    SELECT 
                        startdate,
                        rangename,
                        inde,
                        ROUND(NVL(SUM(qty), 0)) AS total_qty,
                        ROUND(NVL(SUM(AMT), 0)) AS total_amt,
                        ROUND(CASE 
                            WHEN RANGENAME = 'Today' THEN SUM(NVL(AMT, 0))
                            ELSE (SUM(NVL(AMT, 0)) / 
                                  CASE 
                                      WHEN TRUNC(SYSDATE) - startdate = 0 THEN 1 
                                      ELSE TRUNC(SYSDATE) - startdate 
                                  END)
                        END) AS avg_perday
                    FROM (
                        SELECT * FROM (
                            -- Main query to calculate quantity and amount grouped by mrr_date
                            SELECT 
                                mrr_date, 
                                SUM(quantity) AS qty, 
                                SUM(total_price) AS amt 
                            FROM 
                                IP_PRODUCTION_MRR 
                            WHERE 
                                deleted_flag = 'N' 
                                AND COMPANY_CODE IN ('{model.CompanyCode}') 
                            GROUP BY 
                                mrr_date
                        ) a
                        LEFT OUTER JOIN (
                            -- Date range subquery to get different ranges like Today, Yesterday, etc.
                            SELECT 
                                startdate, 
                                enddate, 
                                rangename, 
                                TO_NUMBER('11') AS inde 
                            FROM 
                                V_DATE_RANGE 
                            WHERE 
                                sortorder IN ('2')

                            UNION ALL 

                            SELECT 
                                TRUNC(TO_DATE(SUBSTR(TO_CHAR(SYSDATE, 'YYYY-MM-DD'), 1, 8) || '01', 'YYYY-MM-DD')) AS startdate, 
                                TRUNC(SYSDATE) AS enddate, 
                                'This_Month' AS rangename, 
                                10 AS inde 
                            FROM 
                                DUAL

                            UNION ALL 

                            SELECT 
                                TRUNC(SYSDATE) AS startdate, 
                                TRUNC(SYSDATE) AS enddate, 
                                'Today' AS rangename, 
                                TO_NUMBER('9') AS inde  
                            FROM 
                                V_DATE_RANGE 
                            WHERE 
                                sortorder IN ('3')

                            UNION ALL 

                            SELECT  
                                TRUNC(SYSDATE - 1) AS startdate, 
                                TRUNC(SYSDATE - 1) AS enddate, 
                                'Yesterday' AS rangename, 
                                TO_NUMBER('8') AS inde  
                            FROM 
                                DUAL

                            UNION ALL 

                            -- Generating previous 7 days dynamically
                            SELECT  
                                TRUNC(SYSDATE - n) AS startdate, 
                                TRUNC(SYSDATE - n) AS enddate, 
                                SUBSTR(TO_CHAR(TRUNC(SYSDATE - n), 'DAY'), 1, 3) || '-' || 
                                EXTRACT(MONTH FROM TRUNC(SYSDATE - n)) || '/' || 
                                EXTRACT(DAY FROM TRUNC(SYSDATE - n)) AS rangename, 
                                TO_NUMBER('1200') AS inde  
                            FROM 
                                (SELECT ROWNUM AS n FROM dual CONNECT BY LEVEL <= 7)
                            WHERE 
                                n >= 1
                        ) b
                        ON a.mrr_date BETWEEN b.startdate AND b.enddate
                    )
                    GROUP BY 
                        startdate, 
                        rangename, 
                        inde 
                    ORDER BY 
                        startdate";
                    }
                    else if (rep == "purchase")
                    {
                        query = $@"
                    SELECT 
                        startdate,
                        rangename,
                        inde,
                        ROUND(SUM(sales_qty - sales_ret_qty)) AS net_sales_qty,
                        ROUND(SUM(sales_value - sales_ret_value)) AS net_sales_value,
                        ROUND(CASE 
                            WHEN rangename = 'Today' THEN SUM(sales_value - sales_ret_value)
                            ELSE 
                                (SUM(sales_value - sales_ret_value) / 
                                CASE 
                                    WHEN TRUNC(SYSDATE) - startdate = 0 THEN 1 
                                    ELSE TRUNC(SYSDATE) - startdate 
                                END)
                        END) AS avg_perday
                    FROM (
                        SELECT * FROM (
                            -- Sales Invoice Subquery
                            SELECT 
                                A.COMPANY_CODE, 
                                A.BRANCH_CODE, 
                                A.invoice_date AS sales_date,
                                SUM(NVL(A.ROLL_QTY, 0)) AS sales_roll_qty, 
                                SUM(NVL(A.QUANTITY, 0)) AS sales_qty, 
                                SUM(NVL(A.QUANTITY * A.NET_GROSS_RATE, 0)) AS sales_value,
                                0 AS sales_ret_roll_qty, 
                                0 AS sales_ret_qty, 
                                0 AS sales_ret_value  
                            FROM 
                                ip_purchase_invoice A 
                            WHERE 
                                A.DELETED_FLAG = 'N' 
                                AND A.COMPANY_CODE IN ('{model.CompanyCode}')
                            GROUP BY 
                                A.COMPANY_CODE, A.BRANCH_CODE, A.invoice_date
        
                            UNION ALL
        
                            -- Sales Return Subquery
                            SELECT 
                                A.COMPANY_CODE, 
                                A.BRANCH_CODE, 
                                A.return_date AS sales_date,
                                0 AS sales_roll_qty, 
                                0 AS sales_qty, 
                                0 AS sales_value,
                                SUM(NVL(A.ROLL_QTY, 0)) AS sales_ret_roll_qty, 
                                SUM(NVL(A.QUANTITY, 0)) AS sales_ret_qty,
                                SUM(NVL(A.QUANTITY * A.NET_GROSS_RATE, 0)) AS sales_ret_value 
                            FROM 
                                ip_purchase_return A
                            WHERE 
                                A.DELETED_FLAG = 'N'
                                AND A.COMPANY_CODE IN ('{model.CompanyCode}')
                            GROUP BY 
                                A.COMPANY_CODE, A.BRANCH_CODE, A.return_date
                        ) a
                        LEFT OUTER JOIN (
                            -- Date Range Subquery
                            SELECT 
                                startdate, 
                                enddate, 
                                rangename, 
                                TO_NUMBER('11') AS inde 
                            FROM 
                                V_DATE_RANGE 
                            WHERE 
                                sortorder IN ('2')

                            UNION ALL

                            -- 'This Month' Date Range
                            SELECT 
                                TRUNC(TO_DATE(SUBSTR(TO_CHAR(SYSDATE, 'YYYY-MM-DD'), 1, 8) || '01', 'YYYY-MM-DD')) AS startdate, 
                                TRUNC(SYSDATE) AS enddate, 
                                'This_Month' AS rangename, 
                                10 AS inde 
                            FROM 
                                DUAL

                            UNION ALL

                            -- 'Today' Date Range
                            SELECT 
                                TRUNC(SYSDATE) AS startdate, 
                                TRUNC(SYSDATE) AS enddate, 
                                'Today' AS rangename, 
                                TO_NUMBER('9') AS inde 
                            FROM 
                                V_DATE_RANGE 
                            WHERE 
                                sortorder IN ('3')

                            UNION ALL

                            -- 'Yesterday' Date Range
                            SELECT  
                                TRUNC(SYSDATE - 1) AS startdate, 
                                TRUNC(SYSDATE - 1) AS enddate, 
                                'Yesterday' AS rangename, 
                                TO_NUMBER('8') AS inde 
                            FROM 
                                DUAL

                            UNION ALL

                            -- Last 7 Days
                            SELECT  
                                TRUNC(SYSDATE - n) AS startdate, 
                                TRUNC(SYSDATE - n) AS enddate, 
                                SUBSTR(TO_CHAR(TRUNC(SYSDATE - n), 'DAY'), 1, 3) || '-' || 
                                EXTRACT(MONTH FROM TRUNC(SYSDATE - n)) || '/' || 
                                EXTRACT(DAY FROM TRUNC(SYSDATE - n)) AS rangename, 
                                TO_NUMBER('1200') AS inde 
                            FROM 
                                (SELECT ROWNUM AS n FROM DUAL CONNECT BY LEVEL <= 7)
                            WHERE 
                                n >= 1
                        ) b
                        ON a.sales_date BETWEEN b.startdate AND b.enddate
                    )
                    GROUP BY 
                        startdate, 
                        rangename, 
                        inde
                    ORDER BY 
                        startdate";
                    }
                    else if (rep == "payment")
                    {
                        query = $@"
                    SELECT 
                        startdate,
                        rangename,
                        inde,
                        ROUND(SUM(AMT)) AS total_amt,
                        ROUND(SUM(AMT)) AS total_amt_copy,
                        ROUND(CASE 
                            WHEN RANGENAME = 'Today' THEN SUM(AMT)
                            ELSE 
                                (SUM(AMT) / 
                                 CASE 
                                     WHEN TRUNC(SYSDATE) - startdate = 0 THEN 1 
                                     ELSE TRUNC(SYSDATE) - startdate 
                                 END
                                )
                        END) AS avg_perday
                    FROM (
                        SELECT * FROM (
                            -- Main subquery to calculate amounts grouped by voucher_date
                            SELECT 
                                voucher_date,
                                NVL(SUM(NVL(DR_AMOUNT, 0) * NVL(EXCHANGE_RATE, 1)), 0) AS amt 
                            FROM 
                                V$VIRTUAL_SUB_LEDGER 
                            WHERE 
                                DELETED_FLAG = 'N' 
                                AND COMPANY_CODE = '{model.CompanyCode}' 
                                AND DR_AMOUNT > 0
                                AND SUBSTR(sub_code, 1, 1) = 'S' 
                                AND VOUCHER_DATE IS NOT NULL 
                            GROUP BY 
                                voucher_date
                        ) a
                        LEFT OUTER JOIN (
                            -- Date range subquery to get date ranges like 'Today', 'Yesterday', 'This Month', etc.
                            SELECT 
                                startdate, 
                                enddate, 
                                rangename, 
                                TO_NUMBER('11') AS inde 
                            FROM 
                                V_DATE_RANGE 
                            WHERE 
                                sortorder IN ('2')

                            UNION ALL 

                            -- 'This Month' date range
                            SELECT 
                                TRUNC(TO_DATE(SUBSTR(TO_CHAR(SYSDATE, 'YYYY-MM-DD'), 1, 8) || '01', 'YYYY-MM-DD')) AS startdate, 
                                TRUNC(SYSDATE) AS enddate, 
                                'This_Month' AS rangename, 
                                10 AS inde 
                            FROM 
                                DUAL

                            UNION ALL 

                            -- 'Today' date range
                            SELECT 
                                TRUNC(SYSDATE) AS startdate, 
                                TRUNC(SYSDATE) AS enddate, 
                                'Today' AS rangename, 
                                TO_NUMBER('9') AS inde 
                            FROM 
                                V_DATE_RANGE 
                            WHERE 
                                sortorder IN ('3')

                            UNION ALL 

                            -- 'Yesterday' date range
                            SELECT  
                                TRUNC(SYSDATE - 1) AS startdate, 
                                TRUNC(SYSDATE - 1) AS enddate, 
                                'Yesterday' AS rangename, 
                                TO_NUMBER('8') AS inde 
                            FROM 
                                DUAL

                            UNION ALL 

                            -- Last 7 days
                            SELECT  
                                TRUNC(SYSDATE - n) AS startdate, 
                                TRUNC(SYSDATE - n) AS enddate, 
                                SUBSTR(TO_CHAR(TRUNC(SYSDATE - n), 'DAY'), 1, 3) || '-' || 
                                EXTRACT(MONTH FROM TRUNC(SYSDATE - n)) || '/' || 
                                EXTRACT(DAY FROM TRUNC(SYSDATE - n)) AS rangename, 
                                TO_NUMBER('1200') AS inde 
                            FROM 
                                (SELECT ROWNUM AS n FROM dual CONNECT BY LEVEL <= 7)
                            WHERE 
                                n >= 1
                        ) b
                        ON a.voucher_date BETWEEN b.startdate AND b.enddate
                    )
                    GROUP BY 
                        startdate, 
                        rangename, 
                        inde 
                    ORDER BY 
                        startdate";
                    }

                    // Execute the query and get the results
                    using (OracleConnection conn = new OracleConnection(_connection))
                    {
                        try
                        {
                            conn.Open();
                            using (OracleCommand cmd = new OracleCommand(query, conn))
                            {
                                cmd.CommandType = CommandType.Text;
                                cmd.CommandTimeout = 500;
                                using (OracleDataReader reader = cmd.ExecuteReader())
                                {
                                    while (reader.Read())
                                    {
                                        var rangename = reader["rangename"].ToString();
                                        results[$"{rep}_{rangename}"] = new
                                        {
                                            TotalQty = reader.GetDecimal(3),
                                            TotalAmt = reader.GetDecimal(4),
                                            AvgPerDay = reader.GetDecimal(5)
                                        };
                                    }
                                }
                            }
                        }
                        catch (Exception ex)
                        {

                        }
                    }
                }
            }
            return Ok(results);
        }

        [HttpPost]
        [Route("SalesYTDMTD")]
        public async Task<IHttpActionResult> SalesYTDMTD([FromBody] OverviewRequestModel model)
        {
            var branchCode = new List<string>();
            var results = new Dictionary<string, object>();
            var allReps = new List<string> { "sales" };

            foreach (var rep in allReps)
            {
                string query = string.Empty;

                if (rep == "sales")
                {
                    query = $@"
                    SELECT 
                    startdate,
                    rangename,
                    inde,
                    SUM(sales_qty - sales_ret_qty) AS total_sales_qty,
                    SUM(sales_value - sales_ret_value) AS total_sales_value,
                   CASE 
                    WHEN RANGENAME = 'Today' THEN 
                        ROUND(SUM(sales_value - sales_ret_value), 2)
                    ELSE 
                        ROUND(SUM(sales_value - sales_ret_value) / 
                            CASE 
                                WHEN TRUNC(SYSDATE) - startdate = 0 THEN 1 
                                ELSE TRUNC(SYSDATE) - startdate 
                            END, 2)
                END AS avg_perday
                FROM (
                    SELECT * FROM (
                        SELECT 
                            A.COMPANY_CODE,
                            A.BRANCH_CODE,
                            A.sales_date,
                            SUM(NVL(A.ROLL_QTY, 0)) AS SALES_ROLL_QTY,
                            SUM(NVL(A.QUANTITY, 0)) AS SALES_QTY,
                            SUM(NVL(A.QUANTITY * A.NET_GROSS_RATE, 0)) AS SALES_VALUE,
                            0 AS SALES_RET_ROLL_QTY,
                            0 AS SALES_RET_QTY,
                            0 AS SALES_RET_VALUE
                        FROM 
                            SA_SALES_INVOICE A
                        WHERE 
                            A.DELETED_FLAG = 'N'
                            AND A.COMPANY_CODE IN ('{model.CompanyCode}')                                                             
                        GROUP BY  
                            A.COMPANY_CODE, 
                            A.BRANCH_CODE, 
                            A.sales_date
        
                        UNION ALL
        
                        SELECT 
                            A.COMPANY_CODE, 
                            A.BRANCH_CODE, 
                            A.return_date,
                            0 AS SALES_ROLL_QTY, 
                            0 AS SALES_QTY, 
                            0 AS SALES_VALUE,
                            SUM(NVL(A.ROLL_QTY, 0)) AS SALES_RET_ROLL_QTY, 
                            SUM(NVL(A.QUANTITY, 0)) AS SALES_RET_QTY,
                            SUM(NVL(A.QUANTITY * A.NET_GROSS_RATE, 0)) AS SALES_RET_VALUE  
                        FROM 
                            SA_SALES_RETURN A
                        WHERE 
                            A.DELETED_FLAG = 'N'
                            AND A.COMPANY_CODE IN ('{model.CompanyCode}')                                 
                        GROUP BY  
                            A.COMPANY_CODE, 
                            A.BRANCH_CODE,  
                            A.return_date 
                        ORDER BY 
                            sales_date 
                    ) a
                    LEFT OUTER JOIN (
                        SELECT 
                            startdate,
                            enddate,
                            rangename,
                            TO_NUMBER('11') AS inde 
                        FROM 
                            V_DATE_RANGE 
                        WHERE 
                            sortorder IN ('2')
        
                        UNION ALL
        
                        SELECT 
                            TRUNC(TO_DATE(SUBSTR(TO_CHAR(SYSDATE, 'YYYY-MM-DD'), 1, 8) || '01', 'YYYY-MM-DD')) AS FDATE, 
                            TRUNC(SYSDATE) AS TDATE, 
                            'This_Month' AS ra,
                            10 AS s 
                        FROM 
                            DUAL                             
       
                        UNION ALL
        
                        SELECT  
                            TRUNC(SYSDATE) AS FDATE, 
                            TRUNC(SYSDATE) AS TDATE,
                            'Today' AS rangename,
                            TO_NUMBER('9') AS inde  
                        FROM 
                            V_DATE_RANGE 
                        WHERE 
                            sortorder IN ('3') 
        
                        UNION ALL
        
                        SELECT  
                            TRUNC(SYSDATE) - 1 AS FDATE, 
                            TRUNC(SYSDATE) - 1 AS TDATE,
                            'Yesterday' AS rangename,
                            TO_NUMBER('8') AS inde 
                        FROM 
                            DUAL
        
                        UNION ALL
        
                        SELECT  
                            TRUNC(SYSDATE - n) AS FDATE, 
                            TRUNC(SYSDATE - n) AS TDATE,
                            SUBSTR(TO_CHAR(TRUNC(SYSDATE - n), 'DAY'), 1, 3) || '-' || 
                            TO_CHAR(TRUNC(SYSDATE - n), 'MM') || '/' ||
                            TO_CHAR(TRUNC(SYSDATE - n), 'DD') AS sas,
                            TO_NUMBER('1200') AS rangename  
                        FROM 
                            (SELECT ROWNUM n FROM dual CONNECT BY LEVEL <= 7) 
                        WHERE 
                            n >= 1
                    ) b
                    ON a.sales_date BETWEEN b.startdate AND b.enddate    
                ) 
                GROUP BY 
                    startdate, 
                    rangename, 
                    inde 
                ORDER BY 
                    startdate";
                }
                // Execute the query and get the results
                using (OracleConnection conn = new OracleConnection(_connection))
                {
                    try
                    {
                        conn.Open();
                        using (OracleCommand cmd = new OracleCommand(query, conn))
                        {
                            cmd.CommandType = CommandType.Text;
                            cmd.CommandTimeout = 500;
                            using (OracleDataReader reader = cmd.ExecuteReader())
                            {
                                while (reader.Read())
                                {
                                    var rangename = reader["rangename"].ToString();
                                    results[$"{rep}_{rangename}"] = new
                                    {
                                        TotalQty = reader.GetDecimal(3),
                                        TotalAmt = reader.GetDecimal(4),
                                        AvgPerDay = reader.GetDecimal(5)
                                    };
                                }
                            }
                        }
                    }
                    catch (Exception ex)
                    {

                    }
                }
            }
            return Ok(results);
        }

        [HttpPost]
        [Route("CollectionYTDMTD")]
        public async Task<IHttpActionResult> CollectionYTDMTD([FromBody] OverviewRequestModel model)
        {
            var branchCode = new List<string>();
            var results = new Dictionary<string, object>();
            var allReps = new List<string> { "collection" };

            foreach (var rep in allReps)
            {
                string query = string.Empty;

                if (rep == "collection")
                {
                    query = $@"
                    SELECT startdate, rangename, inde,
                    ISNULL(SUM(qty), 0), ISNULL(SUM(AMT), 0),
                     CASE WHEN RANGENAME = 'Today' THEN
                        SUM(ISNULL(AMT, 0))
                    ELSE
                        (SUM(ISNULL(AMT, 0)) / 
                        (CASE WHEN DATEDIFF(DAY, startdate, GETDATE()) = 0 THEN 1 ELSE DATEDIFF(DAY, startdate, GETDATE()) END))
                    END AS avg_perday
                    FROM
                    (
                        SELECT A.ORDER_DATE AS startdate, 
                               b.rangename, 
                               b.ind, 
                               SUM(NVL(qty, 0)) AS qty,
                               SUM(NVL(AMT, 0)) AS AMT 
                        FROM V$PRODUCTION_ORDER A 
                        INNER JOIN 
                        (
                            SELECT startdate, enddate, rangename, CAST('11' AS INT) AS inde 
                            FROM V_DATE_RANGE 
                            WHERE sortorder IN ('2')
                            UNION ALL 
                            SELECT CAST(CONCAT(SUBSTRING(CONVERT(VARCHAR, GETDATE(), 112), 1, 8), '01') AS DATE) AS FDATE,
                                   CAST(GETDATE() AS DATE) AS TDATE, 
                                   'This_Month' AS ra, 10 AS s 
                            FROM DUAL
                            UNION ALL
                            SELECT CAST(GETDATE() AS DATE) AS startdate, 
                                   CAST(GETDATE() AS DATE) AS enddate, 
                                   'Today' AS rangename, CAST('9' AS INT) AS inde  
                            FROM V_DATE_RANGE 
                            WHERE sortorder IN ('3') 
                            UNION ALL
                            SELECT CAST(DATEADD(DAY, -1, GETDATE()) AS DATE) AS FDATE, 
                                   CAST(DATEADD(DAY, -1, GETDATE()) AS DATE) AS TDATE, 
                                   'Yesterday' AS rangename, CAST('8' AS INT) AS inde  
                            FROM DUAL
                            UNION ALL
                            SELECT CAST(DATEADD(DAY, -n, GETDATE()) AS DATE) AS startdate, 
                                   CAST(DATEADD(DAY, -n, GETDATE()) AS DATE) AS enddate, 
                                   CONCAT(LEFT(DATENAME(WEEKDAY, DATEADD(DAY, -n, GETDATE())), 3), '-', 
                                   MONTH(DATEADD(DAY, -n, GETDATE())),'/', 
                                   DAY(DATEADD(DAY, -n, GETDATE()))) AS sas, 
                                   CAST('1200' AS INT) AS rangename  
                            FROM (SELECT ROW_NUMBER() OVER (ORDER BY (SELECT NULL)) n FROM master.dbo.spt_values) t 
                            WHERE n >= 1 AND n <= 7
                        ) b
                        ON A.ORDER_DATE BETWEEN b.startdate AND b.enddate
                        GROUP BY A.ORDER_DATE, b.rangename, b.ind
                    ) 
                    GROUP BY startdate, rangename, inde 
                    ORDER BY startdate";

                    query = $@"SELECT 
                            startdate,
                            rangename,
                            inde,
                            SUM(AMT) AS total_amt,
                            SUM(AMT) AS total_amt_duplicated,
                            CASE 
                                WHEN RANGENAME = 'Today' THEN SUM(AMT)
                                ELSE (SUM(AMT) / 
                                      CASE 
                                          WHEN TRUNC(SYSDATE) - startdate = 0 THEN 1 
                                          ELSE TRUNC(SYSDATE) - startdate 
                                      END)
                            END AS avg_perday
                        FROM (
                            SELECT * FROM (
                                SELECT 
                                    voucher_date, 
                                    NVL(SUM(NVL(CR_AMOUNT, 0) * NVL(EXCHANGE_RATE, 1)), 0) AS amt
                                FROM 
                                    V$VIRTUAL_SUB_LEDGER b
                                WHERE 
                                    (COMPANY_CODE, Voucher_NO) IN (
                                        SELECT 
                                            COMPANY_CODE, A.voucher_no
                                        FROM 
                                            V$VIRTUAL_GENERAL_LEDGER A
                                        WHERE 
                                            A.ACC_CODE IN (
                                                SELECT ACC_CODE 
                                                FROM FA_CHART_OF_ACCOUNTS_SETUP 
                                                WHERE ACC_NATURE IN ('AB', 'AC', 'LC') 
                                                  AND COMPANY_CODE = A.COMPANY_CODE
                                            )
                                            AND A.TRANSACTION_TYPE = 'DR'
                                            AND A.COMPANY_CODE = '{model.CompanyCode}'
                                            AND A.DELETED_FLAG = 'N'
                                            AND A.Voucher_NO != '0'
                                    )
                                    AND SUBSTR(sub_code, 1, 1) = 'C'
                                    AND TRANSACTION_TYPE = 'CR'
                                GROUP BY 
                                    voucher_date
                            ) a
                            LEFT OUTER JOIN (
                                SELECT 
                                    startdate, 
                                    enddate, 
                                    rangename, 
                                    TO_NUMBER('11') AS inde 
                                FROM 
                                    V_DATE_RANGE 
                                WHERE 
                                    sortorder IN ('2')

                                UNION ALL 

                                SELECT 
                                    TRUNC(TO_DATE(SUBSTR(TO_CHAR(SYSDATE, 'YYYY-MM-DD'), 1, 8) || '01', 'YYYY-MM-DD')) AS startdate, 
                                    TRUNC(SYSDATE) AS enddate, 
                                    'This_Month' AS rangename, 
                                    10 AS inde 
                                FROM 
                                    DUAL

                                UNION ALL

                                SELECT  
                                    TRUNC(SYSDATE) AS startdate, 
                                    TRUNC(SYSDATE) AS enddate, 
                                    'Today' AS rangename, 
                                    TO_NUMBER('9') AS inde  
                                FROM 
                                    V_DATE_RANGE 
                                WHERE 
                                    sortorder IN ('3')

                                UNION ALL

                                SELECT  
                                    TRUNC(SYSDATE - 1) AS startdate, 
                                    TRUNC(SYSDATE - 1) AS enddate, 
                                    'Yesterday' AS rangename, 
                                    TO_NUMBER('8') AS inde 
                                FROM 
                                    DUAL

                                UNION ALL

                                SELECT  
                                    TRUNC(SYSDATE - n) AS startdate, 
                                    TRUNC(SYSDATE - n) AS enddate, 
                                    SUBSTR(TO_CHAR(TRUNC(SYSDATE - n), 'DAY'), 1, 3) || '-' || 
                                    EXTRACT(MONTH FROM TRUNC(SYSDATE - n)) || '/' || 
                                    EXTRACT(DAY FROM TRUNC(SYSDATE - n)) AS rangename, 
                                    TO_NUMBER('1200') AS inde  
                                FROM 
                                    (SELECT ROWNUM AS n FROM dual CONNECT BY LEVEL <= 7)
                                WHERE 
                                    n >= 1
                            ) b
                            ON a.voucher_date BETWEEN b.startdate AND b.enddate
                        )
                        GROUP BY 
                            startdate, 
                            rangename, 
                            inde 
                        ORDER BY 
                            startdate";
                }
                else if (rep == "Production")
                {
                    query = $@"
                    SELECT 
                        startdate,
                        rangename,
                        inde,
                        NVL(SUM(qty), 0) AS total_qty,
                        NVL(SUM(AMT), 0) AS total_amt,
                        CASE 
                            WHEN RANGENAME = 'Today' THEN SUM(NVL(AMT, 0))
                            ELSE (SUM(NVL(AMT, 0)) / 
                                  CASE 
                                      WHEN TRUNC(SYSDATE) - startdate = 0 THEN 1 
                                      ELSE TRUNC(SYSDATE) - startdate 
                                  END)
                        END AS avg_perday
                    FROM (
                        SELECT * FROM (
                            -- Main query to calculate quantity and amount grouped by mrr_date
                            SELECT 
                                mrr_date, 
                                SUM(quantity) AS qty, 
                                SUM(total_price) AS amt 
                            FROM 
                                IP_PRODUCTION_MRR 
                            WHERE 
                                deleted_flag = 'N' 
                                AND COMPANY_CODE IN ('{model.CompanyCode}') 
                            GROUP BY 
                                mrr_date
                        ) a
                        LEFT OUTER JOIN (
                            -- Date range subquery to get different ranges like Today, Yesterday, etc.
                            SELECT 
                                startdate, 
                                enddate, 
                                rangename, 
                                TO_NUMBER('11') AS inde 
                            FROM 
                                V_DATE_RANGE 
                            WHERE 
                                sortorder IN ('2')

                            UNION ALL 

                            SELECT 
                                TRUNC(TO_DATE(SUBSTR(TO_CHAR(SYSDATE, 'YYYY-MM-DD'), 1, 8) || '01', 'YYYY-MM-DD')) AS startdate, 
                                TRUNC(SYSDATE) AS enddate, 
                                'This_Month' AS rangename, 
                                10 AS inde 
                            FROM 
                                DUAL

                            UNION ALL 

                            SELECT 
                                TRUNC(SYSDATE) AS startdate, 
                                TRUNC(SYSDATE) AS enddate, 
                                'Today' AS rangename, 
                                TO_NUMBER('9') AS inde  
                            FROM 
                                V_DATE_RANGE 
                            WHERE 
                                sortorder IN ('3')

                            UNION ALL 

                            SELECT  
                                TRUNC(SYSDATE - 1) AS startdate, 
                                TRUNC(SYSDATE - 1) AS enddate, 
                                'Yesterday' AS rangename, 
                                TO_NUMBER('8') AS inde  
                            FROM 
                                DUAL

                            UNION ALL 

                            -- Generating previous 7 days dynamically
                            SELECT  
                                TRUNC(SYSDATE - n) AS startdate, 
                                TRUNC(SYSDATE - n) AS enddate, 
                                SUBSTR(TO_CHAR(TRUNC(SYSDATE - n), 'DAY'), 1, 3) || '-' || 
                                EXTRACT(MONTH FROM TRUNC(SYSDATE - n)) || '/' || 
                                EXTRACT(DAY FROM TRUNC(SYSDATE - n)) AS rangename, 
                                TO_NUMBER('1200') AS inde  
                            FROM 
                                (SELECT ROWNUM AS n FROM dual CONNECT BY LEVEL <= 7)
                            WHERE 
                                n >= 1
                        ) b
                        ON a.mrr_date BETWEEN b.startdate AND b.enddate
                    )
                    GROUP BY 
                        startdate, 
                        rangename, 
                        inde 
                    ORDER BY 
                        startdate";
                }
                // Execute the query and get the results
                using (OracleConnection conn = new OracleConnection(_connection))
                {
                    try
                    {
                        conn.Open();
                        using (OracleCommand cmd = new OracleCommand(query, conn))
                        {
                            cmd.CommandType = CommandType.Text;
                            cmd.CommandTimeout = 500;
                            using (OracleDataReader reader = cmd.ExecuteReader())
                            {
                                while (reader.Read())
                                {
                                    var rangename = reader["rangename"].ToString();
                                    results[$"{rep}_{rangename}"] = new
                                    {
                                        TotalQty = reader.GetDecimal(3),
                                        TotalAmt = reader.GetDecimal(4),
                                        AvgPerDay = reader.GetDecimal(5)
                                    };
                                }
                            }
                        }
                    }
                    catch (Exception ex)
                    {

                    }
                }
            }
            return Ok(results);
        }

