                                SUM(A.SALES_RET_QTY) SALES_RET_QTY, SUM(A.SALES_RET_VALUE) SALES_RET_VALUE, A.ITEM_CODE 
                                FROM (
                                    SELECT A.COMPANY_CODE, A.BRANCH_CODE, A.ITEM_CODE, 
                                    SUM(NVL(A.ROLL_QTY,0)) SALES_ROLL_QTY, SUM(NVL(A.QUANTITY,0)) SALES_QTY, 
