                                    SALES_QTY - SALES_RET_QTY AS NET_SALES_QTY,
                                    SALES_VALUE - SALES_RET_VALUE AS NET_SALES_VALUE 
                            FROM (
                                SELECT D.CUS_name, D.cod, 
                                        SUM(A.SALES_ROLL_QTY) AS SALES_ROLL_QTY, 
