                       NVL(sales_ret_roll_qty, 0) as sales_ret_roll_qty, NVL(sales_ret_qty, 0) as sales_ret_qty, NVL(sales_ret_value, 0) as sales_ret_value, NVL(net_sales_qty, 0) as net_sales_qty, NVL(net_sales_value, 0) as net_sales_value 
