            else if (repType == "customer_sales_vs_collection")
            {
                string qry = $@"
                        SELECT CUSTOMER_EDESC, ISNULL(NET_SALES_VALUE,0), ISNULL(COLLECTION,0), ISNULL(OPENING,0) FROM (
                            SELECT * FROM (
                                SELECT A.CUSTOMER_CODE, A.CUSTOMER_EDESC FROM SA_CUSTOMER_SETUP A 
                                WHERE A.COMPANY_CODE IN ({companyCode}) {customerStr}
                                GROUP BY A.CUSTOMER_CODE, A.CUSTOMER_EDESC
                            ) A
                            LEFT OUTER JOIN (
                                SELECT COD, NET_SALES_VALUE FROM (
                                    SELECT cus_name, Cod, SALES_ROLL_QTY, SALES_QTY, SALES_VALUE, SALES_RET_ROLL_QTY,
                                           SALES_RET_QTY, SALES_RET_VALUE, SALES_ROLL_QTY - SALES_RET_ROLL_QTY AS NET_ROLL_QTY,
                                           SALES_QTY - SALES_RET_QTY AS NET_SALES_QTY, SALES_VALUE - SALES_RET_VALUE AS NET_SALES_VALUE
                                    FROM (
                                        SELECT D.CUS_name, D.cod, SUM(A.SALES_ROLL_QTY) AS SALES_ROLL_QTY, SUM(A.SALES_QTY) AS SALES_QTY,
                                               SUM(A.SALES_VALUE) AS SALES_VALUE, SUM(SALES_RET_ROLL_QTY) AS SALES_RET_ROLL_QTY,
                                               SUM(A.SALES_RET_QTY) AS SALES_RET_QTY, SUM(A.SALES_RET_VALUE) AS SALES_RET_VALUE
                                        FROM (
                                            SELECT A.COMPANY_CODE, A.BRANCH_CODE, A.customer_code,
                                                   SUM(ISNULL(A.ROLL_QTY,0)) AS SALES_ROLL_QTY, SUM(ISNULL(A.QUANTITY,0)) AS SALES_QTY, 
                                                   SUM(ISNULL(A.QUANTITY*A.NET_GROSS_RATE,0)) AS SALES_VALUE,
                                                   0 AS SALES_RET_ROLL_QTY, 0 AS SALES_RET_QTY, 0 AS SALES_RET_VALUE
                                            FROM SA_SALES_INVOICE A
                                            WHERE A.DELETED_FLAG = 'N' AND A.COMPANY_CODE IN ({companyCode})
                                            {customerStr}
                                            AND A.BRANCH_CODE IN ({GetBranchFilter(companyCode, branchCode, this.UserId.ToString())})
                                            AND TRUNC(a.SALES_DATE) BETWEEN '{fromDate}' AND '{toDate}'
                                            GROUP BY A.COMPANY_CODE, A.BRANCH_CODE, A.customer_CODE
                                        ) A
                                        LEFT OUTER JOIN (
                                            SELECT customer_code AS cod, customer_edesc AS cus_name 
                                            FROM SA_CUSTOMER_SETUP WHERE COMPANY_CODE IN ({companyCode})
                                        ) D ON D.cod = A.CUSTOMER_CODE
                                        GROUP BY D.cod, D.cus_name
                                    ) ORDER BY cus_name
                                )
                            ) B ON A.customer_code = B.cod
                            LEFT OUTER JOIN (
                                SELECT sub_code, ISNULL(SUM(ISNULL(CR_AMOUNT,0) * ISNULL(EXCHANGE_RATE,1)),0) AS amt
                                FROM V$VIRTUAL_SUB_LEDGER
                                WHERE (COMPANY_CODE, Voucher_NO) IN (
                                    SELECT COMPANY_CODE, A.voucher_no FROM V$VIRTUAL_GENERAL_LEDGER A
                                    WHERE A.ACC_CODE IN (
                                        SELECT ACC_CODE FROM FA_CHART_OF_ACCOUNTS_SETUP
                                        WHERE ACC_NATURE IN ('AB','AC','LC') AND COMPANY_CODE = A.COMPANY_CODE
                                    )
                                    AND A.BRANCH_CODE IN ({GetBranchFilter(companyCode, branchCode, this.UserId.ToString())})
                                    AND A.TRANSACTION_TYPE = 'DR' AND A.COMPANY_CODE IN ({companyCode})
                                    AND A.DELETED_FLAG = 'N' AND TRUNC(VOUCHER_DATE) BETWEEN '{fromDate}' AND '{toDate}'
                                    AND A.Voucher_NO != '0'
                                )
                                AND SUBSTR(sub_code,1,1)='C' AND TRANSACTION_TYPE = 'CR'
                                GROUP BY sub_code
                            ) C ON 'C' + A.customer_code = C.sub_code
                            LEFT OUTER JOIN (
                                SELECT sub_code AS D_CODE, ISNULL(SUM(dr_amount) - SUM(cr_amount), 0) AS OPENING
                                FROM V$VIRTUAL_SUB_LEDGER
                                WHERE company_code IN ({companyCode}) AND deleted_flag='N'
                                AND (form_code ='0' OR voucher_date < '{fromDate}')
                                AND SUBSTR(sub_code,1,1)='C'
