                                    FROM SA_CUSTOMER_SETUP 
                                    WHERE 1=1 AND COMPANY_CODE IN ({companyCode}) 
                                    GROUP BY customer_code, customer_edesc
                                ) D ON D.cod = A.CUSTOMER_CODE                                                 
                                GROUP BY D.cod, D.cus_name                                                                            
                            ) 
