                        ) B ON A.customer_code = b.cod
                    )
                    LEFT OUTER JOIN 
                    (
                        SELECT sub_code, NVL(SUM(NVL(CR_AMOUNT, 0) * NVL(EXCHANGE_RATE, 1)), 0) collection
                        FROM V$VIRTUAL_SUB_LEDGER b
                        WHERE (COMPANY_CODE, Voucher_NO) IN
