                        )
                    ) c 
                    ON a.item_code = c.C_code
                    LEFT OUTER JOIN 
                    (
                        SELECT item_code d_code, yesterday s_yes, today s_tdy, this_month s_mtd, this_year s_ytd 
                        FROM 
                        (
                            SELECT *
                            FROM 
                            (
