                                    SELECT TRUNC(SYSDATE-1), TRUNC(SYSDATE-1), 'Yesterday', 21 FROM dual
                                ) a
                                LEFT OUTER JOIN 
                                (
                                    SELECT sales_date mrr_date, item_code, NVL(sales_qty,0)-NVL(sales_ret_qty,0) qty 
                                    FROM 
                                    (
                                        SELECT SALES_DATE, ITEM_CODE, SUM(NVL(QUANTITY,0)) SALES_QTY, 0 SALES_RET_QTY  
                                        FROM SA_SALES_INVOICE
                                        WHERE DELETED_FLAG = 'N'                                                 
                                        AND COMPANY_CODE IN {companyCodeStr}
                                        GROUP BY SALES_DATE, ITEM_CODE
                                        UNION ALL 
                                        SELECT RETURN_DATE, ITEM_CODE, 0 SALES_QTY, SUM(NVL(A.QUANTITY,0)) SALES_RET_QTY
                                        FROM SA_SALES_RETURN A
                                        WHERE DELETED_FLAG = 'N'
                                        AND COMPANY_CODE IN {companyCodeStr}
                                        GROUP BY RETURN_DATE, ITEM_CODE
                                    )
                                ) b 
                                ON b.mrr_date BETWEEN a.startdate AND a.enddate
                            ) 
                            PIVOT
                            (
                                SUM(qty) FOR rangename IN ('Yesterday' Yesterday, 'Today' Today, 'This Month' This_Month, 'This Year' This_Year)
                            )
                            WHERE item_code IS NOT NULL
                        )                            
                    ) d 
                    ON a.item_code = d.d_code
                    LEFT OUTER JOIN 
