                                    total6 += Convert.ToDouble(z[9] ?? 0);  // in_thisyear
                                    total7 += Convert.ToDouble(z[10] ?? 0); // out_today
                                    total8 += Convert.ToDouble(z[11] ?? 0); // out_yesterday
                                    total9 += Convert.ToDouble(z[12] ?? 0); // out_thismonth
                                    total10 += Convert.ToDouble(z[13] ?? 0); // out_thisyear
