                            q2 = Convert.ToDouble(i[6] ?? 0) * ratio; // SALES_RET_QTY
                            q3 = Convert.ToDouble(i[9] ?? 0) * ratio; // NET_SALES_QTY
                            unit = multiUnitD[itemCodeKey]["mu_code"];
                        }
                        else
                        {
                            unit = "N/A";
                            q1 = q2 = q3 = 0;
                        }
                    }
