                    asd.Add(aa);
                    arrTotal1.Add(Convert.ToDouble(i[3] ?? 0));  // SALES_QTY
                    arrTotal2.Add(Convert.ToDouble(i[4] ?? 0));  // SALES_VALUE
                    arrTotal4.Add(Convert.ToDouble(i[6] ?? 0));  // SALES_RET_QTY
                    arrTotal5.Add(Convert.ToDouble(i[7] ?? 0));  // SALES_RET_VALUE
                    arrTotal7.Add(Convert.ToDouble(i[9] ?? 0));  // NET_SALES_QTY
                    arrTotal8.Add(Convert.ToDouble(i[10] ?? 0)); // NET_SALES_VALUE
                }
                var PurInvResult = new Dictionary<string, object>
                {
                    {"product_wise_report", asd},
                    {"p_qty", arrTotal1.Sum()},
                    {"p_value", arrTotal2.Sum()},
                    {"p_ret_qty", arrTotal4.Sum()},
                    {"p_ret_val", arrTotal5.Sum()},
