                                       0 SALES_QTY, 
                                       0 SALES_VALUE, 
                                       SUM(NVL(ROLL_QTY,0)) SALES_RET_ROLL_QTY, 
                                       SUM(NVL(QUANTITY,0)) SALES_RET_QTY, 
                                       SUM(NVL(QUANTITY*CALC_UNIT_PRICE*EXCHANGE_RATE,0)) SALES_RET_VALUE  
                                FROM IP_PURCHASE_RETURN 
                                WHERE company_code IN {companyCodeStr} 
                                AND deleted_flag = 'N' 
                                {itemStringFilter} {brandStr} {catStr} {groupStr}
                                GROUP BY COMPANY_CODE, BRANCH_CODE, ITEM_CODE 
                                ORDER BY 1      
                            ) A     
                            GROUP BY A.ITEM_CODE  
