                            {
                                string asd = z[3]?.ToString() ?? "";
                                asd = asd.Length >= (i[3]?.ToString().Length ?? 0) ?
                                    asd.Substring(0, i[3]?.ToString().Length ?? 0) : asd;

                                if (i[3]?.ToString() == asd)
                                {
                                    addOn = true;
                                    total2 += Convert.ToDouble(z[5] ?? 0);  // SALES_QTY
                                    total3 += Convert.ToDouble(z[6] ?? 0);  // SALES_VALUE
                                    total4 += Convert.ToDouble(z[7] ?? 0);  // SALES_RET_QTY
                                    total5 += Convert.ToDouble(z[8] ?? 0);  // SALES_RET_VALUE
                                    total6 += Convert.ToDouble(z[9] ?? 0);  // NET_SALES_QTY
                                    total7 += Convert.ToDouble(z[10] ?? 0); // NET_SALES_VALUE
                                }
                                else if (addOn)
                                {
                                    break;
                                }
                            }
                        }
                        if (total2 != 0 || total3 != 0 || total4 != 0 || total5 != 0 || total6 != 0 || total7 != 0)
                        {
                            var cals = new Dictionary<string, object>
                            {
                                {"name", i[0]},
                                {"unit", i[1]?.ToString() ?? ""},
                                {"group_flag", i[2]},
                                {"level", i[3]?.ToString().Count(c => c == '.') ?? 0},
                                {"master", i[3]},
                                {"pre", i[4]},
                                {"p_qty", total2},
                                {"p_value", total3},
                                {"p_ret_qty", total4},
                                {"p_ret_value", total5},
                                {"p_net_qty", total6},
                                {"p_net_value", total7}
                            };
                            vals.Add(cals);
