                        arrTotal4.Add(Convert.ToDouble(i[7] ?? 0));  // SALES_RET_QTY
                        arrTotal5.Add(Convert.ToDouble(i[8] ?? 0));  // SALES_RET_VALUE
                        arrTotal6.Add(Convert.ToDouble(i[9] ?? 0));  // NET_SALES_QTY
                        arrTotal7.Add(Convert.ToDouble(i[10] ?? 0)); // NET_SALES_VALUE
                    }
                }
                var PurGrpResult = new Dictionary<string, object>
                {
                    {"product_wise_report", vals},
                    {"p_qty", arrTotal2.Sum()},
                    {"p_value", arrTotal3.Sum()},
                    {"p_ret_qty", arrTotal4.Sum()},
                    {"p_ret_value", arrTotal5.Sum()},
                    {"p_net_qty", arrTotal6.Sum()},
                    {"p_net_value", arrTotal7.Sum()}
                };
                return Ok(PurGrpResult);
            }
            else if(repType == "purSupp")
            {
                string companyCodeStr = $"({string.Join(",", companyCode.Select(c => $"'{c}'"))})";

                string brandStr = string.IsNullOrEmpty(brand) ? "" :
                    $@" and item_code in (select item_code from IP_ITEM_SPEC_SETUP where brand_name='{brand}' AND COMPANY_CODE in {companyCodeStr})";

                string catStr = string.IsNullOrEmpty(cat) ? "" :
                    $@" and item_code in (select item_code from IP_ITEM_MASTER_SETUP where category_code='{cat}' AND COMPANY_CODE in {companyCodeStr})";

                string groupStr = string.IsNullOrEmpty(group) ? "" :
                    $@" and item_code in (select item_code from ip_item_master_setup where master_item_code like '{group}%' AND COMPANY_CODE in {companyCodeStr})";

                string itemStringFilter = "";
                if (itemCode.Count == 0)
                {
                    itemStringFilter = "";
                }
                else if (itemCode.Count == 1)
                {
                    itemCode.Add("0");
                    itemStringFilter = $@" and item_code in ({string.Join(",", itemCode.Select(i => $"'{i}'"))})";
                }
                else if (itemCode.Count > 0)
                {
                    itemStringFilter = $@" and item_code in ({string.Join(",", itemCode.Select(i => $"'{i}'"))})";
                }
                string query = $@"
                SELECT supplier_edesc, sales_qty, sales_value, sales_ret_qty, sales_ret_value, net_sales_qty, net_sales_value 
                FROM 
                (
                    SELECT supplier_CODE, 
                           SALES_ROLL_QTY, 
                           SALES_QTY, SALES_VALUE, SALES_RET_ROLL_QTY,
                           SALES_RET_QTY, SALES_RET_VALUE, 
                           SALES_ROLL_QTY - SALES_RET_ROLL_QTY NET_ROLL_QTY,
                           SALES_QTY - SALES_RET_QTY NET_SALES_QTY, 
                           SALES_VALUE - SALES_RET_VALUE NET_SALES_VALUE
                    FROM ( 
                        SELECT A.supplier_code,  
                               SUM(A.SALES_ROLL_QTY) SALES_ROLL_QTY, 
                               SUM(A.SALES_QTY) SALES_QTY,  
                               SUM(A.SALES_VALUE) SALES_VALUE, 
                               SUM(SALES_RET_ROLL_QTY) SALES_RET_ROLL_QTY, 
                               SUM(A.SALES_RET_QTY) SALES_RET_QTY,
                               SUM(A.SALES_RET_VALUE) SALES_RET_VALUE 
                        FROM (
                            SELECT COMPANY_CODE, BRANCH_CODE, SUPPLIER_CODE, 
                                   SUM(NVL(ROLL_QTY,0)) SALES_ROLL_QTY, 
                                   SUM(NVL(QUANTITY,0)) SALES_QTY, 
                                   SUM(NVL(QUANTITY*CALC_UNIT_PRICE*EXCHANGE_RATE,0)) SALES_VALUE, 
                                   0 SALES_RET_ROLL_QTY, 
                                   0 SALES_RET_QTY, 
                                   0 SALES_RET_VALUE  
                            FROM IP_PURCHASE_INVOICE 
                            WHERE company_code IN {companyCodeStr} 
                            AND deleted_flag = 'N' 
                            {itemStringFilter} {brandStr} {catStr} {groupStr}
                            GROUP BY COMPANY_CODE, BRANCH_CODE, SUPPLIER_CODE 
                            UNION ALL 
                            SELECT COMPANY_CODE, BRANCH_CODE, SUPPLIER_CODE, 
                                   0 SALES_ROLL_QTY, 
                                   0 SALES_QTY, 
                                   0 SALES_VALUE, 
                                   SUM(NVL(ROLL_QTY,0)) SALES_RET_ROLL_QTY, 
                                   SUM(NVL(QUANTITY,0)) SALES_RET_QTY, 
                                   SUM(NVL(QUANTITY*CALC_UNIT_PRICE*EXCHANGE_RATE,0)) SALES_RET_VALUE  
                            FROM IP_PURCHASE_RETURN 
                            WHERE company_code IN {companyCodeStr} 
                            AND deleted_flag = 'N' 
                            {itemStringFilter} {brandStr} {catStr} {groupStr}
                            GROUP BY COMPANY_CODE, BRANCH_CODE, SUPPLIER_CODE 
                            ORDER BY 1      
                        ) A     
                        GROUP BY A.supplier_CODE  
                    )
                ) a
                LEFT OUTER JOIN
                (
                    SELECT supplier_code b_code, supplier_edesc 
                    FROM IP_supplier_setup 
                    WHERE company_code = '01' 
                    AND group_sku_flag = 'I'
                ) b
                ON a.supplier_code = b.b_code 
                ORDER BY 1";
                List<object[]> allCodes = new List<object[]>();
                OracleConnection connection = new OracleConnection(_connection);
                connection.Open();
                using (OracleCommand cmd = new OracleCommand(query, connection))
                {
