                    {

                    }
                }
                List<Dictionary<string, object>> asd = new List<Dictionary<string, object>>();
                List<double> arrTotal1 = new List<double>(); // sales_qty
                List<double> arrTotal2 = new List<double>(); // sales_value
                List<double> arrTotal4 = new List<double>(); // sales_ret_qty
                List<double> arrTotal5 = new List<double>(); // sales_ret_value
                List<double> arrTotal7 = new List<double>(); // net_sales_qty
                List<double> arrTotal8 = new List<double>(); // net_sales_value

