                        {"p_net_value", Convert.ToDouble(i[6] ?? 0)}
                    };
                    asd.Add(aa);
                    arrTotal1.Add(Convert.ToDouble(i[1] ?? 0)); // sales_qty
                    arrTotal2.Add(Convert.ToDouble(i[2] ?? 0)); // sales_value
                    arrTotal4.Add(Convert.ToDouble(i[3] ?? 0)); // sales_ret_qty
                    arrTotal5.Add(Convert.ToDouble(i[4] ?? 0)); // sales_ret_value
                    arrTotal7.Add(Convert.ToDouble(i[5] ?? 0)); // net_sales_qty
                    arrTotal8.Add(Convert.ToDouble(i[6] ?? 0)); // net_sales_value
                }
                var PurSupplierResult = new Dictionary<string, object>
                {
                    {"product_wise_report", asd},
                    {"p_qty", arrTotal1.Sum()},
                    {"p_value", arrTotal2.Sum()},
                    {"p_ret_qty", arrTotal4.Sum()},
                    {"p_ret_val", arrTotal5.Sum()},
                    {"p_net_qty", arrTotal7.Sum()},
                    {"p_net_value", arrTotal8.Sum()}
                };
                return Ok(PurSupplierResult);
            }
            else
            {
                return null;
            }
        }

        private Dictionary<string, Dictionary<string, string>> MultiQty(string unitType, List<string> companyCode)
        {
            string query;
            string companyCodeString = $"({string.Join(",", companyCode.Select(c => $"'{c}'"))})";
            if (unitType == "Second")
            {
                query = $@"
                SELECT item_code, mu_code, 
                       CASE WHEN conversion_factor = 0 THEN 0 
                            ELSE NVL(conversion_factor, 0) / NVL(fraction, 0) 
                       END ratio 
                FROM IP_ITEM_UNIT_SETUP
                WHERE serial_no = '1' 
                AND deleted_flag = 'N' 
                AND company_code IN {companyCodeString}";
            }
            else if (unitType == "Third")
            {
                query = $@"
                SELECT item_code, mu_code, 
                       CASE WHEN conversion_factor = 0 THEN 0 
                            ELSE NVL(conversion_factor, 0) / NVL(fraction, 0) 
                       END ratio 
                FROM IP_ITEM_UNIT_SETUP
                WHERE serial_no = '2' 
                AND deleted_flag = 'N' 
                AND company_code IN {companyCodeString}";
            }
            else
            {
                query = $@"
                SELECT * FROM 
                (
                    SELECT item_code, index_mu_code, 1 ratio 
                    FROM ip_item_master_setup                     
                    WHERE index_mu_code IS NOT NULL 
                    AND INDEX_MU_CODE != 'None' 
                    AND GROUP_SKU_FLAG = 'I' 
                    AND deleted_flag = 'N' 
                    AND company_code IN {companyCodeString}
                    UNION ALL
                    SELECT item_code, mu_code, 
                           CASE WHEN conversion_factor = 0 THEN 0 
                                ELSE NVL(conversion_factor, 0) / NVL(fraction, 0) 
                           END ratio 
                    FROM IP_ITEM_UNIT_SETUP
                    WHERE serial_no = '1' 
                    AND deleted_flag = 'N' 
                    AND company_code IN {companyCodeString}
                    UNION ALL
                    SELECT item_code, mu_code, 
                           CASE WHEN conversion_factor = 0 THEN 0 
                                ELSE NVL(conversion_factor, 0) / NVL(fraction, 0) 
                           END ratio 
                    FROM IP_ITEM_UNIT_SETUP
                    WHERE serial_no = '2' 
                    AND deleted_flag = 'N' 
                    AND company_code IN {companyCodeString}
                ) WHERE index_mu_code = '{unitType}'";
            }

            Dictionary<string, Dictionary<string, string>> vals = new Dictionary<string, Dictionary<string, string>>();
            OracleConnection connection = new OracleConnection(_connection);
            using (OracleCommand cmd = new OracleCommand(query, connection))
            {
                if (connection.State != System.Data.ConnectionState.Open)
                    connection.Open();

                using (OracleDataReader reader = cmd.ExecuteReader())
                {
                    while (reader.Read())
                    {
                        string itemCode = reader["item_code"].ToString();
                        string muCode = reader["mu_code"].ToString();
                        string ratio = reader["ratio"].ToString();
                        vals[itemCode] = new Dictionary<string, string>
                    {
                        {"mu_code", muCode},
                        {"ratio", ratio}
                    };
                    }
                }
            }
            return vals;
        }

