                        ) c ON 'C' || A.customer_code = C.SUB_CODE
                        LEFT OUTER JOIN
                        (
                            SELECT sub_code D_CODE, NVL(SUM(dr_amount) - SUM(cr_amount), 0) OPENING
                            FROM V$VIRTUAL_SUB_LEDGEr
