                    var all_d = new List<Dictionary<string, object>>();
                    var column = new List<string> { "month" };
                    string queryCompany = "SELECT company_code, abbr_code, company_edesc FROM company_setup WHERE deleted_flag = 'N'";
                    _command = new OracleCommand(queryCompany, connection);
                    using (OracleDataReader reader = _command.ExecuteReader())
                    {
