                            column.Add(reader.GetString(1));
                            string queryComMonthlyWiseSales = $@"
                            SELECT startdate, r, NVL(qty, 0), NVL(amt, 0), aa FROM
                            (
                                SELECT rangename r FROM v_date_range WHERE sortorder = '1' AND startdate <= TRUNC(SYSDATE)
                                ORDER BY startdate
                            ) a
                            LEFT OUTER JOIN
                            (
                                SELECT a.*, CASE WHEN a.rangename = 'Ashoj' THEN SUBSTR(a.rangename, 1, 4) ELSE SUBSTR(a.rangename, 1, 3) END aa FROM
                                (
                                    SELECT startdate, rangename, SUM(sales_qty - sales_ret_qty) qty, SUM(sales_value - sales_ret_value) amt FROM
                                    (
                                        SELECT * FROM
                                        (
                                            SELECT A.COMPANY_CODE, A.BRANCH_CODE, A.sales_date,
                                            SUM(NVL(A.ROLL_QTY, 0)) SALES_ROLL_QTY, SUM(NVL(A.QUANTITY, 0)) SALES_QTY, 
                                            SUM(NVL(A.QUANTITY * A.NET_GROSS_RATE, 0)) SALES_VALUE, 0 SALES_RET_ROLL_QTY, 
                                            0 SALES_RET_QTY, 0 SALES_RET_VALUE
                                            FROM SA_SALES_INVOICE A
                                            WHERE A.DELETED_FLAG = 'N'
                                            AND A.COMPANY_CODE = '{reader.GetString(0)}'
                                            AND TRUNC(A.SALES_DATE) BETWEEN '{fromDate}' AND '{toDate}' {customerStr}
                                            GROUP BY A.COMPANY_CODE, A.BRANCH_CODE, A.sales_date
                                
                                            UNION ALL
                                
                                            SELECT A.COMPANY_CODE, A.BRANCH_CODE, A.return_date, 0 SALES_ROLL_QTY, 0 SALES_QTY, 0 SALES_VALUE,
                                            SUM(NVL(A.ROLL_QTY, 0)) SALES_RET_ROLL_QTY, SUM(NVL(A.QUANTITY, 0)) SALES_RET_QTY, 
                                            SUM(NVL(A.QUANTITY * A.NET_GROSS_RATE, 0)) SALES_RET_VALUE
                                            FROM SA_SALES_RETURN A
                                            WHERE A.DELETED_FLAG = 'N'
                                            AND A.COMPANY_CODE = '{reader.GetString(0)}'
                                            AND TRUNC(A.RETURN_DATE) BETWEEN '{fromDate}' AND '{toDate}' {customerStr}
                                            GROUP BY A.COMPANY_CODE, A.BRANCH_CODE, A.return_date ORDER BY sales_date
                                        ) a
                                        LEFT OUTER JOIN V_DATE_RANGE b ON a.sales_date BETWEEN b.startdate AND b.enddate
                                    ) GROUP BY startdate, rangename
                                ) a
                            ) b ON a.r = b.rangename";

                            _command = new OracleCommand(queryComMonthlyWiseSales, connection);
                            _command.CommandType = CommandType.Text;
                            //_command.Parameters.Add("fromDate", OracleType.DateTime).Value = fromDate;
                            //_command.Parameters.Add("toDate", OracleType.DateTime).Value = toDate;
                            using (OracleDataReader subReader = _command.ExecuteReader())
                            {
