                                    { "details", values },
                                    { "ttl_amt", (float)ttlAmt },
                                    { "ttl_qty", (float)ttlQty }
                                };
                                    ass["detail"] = totals;
                                    all_d.Add(ass);
                                    graph["Monthly_wise_sales_Items"] = totals;
                                }
                            }
                        }
                        //graph = new Dictionary<string, object>
                        //{
                        //    { "com_monthly_wise_sales", all_d }
                        //};
                        graph["com_monthly_wise_sales"] = all_d;



                        List<Dictionary<string, object>> jss = new List<Dictionary<string, object>>();
                        List<Dictionary<string, object>> all_data = new List<Dictionary<string, object>>(); // Ensure this is populated before use
                        var mons = new List<Dictionary<string, string>>
                     {
