                            #region Customer Ageing Data
                            try
                            {
                                //companyCode = companyCode.Substring(0, 1);
                                string cusFilter = string.IsNullOrEmpty(customerCode) ? "" : $" AND SUB_CODE = '{customerCode}' ";
                                string grpFilter = string.IsNullOrEmpty(grp) ? "" :
                                    $" AND SUB_CODE IN (SELECT 'C' || CUSTOMER_CODE FROM SA_CUSTOMER_SETUP WHERE MASTER_CUSTOMER_CODE LIKE '{grp}%' AND COMPANY_CODE IN ('{companyCode}')) ";

                                int interval = Convert.ToInt32("30");
                                string queryCustomerAgeingItem = $@"
                                    SELECT * FROM 
                                     (
                                     select * from 
                                    (select to_number(substr(sub_code,2,99)),voucher_date,voucher_no,
                                    case when qw=1 then net_amount else dr_amount end as pending_bal ,
                                    trunc(sysdate)-trunc(voucher_date) age,closing_balance from(select sub_code,voucher_no,voucher_date,dr_amount,cr_amount,qw,(dr_amount - nvl(cr_amount,0)) AS net_amount
                                    ,SUM(dr_amount - nvl(cr_amount,0)) OVER (PARTITION BY to_number(substr(sub_code,2,99)) ORDER BY voucher_date,voucher_no) AS closing_balance 
                                    from(select sub_code,voucher_no,voucher_date,dr_amount,qw,case when qw=1 then cr_amount else 0 end as cr_amount
                                    from(select sub_code,voucher_no,voucher_date,dr_amount,cr_amount, ROW_NUMBER() OVER (PARTITION BY to_number(substr(sub_code,2,9999)) ORDER BY to_number(substr(sub_code,2,9999)),voucher_no) AS qw
                                    from 
                                    (

                                    select sub_code,voucher_no,voucher_date,dr_amount, SUM(cr_amount) OVER (PARTITION BY sub_code) cr_amount 
