                            catch (Exception ex)
                            { }
                            #endregion

                            #region SuppliersAgeing Data

                            string cusCodeCondition = !string.IsNullOrEmpty(customerCode) ? $" AND SUB_CODE = '{customerCode}' " : "";
                            string grpCodeCondition = !string.IsNullOrEmpty(grp)
                                ? $" AND SUB_CODE IN (SELECT 'C' + CUSTOMER_CODE FROM SA_CUSTOMER_SETUP WHERE MASTER_CUSTOMER_CODE LIKE '{grp}%' AND COMPANY_CODE IN ('{companyCode}')) "
                                : "";

                            string querySupplierAgeingItem = $@"
                                    SELECT * FROM (
                                        SELECT * FROM (
                                            SELECT TO_NUMBER(SUBSTR(SUB_CODE,2,99)), VOUCHER_DATE, VOUCHER_NO,
                                                CASE WHEN QW=1 THEN NET_AMOUNT ELSE DR_AMOUNT END AS PENDING_BAL,
                                                TRUNC(SYSDATE) - TRUNC(VOUCHER_DATE) AGE, CLOSING_BALANCE
                                            FROM (
                                                SELECT SUB_CODE, VOUCHER_NO, VOUCHER_DATE, DR_AMOUNT, CR_AMOUNT, QW,
                                                    (DR_AMOUNT - NVL(CR_AMOUNT,0)) AS NET_AMOUNT,
                                                    SUM(DR_AMOUNT - NVL(CR_AMOUNT,0)) OVER (PARTITION BY TO_NUMBER(SUBSTR(SUB_CODE,2,99)) ORDER BY VOUCHER_DATE,VOUCHER_NO) AS CLOSING_BALANCE
                                                FROM (
                                                    SELECT SUB_CODE, VOUCHER_NO, VOUCHER_DATE, DR_AMOUNT, QW,
                                                        CASE WHEN QW=1 THEN CR_AMOUNT ELSE 0 END AS CR_AMOUNT
                                                    FROM (
                                                        SELECT SUB_CODE, VOUCHER_NO, VOUCHER_DATE, DR_AMOUNT, CR_AMOUNT,
                                                            ROW_NUMBER() OVER (PARTITION BY TO_NUMBER(SUBSTR(SUB_CODE,2,9999)) ORDER BY TO_NUMBER(SUBSTR(SUB_CODE,2,9999)), VOUCHER_NO) AS QW
                                                        FROM (
                                                            SELECT SUB_CODE, VOUCHER_NO, VOUCHER_DATE, DR_AMOUNT,
                                                                SUM(CR_AMOUNT) OVER (PARTITION BY SUB_CODE) CR_AMOUNT
                                                            FROM V$VIRTUAL_SUB_LEDGER
                                                            WHERE VOUCHER_NO != '0' 
                                                            AND COMPANY_CODE='{companyCode}'
                                                            AND SUBSTR(SUB_CODE,1,1)='S' {cusCodeCondition} {grpCodeCondition}
                                                            AND FORM_CODE NOT IN (SELECT DISTINCT FORM_CODE FROM FORM_DETAIL_SETUP WHERE TABLE_NAME='FA_PAY_ORDER' AND COMPANY_CODE='{companyCode}')
                                                            ORDER BY TO_NUMBER(SUBSTR(SUB_CODE,2,99)), VOUCHER_DATE, VOUCHER_NO
                                                        )
                                                        WHERE DR_AMOUNT != 0
                                                    )
                                                )
                                            )
                                            WHERE CLOSING_BALANCE > 0
                                        )
                                    )
                                    ORDER BY 1";

                            //List<string> allCodesSA = ExecuteQueryToList(querySupplierAgeingItem);
                            List<string> allCodesSA = ExecuteQueryToListAgein(querySupplierAgeingItem);
                            int intervalSA = Convert.ToInt32("30");
                            Dictionary<int, Dictionary<string, object>> allDataSA = new Dictionary<int, Dictionary<string, object>>();
                            List<Dictionary<string, object>> firstSA030 = new List<Dictionary<string, object>>();
                            List<Dictionary<string, object>> thirdSA3160 = new List<Dictionary<string, object>>();
                            List<Dictionary<string, object>> fourthSA6190 = new List<Dictionary<string, object>>();
                            List<Dictionary<string, object>> sixthSA91120 = new List<Dictionary<string, object>>();
                            List<Dictionary<string, object>> seventhSA120 = new List<Dictionary<string, object>>();

                            List<decimal> allBalSA = new List<decimal>();
                            //List<object> allBalSA = new List<object>();
                            int xSA = 0;
                            decimal balSA = 0;
                            int sub_codeSA = 0;
                            int daySA = 0;
                            string v_noSA = "";
                            foreach (var i in allCodesSA)
                            {
                                try
                                {
                                    if (xSA == 0)
                                    {
                                        sub_codeSA = i[0];
                                        allBalSA = new List<decimal>();
                                    }
                                    else
                                    {
                                        allBalSA.Add(balSA);

                                        if (daySA <= intervalSA)
                                        {
                                            firstSA030.Add(new Dictionary<string, object> { { "amt", balSA }, { "v_no", v_noSA }, { "days", daySA } });
                                        }
                                        else if (daySA <= intervalSA * 2)
                                        {
                                            thirdSA3160.Add(new Dictionary<string, object> { { "amt", balSA }, { "v_no", v_noSA }, { "days", daySA } });
                                        }
                                        else if (daySA <= intervalSA * 3)
                                        {
                                            fourthSA6190.Add(new Dictionary<string, object> { { "amt", balSA }, { "v_no", v_noSA }, { "days", daySA } });
                                        }
                                        else if (daySA <= intervalSA * 4)
                                        {
                                            sixthSA91120.Add(new Dictionary<string, object> { { "amt", balSA }, { "v_no", v_noSA }, { "days", daySA } });
                                        }
                                        else
                                        {
                                            seventhSA120.Add(new Dictionary<string, object> { { "amt", balSA }, { "v_no", v_noSA }, { "days", daySA } });
                                        }
                                    }
                                    if (sub_codeSA != i[0])
                                    {
                                        allDataSA[sub_codeSA] = new Dictionary<string, object>
                                    {
                                        { "sub_code", sub_codeSA },
                                        { "total", allBalSA.Sum() },
                                        { "0-30", firstSA030.Sum(entry => Convert.ToDecimal(entry["amt"])) },
                                        { "0-31_detail", firstSA030 },
                                        { "31-60", thirdSA3160.Sum(entry => Convert.ToDecimal(entry["amt"])) },
                                        { "31-60_detail", thirdSA3160 },
                                        { "61-90", fourthSA6190.Sum(entry => Convert.ToDecimal(entry["amt"])) },
                                        { "61-90_detail", fourthSA6190 },
                                        { "91-120", sixthSA91120.Sum(entry => Convert.ToDecimal(entry["amt"])) },
                                        { "91-120_detail", sixthSA91120 },
                                        { "120+", seventhSA120.Sum(entry => Convert.ToDecimal(entry["amt"])) },
                                        { "120+_detail", seventhSA120 }
                                    };

                                        // Reset Lists
                                        allBalSA = new List<decimal>();
                                        firstSA030 = new List<Dictionary<string, object>>();
                                        thirdSA3160 = new List<Dictionary<string, object>>();
                                        fourthSA6190 = new List<Dictionary<string, object>>();
                                        sixthSA91120 = new List<Dictionary<string, object>>();
                                        seventhSA120 = new List<Dictionary<string, object>>();
                                    }

                                    sub_codeSA = i[0];
                                    balSA = i[3];
                                    daySA = i[4];
                                    v_noSA = i[2].ToString();
                                    xSA++;
                                }
                                catch(Exception ex)
                                { }
                            }
                            allBalSA.Add(balSA);
                            int parsedDaySA=0;
                            try
                            {
                                parsedDaySA = Convert.ToInt32(daySA);
                            }
                            catch (Exception)
                            {

                            }

                            // Categorize balance into aging buckets
                            if (parsedDaySA <= intervalSA)
                            {
                                firstSA030.Add(new Dictionary<string, object> { { "amt", balSA }, { "v_no", v_noSA }, { "days", parsedDaySA } });
                            }
                            else if (parsedDaySA <= intervalSA * 2)
                            {
                                thirdSA3160.Add(new Dictionary<string, object> { { "amt", balSA }, { "v_no", v_noSA }, { "days", parsedDaySA } });
                            }
                            else if (parsedDaySA <= intervalSA * 3)
                            {
                                fourthSA6190.Add(new Dictionary<string, object> { { "amt", balSA }, { "v_no", v_noSA }, { "days", parsedDaySA } });
                            }
                            else if (parsedDaySA <= intervalSA * 4)
                            {
                                sixthSA91120.Add(new Dictionary<string, object> { { "amt", balSA }, { "v_no", v_noSA }, { "days", parsedDaySA } });
                            }
                            else
                            {
                                seventhSA120.Add(new Dictionary<string, object> { { "amt", balSA }, { "v_no", v_noSA }, { "days", parsedDaySA } });
                            }

                            // Store categorized data into dictionary
                            allDataSA[sub_codeSA] = new Dictionary<string, object>
                            {
                                { "sub_code", sub_codeSA },
                                { "total", allBalSA.Sum() },
                                { "0-30", firstSA030.Sum(entry => Convert.ToDecimal(entry["amt"])) },
                                { "0-31_detail", firstSA030 },
                                { "31-60", thirdSA3160.Sum(entry => Convert.ToDecimal(entry["amt"])) },
                                { "31-60_detail", thirdSA3160 },
                                { "61-90", fourthSA6190.Sum(entry => Convert.ToDecimal(entry["amt"])) },
                                { "61-90_detail", fourthSA6190 },
                                { "91-120", sixthSA91120.Sum(entry => Convert.ToDecimal(entry["amt"])) },
                                { "91-120_detail", sixthSA91120 },
                                { "120+", seventhSA120.Sum(entry => Convert.ToDecimal(entry["amt"])) },
                                { "120+_detail", seventhSA120 }
                            };

                            List<Dictionary<string, object>> allCusSA = new List<Dictionary<string, object>>();
                            string querySA = $@"
                                SELECT SUPPLIER_CODE, SUPPLIER_EDESC, GROUP_SKU_FLAG, MASTER_SUPPLIER_CODE, PRE_SUPPLIER_CODE
                                FROM IP_SUPPLIER_SETUP 
                                WHERE company_code = '{companyCode}' AND deleted_flag = 'N'
                                GROUP BY SUPPLIER_CODE, SUPPLIER_EDESC, GROUP_SKU_FLAG, MASTER_SUPPLIER_CODE, PRE_SUPPLIER_CODE
                                ORDER BY 4";

                            using (OracleCommand cmdSA = new OracleCommand(querySA, connection))
                            {
                                cmdSA.CommandType = CommandType.Text;
                                try
                                {
                                    using (var readerSA = cmdSA.ExecuteReader())
                                    {
                                        while (readerSA.Read())
                                        {
                                            int subCodeSA = Convert.ToInt32(readerSA[0]);
                                            var totalSA = allDataSA.ContainsKey(subCodeSA) ? allDataSA[subCodeSA] : new Dictionary<string, object>();

                                            allCusSA.Add(new Dictionary<string, object>
                                        {
                                            { "CUSTOMER_CODE", readerSA[0] },
                                            { "CUSTOMER_EDESC", readerSA[1] },
                                            { "GROUP_SKU_FLAG", readerSA[2] },
                                            { "MASTER_CUSTOMER_CODE", readerSA[3] },
                                            { "PRE_CUSTOMER_CODE", readerSA[4] },
                                            { "total", totalSA.ContainsKey("total") ? totalSA["total"] : 0 },
                                            { "0-30", totalSA.ContainsKey("0-30") ? totalSA["0-30"] : 0 },
                                            { "0-31_detail", totalSA.ContainsKey("0-31_detail") ? totalSA["0-31_detail"] : new List<object>() },
                                            { "31-60", totalSA.ContainsKey("31-60") ? totalSA["31-60"] : 0 },
                                            { "31-60_detail", totalSA.ContainsKey("31-60_detail") ? totalSA["31-60_detail"] : new List<object>() },
                                            { "61-90", totalSA.ContainsKey("61-90") ? totalSA["61-90"] : 0 },
                                            { "61-90_detail", totalSA.ContainsKey("61-90_detail") ? totalSA["61-90_detail"] : new List<object>() },
                                            { "91-120", totalSA.ContainsKey("91-120") ? totalSA["91-120"] : 0 },
                                            { "91-120_detail", totalSA.ContainsKey("91-120_detail") ? totalSA["91-120_detail"] : new List<object>() },
                                            { "120+", totalSA.ContainsKey("120+") ? totalSA["120+"] : 0 },
                                            { "120+_detail", totalSA.ContainsKey("120+_detail") ? totalSA["120+_detail"] : new List<object>() }
                                        });
                                        }
                                    }
                                }
                                catch(Exception ex)
                                { }
                            }

                            //List<Dictionary<string, object>> vals = new List<Dictionary<string, object>>();
                            double totalSA1, totalSA2, totalSA3, totalSA4, totalSA5, totalSA6;
                            List<double> arrTotalSA1 = new List<double>();
                            List<double> arrTotalSA2 = new List<double>();
                            List<double> arrTotalSA3 = new List<double>();
                            List<double> arrTotalSA4 = new List<double>();
                            List<double> arrTotalSA5 = new List<double>();
                            List<double> arrTotalSA6 = new List<double>();

                            foreach (var i in allCusSA)
                            {
                                try
                                {
                                    totalSA1 = totalSA2 = totalSA3 = totalSA4 = totalSA5 = totalSA6 = 0;

                                    if (i["GROUP_SKU_FLAG"].ToString() == "G")
                                    {
                                        bool addOnSA = false;
                                        foreach (var z in allCusSA)
                                        {
                                            if (z["GROUP_SKU_FLAG"].ToString() == "I")
                                            {
                                                string asd = "";
                                                try
                                                {
                                                    asd = z["MASTER_CUSTOMER_CODE"].ToString();
                                                    asd = asd.Substring(0, Math.Min(asd.Length, i["MASTER_CUSTOMER_CODE"].ToString().Length));
                                                }
                                                catch (Exception)
                                                {
                                                    asd = string.Empty;
                                                }

                                                if (i["MASTER_CUSTOMER_CODE"].ToString().Contains(asd))
                                                {
                                                    addOnSA = true;
                                                    totalSA1 += Convert.ToDouble(z["total"]);
                                                    totalSA2 += Convert.ToDouble(z["0-30"]);
                                                    totalSA3 += Convert.ToDouble(z["31-60"]);
                                                    totalSA4 += Convert.ToDouble(z["61-90"]);
                                                    totalSA5 += Convert.ToDouble(z["91-120"]);
                                                    totalSA6 += Convert.ToDouble(z["120+"]);
                                                }
                                                else if (addOnSA)
                                                {
                                                    break;
                                                }
                                            }
                                        }

                                        if (totalSA1 > 0)
                                        {
                                            vals.Add(new Dictionary<string, object>
                                            {
                                                { "item", i["CUSTOMER_EDESC"] },
                                                { "group_flag", i["GROUP_SKU_FLAG"] },
                                                { "total", totalSA1 },
                                                { "level", i["MASTER_CUSTOMER_CODE"].ToString().Count(c => c == '.') },
                                                { "master", i["MASTER_CUSTOMER_CODE"] },
                                                { "pre", i["PRE_CUSTOMER_CODE"] },
                                                { "code", i["CUSTOMER_CODE"] },
                                                { "0-30", totalSA2 },
                                                { "31-60", totalSA3 },
                                                { "61-90", totalSA4 },
                                                { "91-120", totalSA5 },
                                                { "120+", totalSA6 }
                                            });
                                        }
                                    }

                                    if (i["GROUP_SKU_FLAG"].ToString() == "I")
                                    {
                                        if (Convert.ToDouble(i["total"]) > 0)
                                        {
                                            arrTotalSA1.Add(Convert.ToDouble(i["total"]));
                                            arrTotalSA2.Add(Convert.ToDouble(i["0-30"]));
                                            arrTotalSA3.Add(Convert.ToDouble(i["31-60"]));
                                            arrTotalSA4.Add(Convert.ToDouble(i["61-90"]));
                                            arrTotalSA5.Add(Convert.ToDouble(i["91-120"]));
                                            arrTotalSA6.Add(Convert.ToDouble(i["120+"]));
                                            vals.Add(new Dictionary<string, object>
                                        {
                                            { "item", i["CUSTOMER_EDESC"] },
                                            { "group_flag", i["GROUP_SKU_FLAG"] },
                                            { "total", Convert.ToDouble(i["total"]) },
                                            { "level", i["MASTER_CUSTOMER_CODE"].ToString().Count(c => c == '.') },
                                            { "master", i["MASTER_CUSTOMER_CODE"] },
                                            { "pre", i["PRE_CUSTOMER_CODE"] },
                                            { "code", i["CUSTOMER_CODE"] },
                                            { "0-30", Convert.ToDouble(i["0-30"]) },
                                            { "31-60", Convert.ToDouble(i["31-60"]) },
                                            { "61-90", Convert.ToDouble(i["61-90"]) },
                                            { "91-120", Convert.ToDouble(i["91-120"]) },
                                            { "120+", Convert.ToDouble(i["120+"]) },
                                            { "0-30_detail", i["0-31_detail"] },
                                            { "31-60_detail", i["31-60_detail"] },
                                            { "61-90_detail", i["61-90_detail"] },
                                            { "91-120_detail", i["91-120_detail"] },
                                            { "120+_detail", i["120+_detail"] }
                                        });
                                        }
                                    }
                                }
                                catch(Exception ex)
                                { }

                            }
                            var SupplierAgeingResult = new
                            {
                                detail = vals,
                                total = new
                                {
                                    _0_30 = arrTotalSA2.Sum(),
                                    _31_60 = arrTotalSA3.Sum(),
                                    _61_90 = arrTotalSA4.Sum(),
                                    _91_120 = arrTotalSA5.Sum(),
                                    _120Plus = arrTotalSA6.Sum(),
                                    total = arrTotalSA1.Sum()
                                }
                            };
                            graph["Supplier_Ageing_Item"] = SupplierAgeingResult;

                            #endregion

                            #region category wise sales
                            string queryCatWiseSalesItem = $@"
                                SELECT category_edesc, qty, amt
                                FROM (
                                SELECT CASE WHEN category_code IS NULL THEN 'not defined' ELSE category_code END AS cat,
                                       SUM(sales_qty - sales_ret_qty) AS qty,
                                       SUM(sales_value - sales_ret_value) AS amt
                                FROM (
                                    SELECT *
                                    FROM (
                                        SELECT A.COMPANY_CODE, A.BRANCH_CODE, a.item_code,
                                               NVL(SUM(A.ROLL_QTY), 0) AS SALES_ROLL_QTY,
                                               NVL(SUM(A.QUANTITY), 0) AS SALES_QTY,
                                               NVL(SUM(A.QUANTITY * A.NET_GROSS_RATE), 0) AS SALES_VALUE,
                                               0 AS SALES_RET_ROLL_QTY, 0 AS SALES_RET_QTY, 0 AS SALES_RET_VALUE
                                        FROM SA_SALES_INVOICE A
                                        WHERE A.DELETED_FLAG = 'N'
                                              AND A.BRANCH_CODE IN {GetBranchFilter(companyCode, branchCode, this.UserId.ToString())}
                                              AND A.COMPANY_CODE IN {companyCode}
                                              AND TRUNC(A.SALES_DATE) BETWEEN '{fromDate}' AND '{toDate}'
                                              {customerStr} {itemStringFilter}
                                        GROUP BY A.COMPANY_CODE, A.BRANCH_CODE, a.item_code
                                        UNION ALL
                                        SELECT A.COMPANY_CODE, A.BRANCH_CODE, a.item_code,
                                               0 AS SALES_ROLL_QTY, 0 AS SALES_QTY, 0 AS SALES_VALUE,
                                               NVL(SUM(A.ROLL_QTY), 0) AS SALES_RET_ROLL_QTY,
                                               NVL(SUM(A.QUANTITY), 0) AS SALES_RET_QTY,
                                               NVL(SUM(A.QUANTITY * A.NET_GROSS_RATE), 0) AS SALES_RET_VALUE
                                        FROM SA_SALES_RETURN A
                                        WHERE A.DELETED_FLAG = 'N'
                                              AND A.BRANCH_CODE IN {GetBranchFilter(companyCode, branchCode, this.UserId.ToString())}
                                              AND A.COMPANY_CODE IN {companyCode}
                                              AND TRUNC(A.return_DATE) BETWEEN '{fromDate}' AND '{toDate}'
                                              {customerStr} {itemStringFilter}
                                        GROUP BY A.COMPANY_CODE, A.BRANCH_CODE, a.item_code
                                    ) a
                                    LEFT OUTER JOIN (
                                        SELECT item_code AS code, category_code
                                        FROM IP_ITEM_MASTER_SETUP
                                        WHERE COMPANY_CODE IN {companyCode}
                                    ) b ON a.item_code = b.code
                                ) GROUP BY category_code
                            ) a
                            LEFT OUTER JOIN (
                                SELECT category_code AS code, category_edesc
                                FROM IP_CATEGORY_CODE
                                WHERE COMPANY_CODE IN {companyCode}
                            ) b ON a.cat = b.code
                            ORDER BY category_edesc";

                            using (OracleCommand cmdCatWiseSalesItem = new OracleCommand(queryCatWiseSalesItem, connection))
                                {
                                    cmdCatWiseSalesItem.CommandType = CommandType.Text;
                                    //cmd.Parameters.Add("fromDate", OracleType.DateTime).Value = fromDate;
                                    //cmd.Parameters.Add("toDate", OracleType.DateTime).Value = toDate;
                                    List<Dictionary<string, object>> values = new List<Dictionary<string, object>>();
                                    List<float> qtys = new List<float>();
                                    List<float> amts = new List<float>();

                                    using (OracleDataReader DataReader = cmdCatWiseSalesItem.ExecuteReader())
                                    {
                                        while (DataReader.Read())
                                        {
                                            string categoryDescription = DataReader["category_edesc"].ToString();
                                            float quantity = Convert.ToSingle(DataReader["qty"]);
                                            float amount = Convert.ToSingle(DataReader["amt"]);

                                            qtys.Add(quantity);
                                            amts.Add(amount);

                                            values.Add(new Dictionary<string, object>
                                        {
                                            { "name", categoryDescription },
                                            { "qty", quantity },
                                            { "amt", amount }
                                        });
                                        }
                                    }

                                    graph["cat_wise_sales_Items"] = values;

                                    float totalQtys = qty.Sum();
                                    float totalAmts = amt.Sum();
                                    var totals = new Dictionary<string, object>
                                    {
                                        { "total_qty", totalQtys },
                                        { "total_amt", totalAmts },
                                        { "details", values }
                                    };

                                    //graph = new Dictionary<string, object>
                                    //{
                                    //    { "cat_wise_sales", totals }
                                    //};

                                    graph["cat_wise_sales"] = total;


                                    string queryTopTenProductSalesItems = $@"
                                    SELECT * FROM (
                                    SELECT * FROM (
                                        SELECT A.*, ROWNUM AS RM FROM (
                                            SELECT ITEM_EDESC, SUM(sales_qty - sales_ret_qty) AS qty, SUM(sales_value - sales_ret_value) AS amt
                                            FROM (
                                                SELECT *
                                                FROM (
                                                    SELECT A.COMPANY_CODE, A.BRANCH_CODE, A.item_code,
                                                           NVL(SUM(A.ROLL_QTY), 0) AS SALES_ROLL_QTY,
                                                           NVL(SUM(A.QUANTITY), 0) AS SALES_QTY,
                                                           NVL(SUM(A.QUANTITY * A.NET_GROSS_RATE), 0) AS SALES_VALUE,
                                                           0 AS SALES_RET_ROLL_QTY, 0 AS SALES_RET_QTY, 0 AS SALES_RET_VALUE
                                                    FROM SA_SALES_INVOICE A
                                                    WHERE A.DELETED_FLAG = 'N'
                                                      AND A.BRANCH_CODE IN {GetBranchFilter(companyCode, branchCode, this.UserId.ToString())}
                                                      AND A.COMPANY_CODE IN {companyCode}
                                                    GROUP BY A.COMPANY_CODE, A.BRANCH_CODE, A.item_code

                                                    UNION ALL

                                                    SELECT A.COMPANY_CODE, A.BRANCH_CODE, A.item_code,
                                                           0 AS SALES_ROLL_QTY, 0 AS SALES_QTY, 0 AS SALES_VALUE,
                                                           NVL(SUM(A.ROLL_QTY), 0) AS SALES_RET_ROLL_QTY,
                                                           NVL(SUM(A.QUANTITY), 0) AS SALES_RET_QTY,
                                                           NVL(SUM(A.QUANTITY * A.NET_GROSS_RATE), 0) AS SALES_RET_VALUE
                                                    FROM SA_SALES_RETURN A
                                                    WHERE A.DELETED_FLAG = 'N'
                                                      AND A.BRANCH_CODE IN {GetBranchFilter(companyCode, branchCode, this.UserId.ToString())}
                                                      AND A.COMPANY_CODE IN {companyCode}
                                                    GROUP BY A.COMPANY_CODE, A.BRANCH_CODE, A.item_code
                                                ) a
                                                LEFT OUTER JOIN (
                                                    SELECT item_code AS code, ITEM_EDESC
                                                    FROM IP_ITEM_MASTER_SETUP
                                                    WHERE COMPANY_CODE IN {companyCode}
                                                ) b ON a.item_code = b.code
                                            ) GROUP BY ITEM_EDESC
                                            ORDER BY amt DESC
                                        ) A
                                    ) WHERE RM < 11
                                )
                                ORDER BY TO_NUMBER(amt) DESC";
                                    using (OracleCommand comm = new OracleCommand(queryTopTenProductSalesItems, connection))
                                    {
                                        comm.CommandType = CommandType.Text;
                                        List<Dictionary<string, object>> valueList = new List<Dictionary<string, object>>();
                                        List<float> quantities = new List<float>();
                                        List<float> amounts = new List<float>();

                                        using (OracleDataReader DataRead = comm.ExecuteReader())
                                        {
                                            while (DataRead.Read())
                                            {
                                                string itemDescription = DataRead["ITEM_EDESC"].ToString();
                                                float quantity = Convert.ToSingle(DataRead["qty"]);
                                                float amount = Convert.ToSingle(DataRead["amt"]);
                                                quantities.Add(quantity);
                                                amounts.Add(amount);
                                                valueList.Add(new Dictionary<string, object>
                                            {
                                                { "name", itemDescription },
                                                { "qty", quantity },
                                                { "amt", amount }
                                            });
                                            }
                                        }
                                        graph["top_ten_product_sales_Items"] = valueList;

                                        float total_Qty = quantities.Sum();
                                        float total_Amt = amounts.Sum();
                                        var totls = new Dictionary<string, object>
                                    {
                                        { "total_qty", total_Qty },
                                        { "total_amt", total_Amt },
                                        { "details", valueList }
                                    };
                                        //graph = new Dictionary<string, object>
                                        //{
                                        //    { "top_ten_product_sales", totls }
                                        //};

                                        graph["top_ten_product_sales"] = total;
                                    }
                                }
                            }
                        #endregion

                        #region Monthly Sales Vs Collection
                     
                        List<float> opening = new List<float>();

                            // Opening Balance Query
                            string openingQuery = $@"
                            SELECT NVL(SUM(dr_amount) - SUM(cr_amount), 0) OPENING
                            FROM V$VIRTUAL_SUB_LEDGER
                            WHERE COMPANY_CODE IN ({companyCode})
                            AND deleted_flag = 'N'
                            AND form_code = '0'
                            AND SUBSTR(sub_code, 1, 1) = 'C'";
                            using (var commandVsMSColl = new OracleCommand(openingQuery, connection))
                             {
                                commandVsMSColl.CommandType = CommandType.Text;
                                commandVsMSColl.CommandTimeout = 300;
                                using (var readerOpBal = commandVsMSColl.ExecuteReader())
                                    {
                                        while (readerOpBal.Read())
                                        {
                                            opening.Add(readerOpBal.IsDBNull(0) ? 0 : readerOpBal.GetFloat(0));
                                        }
                                    }
                                }
                         // Monthly Sales vs Collection Query
                        string salesVsCollectionQuery = $@"
                        SELECT CASE 
                            WHEN mahina = 'Shrawan' THEN 'Bhadra'
                            WHEN mahina = 'Bhadra' THEN 'Ashoj'
                            WHEN mahina = 'Ashoj' THEN 'Kartik'
                            WHEN mahina = 'Kartik' THEN 'Mangsir'
                            WHEN mahina = 'Mangsir' THEN 'Poush'
                            WHEN mahina = 'Poush' THEN 'Magh'
                            WHEN mahina = 'Magh' THEN 'Falgun'
                            WHEN mahina = 'Falgun' THEN 'Chaitra'
                            WHEN mahina = 'Chaitra' THEN 'Baishakh'
                            WHEN mahina = 'Baishakh' THEN 'Jestha'
                            WHEN mahina = 'Jestha' THEN 'Ashadh'
                            ELSE 'undefined'
                        END mahina,
                        SUM(balance), startdate
                        FROM 
                        (
                            SELECT ACC_CODE, COMPANY_CODE, b.startdate, B.RANGENAME MAHINA,  
                            CASE 
                                WHEN (SELECT TRANSACTION_TYPE FROM FA_CHART_OF_ACCOUNTS_SETUP WHERE ACC_CODE = A.ACC_CODE AND COMPANY_CODE = A.COMPANY_CODE) = 'DR' 
                                THEN SUM(NVL(DR_AMOUNT, 0) - NVL(CR_AMOUNT, 0)) 
                                ELSE SUM(NVL(CR_AMOUNT, 0) - NVL(DR_AMOUNT, 0)) 
                            END BALANCE  
                            FROM V$VIRTUAL_GENERAL_LEDGER A, V_DATE_RANGE B  
                            WHERE VOUCHER_DATE <= ENDDATE  
                            AND SORTORDER = 1 
                            AND ENDDATE <= (SELECT ENDDATE FROM V_DATE_RANGE  
                                            WHERE ENDDATE > (SELECT MAX(VOUCHER_DATE) FROM V$VIRTUAL_GENERAL_LEDGER 
                                                             WHERE COMPANY_CODE IN ({companyCode})
                                                             AND TRUNC(VOUCHER_DATE) <= '{toDate}') 
                                            AND ROWNUM = 1)  
                            AND COMPANY_CODE IN ({companyCode})                
                            AND DELETED_FLAG = 'N'  
                            AND ACC_CODE IN (SELECT ACC_CODE FROM FA_CHART_OF_ACCOUNTS_SETUP 
                                             WHERE COMPANY_CODE IN ({companyCode}) 
                                             AND DELETED_FLAG = 'N' 
                                             AND acc_nature IN ('AE'))  
                            GROUP BY ACC_CODE, b.startdate, B.RANGENAME, COMPANY_CODE
                        ) 
                        GROUP BY mahina, startdate 
                        ORDER BY 3";

                        using (var commandVsColl = new OracleCommand(salesVsCollectionQuery, connection))
                        {
                            commandVsColl.CommandType = CommandType.Text;
                            commandVsColl.CommandTimeout = 300;
                            using (var readerMC = commandVsColl.ExecuteReader())
                            {
                                int x = 0;
                                while (readerMC.Read())
                                {
                                    if (readerMC.IsDBNull(1)) continue;
                                    opening.Add(readerMC.GetFloat(1)); // Adjust index as needed
                                    x++;
                                }
                            }
                        }
                    // Final Sales and Collection Query
                     string salesVsCollectionQuerys = $@"
                        SELECT rangename, NVL(sales, 0), NVL(collection, 0) 
                        FROM 
                        (
                            SELECT * 
                            FROM 
                            (
                                SELECT RANGENAME  
                                FROM V_DATE_RANGE 
                                WHERE SORTORDER = 1 
                                AND startdate <= TRUNC(SYSDATE) 
                                ORDER BY STARTDATE
                            ) A
                            LEFT OUTER JOIN 
                            (
                                SELECT RANGENAME rs, VAL SALES  
                                FROM 
                                (
                                    SELECT rangename, SUM(sales_qty - sales_ret_qty), SUM(sales_value - sales_ret_value) VAL 
                                    FROM
                                    (
                                        SELECT A.COMPANY_CODE, A.BRANCH_CODE, A.SALES_DATE,
                                        SUM(NVL(A.ROLL_QTY, 0)) SALES_ROLL_QTY, 
                                        SUM(NVL(A.QUANTITY, 0)) SALES_QTY, 
                                        SUM(NVL(A.QUANTITY * A.NET_sales_RATE, 0)) SALES_VALUE,
                                        0 SALES_RET_ROLL_QTY, 
                                        0 SALES_RET_QTY, 
                                        0 SALES_RET_VALUE  
                                        FROM SA_SALES_INVOICE A 
                                        WHERE A.DELETED_FLAG = 'N'
                                        AND A.BRANCH_CODE IN ({branchCode})
                                        AND A.COMPANY_CODE IN ({companyCode}) {cusGrpStr}
                                        AND TRUNC(a.SALES_DATE) BETWEEN '{fromDate}' AND '{toDate}' {customerStr} {itemStringFilter}                             
                                        GROUP BY A.COMPANY_CODE, A.BRANCH_CODE, A.SALES_DATE
                                        UNION ALL
                                        SELECT A.COMPANY_CODE, A.BRANCH_CODE, A.RETURN_DATE, 
                                        0 SALES_ROLL_QTY, 
                                        0 SALES_QTY, 
                                        0 SALES_VALUE,
                                        SUM(NVL(A.ROLL_QTY, 0)) SALES_RET_ROLL_QTY, 
                                        SUM(NVL(A.QUANTITY, 0)) SALES_RET_QTY,
                                        SUM(NVL(A.QUANTITY * A.NET_sales_RATE, 0)) SALES_RET_VALUE  
                                        FROM SA_SALES_RETURN A
                                        WHERE A.DELETED_FLAG = 'N'
                                        AND A.COMPANY_CODE IN ({companyCode}) {cusGrpStr}
                                        AND A.BRANCH_CODE IN ({branchCode})
                                        AND TRUNC(A.RETURN_DATE) BETWEEN '{fromDate}' AND '{toDate}' {customerStr} {itemStringFilter}
                                        GROUP BY A.COMPANY_CODE, A.BRANCH_CODE, A.RETURN_DATE 
                                    ) a
                                    LEFT OUTER JOIN 
                                    (SELECT * FROM V_DATE_RANGE WHERE SORTORDER = '1') b
                                    ON a.SALES_DATE BETWEEN b.STARTDATE AND b.ENDDATE    
                                    WHERE RANGENAME IS NOT NULL 
                                    GROUP BY STARTDATE, RANGENAME 
                                    )
                                ) B 
                                ON A.RANGENAME = B.rs
                                LEFT OUTER JOIN 
                                (
                                    SELECT RANGENAME ms, SUM(amt) collection 
                                    FROM 
                                    (
                                        SELECT * 
                                        FROM
                                        (
                                            SELECT voucher_date, NVL(SUM(NVL(CR_AMOUNT, 0) * NVL(EXCHANGE_RATE, 1)), 0) amt
                                            FROM V$VIRTUAL_SUB_LEDGER b
                                            WHERE (COMPANY_CODE, Voucher_NO) IN
                                            (
                                                SELECT COMPANY_CODE, A.voucher_no
                                                FROM V$VIRTUAL_GENERAL_LEDGER A
                                                WHERE A.ACC_CODE IN 
                                                (
                                                    SELECT ACC_CODE 
                                                    FROM FA_CHART_OF_ACCOUNTS_SETUP 
                                                    WHERE ACC_NATURE IN ('AB', 'AC', 'LC') 
                                                    AND COMPANY_CODE = A.COMPANY_CODE
                                                )
                                                AND A.TRANSACTION_TYPE = 'DR'                                        
                                                AND A.COMPANY_CODE IN ({companyCode})                                                                                                                     
                                                AND A.BRANCH_CODE IN ({branchCode})
                                                {subCodeStr} {subCodeCusStr}                                                                                                                   
                                                AND A.DELETED_FLAG = 'N'
                                                AND A.Voucher_NO != '0'
                                            )
                                            AND SUBSTR(sub_code, 1, 1) = 'C'
                                            AND TRANSACTION_TYPE = 'CR'                                                                                                                            
                                            GROUP BY voucher_date
                                        ) a
                                        LEFT OUTER JOIN 
                                        (SELECT * FROM V_DATE_RANGE WHERE SORTORDER = '1') b
                                        ON a.voucher_date BETWEEN b.STARTDATE AND b.ENDDATE
                                    )  
                                    WHERE RANGENAME IS NOT NULL 
                                    GROUP BY STARTDATE, RANGENAME
                                ) C
                                ON A.RANGENAME = C.ms
                        )";

                        List<Dictionary<string, object>> reportDetails = new List<Dictionary<string, object>>();
                        using (var commandVsCollection = new OracleCommand(salesVsCollectionQuerys, connection))
                        {
                            commandVsCollection.CommandType = CommandType.Text;
                            commandVsCollection.CommandTimeout = 300;
                            using (var readerMonthVsSales = commandVsCollection.ExecuteReader())
                            {
                                int x = 0;
                                while (readerMonthVsSales.Read())
                                {
                                    reportDetails.Add(new Dictionary<string, object>
                                    {
                                        { "title", readerMonthVsSales.GetString(0) },
                                        { "sales", readerMonthVsSales.IsDBNull(1) ? 0 : readerMonthVsSales.GetFloat(1) },
                                        { "collection", readerMonthVsSales.IsDBNull(2) ? 0 : readerMonthVsSales.GetFloat(2) },
                                        { "abbr", readerMonthVsSales.GetString(0).Substring(0, 4) },
                                        { "opening", opening[x] }
                                    });
                                    x++;
                                }
                            }
                        }
                        // Calculate totals
                        float totalSales = 0f;
                        float totalCollection = 0f;
                        foreach (var record in reportDetails)
                        {
                            totalSales += Convert.ToSingle(record["sales"]);
                            totalCollection += Convert.ToSingle(record["collection"]);
                        }
                        var response = new Dictionary<string, object>
                        {
                            { "detail", reportDetails },
                            { "total", new Dictionary<string, object> { { "sales", totalSales }, { "collection", totalCollection }, { "abbr", "Bak" } } }
                        };
                        graph["monthly_sales_vs_collection"] = response;
                        #endregion
                    }
                }
                catch (Exception ex)
                {

                }
                return Ok(graph);
            }
            else
            {
                return null;
            }
        }

        [HttpPost]
        [Route("GetPeriodWiseSalesReport")]
        public async Task<IHttpActionResult> GetPeriodWiseSalesReport([FromBody] Dictionary<string, object> bodyData)
        {
            #region Variable Define
            string companyCode = null;
            string branchCode = null;
            string userNo = null;
            string fromDate = null;
            string toDate = null;
            string grossNetStr = null;
            string dealerCode = null;
            string customerStr = null;
            string itemStringFilter = null;
            List<string> itemCode = new List<string>();
            string customerCode = null;
            string months = null;
            string brand = null;
            string cat = null;
            string grp = null;
            bool withEngDate = false;
            string cusGrp = null;
            string cusGrpStr = null;
            string repType = null;
            string unitType = null;
            string grossNet = null;
            #endregion

            #region Extract the parameters from the bodyData dictionary
            companyCode = GetStringParameter(bodyData, "companyCode");
            branchCode = GetStringParameter(bodyData, "branchCode");
            userNo = GetStringParameter(bodyData, "userNo");
            fromDate = GetStringParameter(bodyData, "fromDate");
            toDate = GetStringParameter(bodyData, "toDate");
            grossNetStr = GetStringParameter(bodyData, "grossNetStr");
            dealerCode = GetStringParameter(bodyData, "dealerCode");
            customerStr = GetStringParameter(bodyData, "customerStr");
            itemStringFilter = GetStringParameter(bodyData, "itemStringFilter");

            // Handle itemCode as a JSON array
            if (bodyData.ContainsKey("itemCode") && bodyData["itemCode"] != null)
            {
                var itemCodeJson = bodyData["itemCode"].ToString();
                itemCode = JsonConvert.DeserializeObject<List<string>>(itemCodeJson);
            }

            // Extract and validate other parameters
            customerCode = GetStringParameter(bodyData, "customerCode");
            months = GetStringParameter(bodyData, "months");
            brand = GetStringParameter(bodyData, "brand");
            cat = GetStringParameter(bodyData, "cat");
            grp = GetStringParameter(bodyData, "grp");
            //withEngDate = GetBooleanParameter(bodyData, "withEngDate");
            cusGrp = GetStringParameter(bodyData, "cusGrp");
            cusGrpStr = GetStringParameter(bodyData, "cusGrpStr");
            repType = GetStringParameter(bodyData, "repType");
            unitType = GetStringParameter(bodyData, "unitType");
            grossNet = GetStringParameter(bodyData, "grossNet");
            #endregion

            #region Query
            var companyCodeTuple = companyCode + "','0";
            customerCode = customerCode.TrimStart();
            grossNetStr = grossNet == "net" ? "NET_SALES_RATE" : "NET_GROSS_RATE";
            string brandStr = "";

            if (!string.IsNullOrEmpty(brand))
            {
                brandStr = $@" and item_code in (select item_code from iP_ITEM_SPEC_SETUP where brand_name='{brand}' and company_code in {companyCode}) ";
            }
            string grpStr = "";
            if (!string.IsNullOrEmpty(grp))
            {
                grpStr = $@" and item_code in (select item_code from ip_item_master_setup where pre_item_code like '{grp}%' and company_code in {companyCode}) ";
            }

            cusGrpStr = "";
            string subCodeCusStr = "";

            if (!string.IsNullOrEmpty(cusGrp))
            {
                cusGrpStr = $@" and customer_code in (select customer_code from sa_customer_setup where pre_customer_code like '{cusGrp}%' and company_code in {companyCode}) ";
                subCodeCusStr = $@" and sub_code in (select distinct('C'||customer_code) from sa_customer_setup where pre_customer_code like '{cusGrp}%' and company_code in {companyCode}) ";
            }

            string catStr = "";
            if (!string.IsNullOrEmpty(cat))
            {
                catStr = $@" and item_code in (select item_code from ip_item_master_setup where category_code in ('{cat}') and company_code in {companyCode}) ";
            }

            itemStringFilter = "";

            if (itemCode.Count == 0)
            {
                itemStringFilter = $@" and item_code in (select item_code from ip_item_master_setup where company_code in {companyCode} {brandStr} {grpStr} {catStr})";
            }
            else if (itemCode.Count == 1)
            {
                itemCode.Add("0"); // assuming itemCode is a List<string>
                var itemCodeTuple = string.Join(",", itemCode.Select(ic => $"'{ic}'"));
                itemStringFilter = $@" and item_code in ({itemCodeTuple}) ";
                itemStringFilter += $@" and item_code in (select item_code from ip_item_master_setup where item_code in ({itemCodeTuple}) and company_code in {companyCode} {brandStr} {grpStr} {catStr}) ";
            }
            else if (itemCode.Count != 0)
            {
                var itemCodeTuple = string.Join(",", itemCode.Select(ic => $"'{ic}'"));
                itemStringFilter = $@" and item_code in ({itemCodeTuple}) and company_code in {companyCode} ";
            }
            if (string.IsNullOrEmpty(cusGrp) && string.IsNullOrEmpty(cat) && string.IsNullOrEmpty(brand) && itemCode.Count == 0)
            {
                itemStringFilter = "";
            }
            customerStr = "";
            string subCodeStr = "";
            grossNetStr = "NET_GROSS_RATE";
            if (grossNet == "net")
            {
                grossNetStr = "NET_SALES_RATE";
            }

            if (!string.IsNullOrEmpty(customerCode))
            {
                customerStr = $@" AND A.customer_code ='{customerCode}' ";
                subCodeStr = $@" and sub_code='C{customerCode}' ";
            }
            #endregion
            if (repType == "period_wise_sales")
            {
                var cals = new Dictionary<string, object>();

                string query;

                if (withEngDate == true)
                {
                    query = $@"
                        SELECT item_edesc, this_year_qty, this_year_amt, last_month_qty, last_month_amt, this_month_qty, this_month_amt, index_mu_code, ss 
                        FROM (
                            SELECT rangename, qty, amt, item_edesc, index_mu_code, ss 
                            FROM (
                                SELECT startdate, rangename, item_code, SUM(sales_qty - sales_ret_qty) AS qty, SUM(sales_value - sales_ret_value) AS amt 
                                FROM (
                                    SELECT * FROM (
                                        SELECT A.COMPANY_CODE, A.BRANCH_CODE, A.sales_date, a.item_code,
                                            SUM(NVL(A.ROLL_QTY, 0)) AS SALES_ROLL_QTY,
                                            SUM(NVL(A.QUANTITY, 0)) AS SALES_QTY,
                                            SUM(NVL(A.QUANTITY * A.{grossNetStr}, 0)) AS SALES_VALUE,
                                            0 AS SALES_RET_ROLL_QTY,
                                            0 AS SALES_RET_QTY,
                                            0 AS SALES_RET_VALUE 
                                        FROM SA_SALES_INVOICE A 
                                        WHERE A.DELETED_FLAG = 'N'
                                            AND A.BRANCH_CODE IN {GetBranchFilter(companyCode, branchCode, this.UserId.ToString())}
                                            AND A.COMPANY_CODE IN {companyCode} 
                                            {customerStr} 
                                            {itemStringFilter}
                                            AND item_code IN (
                                                SELECT item_code FROM ip_item_master_setup WHERE company_code IN {companyCode}
                                            )
                                        GROUP BY A.COMPANY_CODE, A.BRANCH_CODE, A.sales_date, a.item_code
                                        UNION ALL
                                        SELECT A.COMPANY_CODE, A.BRANCH_CODE, A.return_date, a.item_code,
                                            0 AS SALES_ROLL_QTY, 0 AS SALES_QTY, 0 AS SALES_VALUE,
                                            SUM(NVL(A.ROLL_QTY, 0)) AS SALES_RET_ROLL_QTY,
                                            SUM(NVL(A.QUANTITY, 0)) AS SALES_RET_QTY,
                                            SUM(NVL(A.QUANTITY * A.{grossNetStr}, 0)) AS SALES_RET_VALUE 
                                        FROM SA_SALES_RETURN A 
                                        WHERE A.DELETED_FLAG = 'N'
                                            AND A.BRANCH_CODE IN {GetBranchFilter(companyCode, branchCode, this.UserId.ToString())}
                                            AND A.COMPANY_CODE IN {companyCode} 
                                            {customerStr} 
                                            {itemStringFilter}
                                            AND item_code IN (
                                                SELECT item_code FROM ip_item_master_setup WHERE company_code IN {companyCode}
                                            )
                                        GROUP BY A.COMPANY_CODE, A.BRANCH_CODE, A.return_date, a.item_code 
                                        ORDER BY sales_date
                                    ) a
                                    LEFT OUTER JOIN (
                                        SELECT * FROM V_DATE_RANGE WHERE rangename IN ('This Month', 'Last Month', 'This Year')
                                    ) b ON a.sales_date BETWEEN b.startdate AND b.enddate
                                ) 
                                GROUP BY startdate, rangename, item_code 
                                ORDER BY startdate
                            ) a
                            LEFT OUTER JOIN (
                                SELECT item_code AS ss, item_edesc, index_mu_code 
                                FROM ip_item_master_setup WHERE company_code IN {companyCode} 
                                GROUP BY item_code, item_edesc, index_mu_code
                            ) b ON a.item_code = b.ss
                        )
                        PIVOT (
                            SUM(qty) AS qty, SUM(amt) AS amt
                            FOR rangename IN ('This Year' AS This_Year, 'Last Month' AS Last_Month, 'This Month' AS This_Month)
                        ) 
                        ORDER BY ITEM_EDESC";
                }
                else
                {
                    query = $@"
                        SELECT item_edesc, this_year_qty, this_year_amt, last_month_qty, last_month_amt, this_month_qty, this_month_amt, index_mu_code, ss 
                        FROM (
                            SELECT rangename, qty, amt, item_edesc, index_mu_code, ss 
                            FROM (
                                SELECT startdate, rangename, item_code, SUM(sales_qty - sales_ret_qty) AS qty, SUM(sales_value - sales_ret_value) AS amt 
                                FROM (
                                    SELECT * FROM (
                                        SELECT A.COMPANY_CODE, A.BRANCH_CODE, A.sales_date, a.item_code,
                                            SUM(NVL(A.ROLL_QTY, 0)) AS SALES_ROLL_QTY,
                                            SUM(NVL(A.QUANTITY, 0)) AS SALES_QTY,
                                            SUM(NVL(A.QUANTITY * A.{grossNetStr}, 0)) AS SALES_VALUE,
                                            0 AS SALES_RET_ROLL_QTY,
                                            0 AS SALES_RET_QTY,
                                            0 AS SALES_RET_VALUE 
                                        FROM SA_SALES_INVOICE A 
                                        WHERE A.DELETED_FLAG = 'N'
                                            AND A.BRANCH_CODE IN {GetBranchFilter(companyCode, branchCode, this.UserId.ToString())}
                                            AND A.COMPANY_CODE IN {companyCode} 
                                            {customerStr} 
                                            {itemStringFilter}
                                            AND item_code IN (
                                                SELECT item_code FROM ip_item_master_setup WHERE company_code IN {companyCode}
                                            )
                                        GROUP BY A.COMPANY_CODE, A.BRANCH_CODE, A.sales_date, a.item_code
                                        UNION ALL
                                        SELECT A.COMPANY_CODE, A.BRANCH_CODE, A.return_date, a.item_code,
                                            0 AS SALES_ROLL_QTY, 0 AS SALES_QTY, 0 AS SALES_VALUE,
                                            SUM(NVL(A.ROLL_QTY, 0)) AS SALES_RET_ROLL_QTY,
                                            SUM(NVL(A.QUANTITY, 0)) AS SALES_RET_QTY,
                                            SUM(NVL(A.QUANTITY * A.{grossNetStr}, 0)) AS SALES_RET_VALUE 
                                        FROM SA_SALES_RETURN A 
                                        WHERE A.DELETED_FLAG = 'N'
                                            AND A.BRANCH_CODE IN {GetBranchFilter(companyCode, branchCode, this.UserId.ToString())}
                                            AND A.COMPANY_CODE IN {companyCode} 
                                            {customerStr} 
                                            {itemStringFilter}
                                            AND item_code IN (
                                                SELECT item_code FROM ip_item_master_setup WHERE company_code IN {companyCode}
                                            )
                                        GROUP BY A.COMPANY_CODE, A.BRANCH_CODE, A.return_date, a.item_code 
                                        ORDER BY sales_date
                                    ) a
                                    LEFT OUTER JOIN (
                                        SELECT TRUNC(SYSDATE, 'MONTH') AS startdate, 
                                               TRUNC(LAST_DAY(SYSDATE)) AS enddate, 'This Month' AS rangename 
                                        FROM dual
                                        UNION ALL
                                        SELECT TRUNC(ADD_MONTHS(SYSDATE, -1), 'MONTH') AS startdate, 
                                               TRUNC(LAST_DAY(ADD_MONTHS(SYSDATE, -1))) AS enddate, 'Last Month' AS rangename 
                                        FROM dual
                                        UNION ALL
                                        SELECT startdate, enddate, rangename FROM V_DATE_RANGE WHERE rangename IN ('This Year')
                                    ) b ON a.sales_date BETWEEN b.startdate AND b.enddate
                                ) 
                                GROUP BY startdate, rangename, item_code 
                                ORDER BY startdate
                            ) a
                            LEFT OUTER JOIN (
                                SELECT item_code AS ss, item_edesc, index_mu_code 
                                FROM ip_item_master_setup WHERE company_code IN {companyCode} 
                                GROUP BY item_code, item_edesc, index_mu_code
                            ) b ON a.item_code = b.ss
                        )
                        PIVOT (
                            SUM(qty) AS qty, SUM(amt) AS amt
                            FOR rangename IN ('This Year' AS This_Year, 'Last Month' AS Last_Month, 'This Month' AS This_Month)
                        ) 
                        ORDER BY ITEM_EDESC";
                }
                var results = new List<Dictionary<string, object>>();
                using (var connection = new OracleConnection(_connection))
                {
                    using (var command = new OracleCommand(query, connection))
                    {
                        connection.Open();
                        using (var adapter = new OracleDataAdapter(command))
                        {
                            var dataTable = new DataTable();
                            adapter.Fill(dataTable);

                            foreach (DataRow row in dataTable.Rows)
                            {
                                var rowDict = new Dictionary<string, object>();
                                foreach (DataColumn column in dataTable.Columns)
                                {
                                    rowDict[column.ColumnName] = row[column];
                                }
                                results.Add(rowDict);
                            }
                        }
                    }
                }
                var THIS_YEAR_QTY = new List<double>();
                var THIS_YEAR_AMT = new List<double>();
                var LAST_MONTH_QTY = new List<double>();
                var LAST_MONTH_AMT = new List<double>();
                var THIS_MONTH_QTY = new List<double>();
                var THIS_MONTH_AMT = new List<double>();
                var multi_unit_d = new Dictionary<string, dynamic>();

                if (!string.IsNullOrEmpty(unitType))
                {
                    multi_unit_d = GetMultiQty(unitType, companyCode); // Assuming GetMultiQty returns a dictionary
                }
                foreach (var i in results)
                {
                    double t1 = i.ContainsKey("this_year_qty") && i["this_year_qty"] != null ? Convert.ToDouble(i["this_year_qty"]) : 0;
                    double t2 = i.ContainsKey("this_year_amt") && i["this_year_amt"] != null ? Convert.ToDouble(i["this_year_amt"]) : 0;
                    double t3 = i.ContainsKey("last_month_qty") && i["last_month_qty"] != null ? Convert.ToDouble(i["last_month_qty"]) : 0;
                    double t4 = i.ContainsKey("last_month_amt") && i["last_month_amt"] != null ? Convert.ToDouble(i["last_month_amt"]) : 0;
                    double t5 = i.ContainsKey("this_month_qty") && i["this_month_qty"] != null ? Convert.ToDouble(i["this_month_qty"]) : 0;
                    double t6 = i.ContainsKey("this_month_amt") && i["this_month_amt"] != null ? Convert.ToDouble(i["this_month_amt"]) : 0;

                    double q1 = 0, q2 = 0, q3 = 0;
                    string unit = "";
                    double ratio = 0;
                    if (!string.IsNullOrEmpty(unitType))
                    {
                        if (i.ContainsKey("item_code") && i["item_code"] != null)
                        {
                            string itemCodes = i["item_code"].ToString(); // Safely cast to string
                            if (multi_unit_d.ContainsKey(itemCodes))
                            {
                                var ratioObj = multi_unit_d[itemCodes]["ratio"];
                                var muCodeObj = multi_unit_d[itemCodes]["mu_code"];
                                if (ratioObj != null && double.TryParse(ratioObj.ToString(), out ratio))
                                {
                                    q1 = t1 * ratio;
                                    q2 = t3 * ratio;
                                    q3 = t5 * ratio;
                                }
                                else
                                {
                                    q1 = q2 = q3 = 0; // Default to 0 if ratio parsing fails
                                }

                                unit = muCodeObj != null ? muCodeObj.ToString() : string.Empty; // Safely set unit to empty if mu_code is null
                            }
                        }
                        else
                        {
                            q1 = q2 = q3 = 0;
                        }
                    }
                    else
                    {
                        q1 = t1;
                        q2 = t3;
                        q3 = t5;
                    }
                    THIS_YEAR_QTY.Add(q1);
                    THIS_YEAR_AMT.Add(t2);
                    LAST_MONTH_QTY.Add(q2);
                    LAST_MONTH_AMT.Add(t4);
                    THIS_MONTH_QTY.Add(q3);
                    THIS_MONTH_AMT.Add(t6);
                }
                cals.Add("this_year_qty", THIS_YEAR_QTY);
                cals.Add("this_year_amt", THIS_YEAR_AMT);
                cals.Add("last_month_qty", LAST_MONTH_QTY);
                cals.Add("last_month_amt", LAST_MONTH_AMT);
                cals.Add("this_month_qty", THIS_MONTH_QTY);
                cals.Add("this_month_amt", THIS_MONTH_AMT);
                cals.Add("item_edesc", results);
                return Ok(cals);
            }
            else
            {
                return null;
            }
        }
