        [HttpPost]
        public IHttpActionResult AnalyzeData([FromBody] UserQuery query)
        {
            // Process the user query
            var result = ProcessQuery(query.Query);
            return Ok(result);
        }
        private Response ProcessQuery(string query)
        {
            // Simple check to determine if user requested table or chart
            if (query.Contains("table"))
            {
                return GetEmployeeDataTable();
            }
            else if (query.Contains("chart"))
            {
                return GetEmployeeDataChart();
            }
            else
            {
                return new Response { Type = "text", Data = "Sorry, I don't understand your query." };
            }
        }
        private Response GetEmployeeDataTable()
        {
            // Generate a simple HTML table for employee data
            var tableHtml = "<table class='table table-bordered'><thead><tr><th>Name</th><th>Salary</th><th>Age</th></tr></thead><tbody>";
            // Sample data
            var employees = new List<Employee>
            {
                new Employee { YearOfExp = 1.0f, Salary = 45000.0f, Age = 23, Gender = "Male", EducationLevel = "Bachelor", Department = 1, JobLevel = 1, IsManager = false, Bonus = 2000, Location = "New York", WorkingHours = 40 },
                new Employee { YearOfExp = 2.0f, Salary = 50000.0f, Age = 24, Gender = "Female", EducationLevel = "Bachelor", Department = 1, JobLevel = 2, IsManager = false, Bonus = 2500, Location = "California", WorkingHours = 45 }
            };

            foreach (var emp in employees)
            {
                tableHtml += $"<tr><td>{emp.Gender} {emp.YearOfExp}</td><td>{emp.Salary}</td><td>{emp.Age}</td></tr>";
            }
            tableHtml += "</tbody></table>";

            return new Response { Type = "table", Data = tableHtml };
        }

        private Response GetEmployeeDataChart()
        {
            // Prepare data for chart
            var chartData = new
            {
                labels = new List<string> { "Employee 1", "Employee 2" },
                datasets = new List<object>
        {
            new {
                label = "Salary",
                data = new List<int> { 45000, 50000 },
                backgroundColor = "rgba(75, 192, 192, 0.2)",
                borderColor = "rgba(75, 192, 192, 1)",
                borderWidth = 1
            }
        }
            };

            return new Response { Type = "chart", Data = chartData };
        }
