        private string GetStringValue(object value)
        {
            if (value == null || value == DBNull.Value)
                return null; 
            return value.ToString();
        }
       
        private double GetDoubleValue(object value)
        {
            if (value == null || value == DBNull.Value)
                return 0.0; 
            return Convert.ToDouble(value);
